// CallGraphVisitor.java
import visitor.*;
import syntaxtree.*;
import java.util.*;

public class CallGraphVisitor extends GJDepthFirst<Object, String[]> {
    // A = String[] {currentClass, currentMethod}

    private ClassHierarchyVisitor ch;
    private SymbolTableVisitor st;

    public Set<String> reachable = new LinkedHashSet<>(); // "ClassName.methodName"
    private Queue<String> worklist = new LinkedList<>();

    // AST storage: map "ClassName.methodName" → MethodDeclaration node
    private Map<String, MethodDeclaration> methodNodes = new LinkedHashMap<>();
    // Also store main class statements
    private Goal rootGoal;

    public CallGraphVisitor(ClassHierarchyVisitor ch, SymbolTableVisitor st, Goal root) {
        this.ch = ch;
        this.st = st;
        this.rootGoal = root;
    }

    // Index all methods first, then run reachability
    public void build() {
        // First pass: index all MethodDeclaration nodes
        IndexVisitor indexer = new IndexVisitor();
        rootGoal.accept(indexer, null);
        methodNodes = indexer.methodNodes;

        // Seed with main
        String mainClass = rootGoal.f0.f1.f0.tokenImage;
        // Analyze main body directly
        reachable.add(mainClass + ".main");
        worklist.add(mainClass + ".main");

        // Analyze main statements for calls
        analyzeMain(rootGoal.f0);

        // Process worklist
        while (!worklist.isEmpty()) {
            String sig = worklist.poll();
            MethodDeclaration md = methodNodes.get(sig);
            if (md != null) {
                String cls = sig.substring(0, sig.lastIndexOf('.'));
                String meth = sig.substring(sig.lastIndexOf('.') + 1);
                md.accept(this, new String[]{cls, meth});
            }
        }
    }

    private void analyzeMain(MainClass mc) {
        String mainClass = mc.f1.f0.tokenImage;
        // Visit statements
        mc.f15.accept(this, new String[]{mainClass, "main"});
    }

    @Override
    public Object visit(MessageSend n, String[] argu) {
        // Resolve receiver type
        String receiverType = resolveReceiverType(n.f0, argu);
        String methodName = n.f2.f0.tokenImage;

        // CHA: add all implementations
        Set<String> targets = chaResolve(receiverType, methodName);
        for (String target : targets) {
            if (reachable.add(target)) {
                worklist.add(target);
            }
        }

        // Continue visiting arguments
        n.f4.accept(this, argu);
        return null;
    }

    private String resolveReceiverType(PrimaryExpression pe, String[] argu) {
        Node choice = pe.f0.choice;
        if (choice instanceof Identifier) {
            String varName = ((Identifier)choice).f0.tokenImage;
            if (argu != null) {
                return st.lookupType(argu[0], argu[1], varName, ch);
            }
        }
        if (choice instanceof ThisExpression) {
            return argu != null ? argu[0] : null;
        }
        if (choice instanceof AllocationExpression) {
            return ((AllocationExpression)choice).f1.f0.tokenImage;
        }
        return null;
    }

    private Set<String> chaResolve(String receiverType, String methodName) {
        Set<String> result = new LinkedHashSet<>();
        if (receiverType == null) return result;

        // All classes: receiverType and all subclasses
        Set<String> candidates = new LinkedHashSet<>();
        candidates.add(receiverType);
        candidates.addAll(ch.allSubclasses(receiverType));

        for (String cls : candidates) {
            // Find where method is defined (in cls or ancestor)
            String defClass = ch.resolveMethod(cls, methodName);
            if (defClass != null) {
                result.add(defClass + "." + methodName);
            }
        }
        return result;
    }

    // Helper visitor to index all method nodes
    private static class IndexVisitor extends GJDepthFirst<Object, Void> {
        Map<String, MethodDeclaration> methodNodes = new LinkedHashMap<>();
        private String currentClass = null;

        @Override
        public Object visit(ClassDeclaration n, Void argu) {
            currentClass = n.f1.f0.tokenImage;
            n.f4.accept(this, argu);
            currentClass = null;
            return null;
        }

        @Override
        public Object visit(ClassExtendsDeclaration n, Void argu) {
            currentClass = n.f1.f0.tokenImage;
            n.f6.accept(this, argu);
            currentClass = null;
            return null;
        }

        @Override
        public Object visit(MethodDeclaration n, Void argu) {
            String methodName = n.f2.f0.tokenImage;
            methodNodes.put(currentClass + "." + methodName, n);
            return null;
        }
    }

    public boolean isReachable(String className, String methodName) {
        return reachable.contains(className + "." + methodName);
    }
}
