        if (classMethods == null) return;
        Map<String,String> locals = classMethods.get(meth);
        if (locals == null) return;
        Set<String> params = new HashSet<>();
        Map<String,List<String>> classParams = st.methodParams.get(cls);
        if (classParams != null) {
            List<String> p = classParams.get(meth);
            if (p != null) params.addAll(p);
        }
        for (String var : locals.keySet()) {
            state.put(var, params.contains(var) ? CPValue.NAC : CPValue.UNDEF);
        }
    }

