// CPValue.java
public class CPValue {
    public static final int KIND_UNDEF = 0;
    public static final int KIND_NAC   = 1;
    public static final int KIND_INT   = 2;
    public static final int KIND_BOOL  = 3;

    public final int kind;
    public final int intVal;
    public final boolean boolVal;

    public static final CPValue UNDEF = new CPValue(KIND_UNDEF, 0, false);
    public static final CPValue NAC   = new CPValue(KIND_NAC, 0, false);

    private CPValue(int k, int i, boolean b) { kind=k; intVal=i; boolVal=b; }

    public static CPValue ofInt(int v)     { return new CPValue(KIND_INT, v, false); }
    public static CPValue ofBool(boolean v){ return new CPValue(KIND_BOOL, 0, v); }

    public boolean isConst() { return kind == KIND_INT || kind == KIND_BOOL; }
    public boolean isInt()   { return kind == KIND_INT; }
    public boolean isBool()  { return kind == KIND_BOOL; }
    public boolean isUndef() { return kind == KIND_UNDEF; }
    public boolean isNAC()   { return kind == KIND_NAC; }

    public CPValue meet(CPValue other) {
        if (kind == KIND_UNDEF) return other;
        if (other.kind == KIND_UNDEF) return this;
        if (kind == KIND_NAC || other.kind == KIND_NAC) return NAC;
        if (kind != other.kind) return NAC;
        if (kind == KIND_INT && intVal == other.intVal) return this;
        if (kind == KIND_BOOL && boolVal == other.boolVal) return this;
        return NAC;
    }

    public String toCode() {
        if (kind == KIND_INT) {
            if (intVal < 0) return "- " + (-intVal); // signed
            return Integer.toString(intVal);
        }
        if (kind == KIND_BOOL) return boolVal ? "true" : "false";
        throw new RuntimeException("Not a constant");
    }

    @Override
    public boolean equals(Object o) {
        if (!(o instanceof CPValue)) return false;
        CPValue c = (CPValue)o;
        if (kind != c.kind) return false;
        if (kind == KIND_INT) return intVal == c.intVal;
        if (kind == KIND_BOOL) return boolVal == c.boolVal;
        return true;
    }

    @Override
    public int hashCode() {
        if (kind == KIND_INT) return intVal;
        if (kind == KIND_BOOL) return boolVal ? 1 : 0;
        return kind;
    }

    @Override
    public String toString() {
        if (kind == KIND_INT) return "INT(" + intVal + ")";
        if (kind == KIND_BOOL) return "BOOL(" + boolVal + ")";
        return kind == KIND_UNDEF ? "UNDEF" : "NAC";
    }
}
