// SymbolTableVisitor.java
import visitor.*;
import syntaxtree.*;
import java.util.*;

public class SymbolTableVisitor extends GJDepthFirst<Object, Object> {
    // class → field name → type
    public Map<String, Map<String,String>> classFields = new LinkedHashMap<>();
    // class → method → var name → type
    public Map<String, Map<String, Map<String,String>>> methodVars = new LinkedHashMap<>();
    // class → method → ordered param names
    public Map<String, Map<String, List<String>>> methodParams = new LinkedHashMap<>();
    // class → method → return type
    public Map<String, Map<String, String>> methodRetTypes = new LinkedHashMap<>();

    private String curClass = null, curMethod = null;
    private boolean inField = false; // inside class but outside method

    private String typeName(Type t) {
        Node c = t.f0.choice;
        if (c instanceof ArrayType) return "int[]";
        if (c instanceof BooleanType) return "boolean";
        if (c instanceof IntegerType) return "int";
        if (c instanceof Identifier) return ((Identifier)c).f0.tokenImage;
        return "?";
    }

    @Override
    public Object visit(MainClass n, Object argu) {
        curClass = n.f1.f0.tokenImage;
        curMethod = "main";
        classFields.put(curClass, new LinkedHashMap<>());
        methodVars.computeIfAbsent(curClass, k -> new LinkedHashMap<>()).put("main", new LinkedHashMap<>());
        methodParams.computeIfAbsent(curClass, k -> new LinkedHashMap<>()).put("main", new ArrayList<>());
        methodRetTypes.computeIfAbsent(curClass, k -> new LinkedHashMap<>()).put("main", "void");
        n.f14.accept(this, argu); // var declarations
        curClass = null; curMethod = null;
        return null;
    }

    @Override
    public Object visit(ClassDeclaration n, Object argu) {
        curClass = n.f1.f0.tokenImage;
        classFields.put(curClass, new LinkedHashMap<>());
        methodVars.put(curClass, new LinkedHashMap<>());
        methodParams.put(curClass, new LinkedHashMap<>());
        methodRetTypes.put(curClass, new LinkedHashMap<>());
        inField = true;
        n.f3.accept(this, argu); // fields
        inField = false;
        n.f4.accept(this, argu); // methods
        curClass = null;
        return null;
    }

    @Override
    public Object visit(ClassExtendsDeclaration n, Object argu) {
        curClass = n.f1.f0.tokenImage;
        classFields.put(curClass, new LinkedHashMap<>());
        methodVars.put(curClass, new LinkedHashMap<>());
        methodParams.put(curClass, new LinkedHashMap<>());
        methodRetTypes.put(curClass, new LinkedHashMap<>());
        inField = true;
        n.f5.accept(this, argu);
        inField = false;
        n.f6.accept(this, argu);
        curClass = null;
        return null;
    }

    @Override
    public Object visit(VarDeclaration n, Object argu) {
        String type = typeName(n.f0);
        String name = n.f1.f0.tokenImage;
        if (curMethod == null || inField) {
            classFields.get(curClass).put(name, type);
        } else {
            methodVars.get(curClass).get(curMethod).put(name, type);
        }
        return null;
    }

    @Override
    public Object visit(MethodDeclaration n, Object argu) {
        curMethod = n.f2.f0.tokenImage;
        String retType = typeName(n.f1);
        methodRetTypes.get(curClass).put(curMethod, retType);
        methodVars.get(curClass).put(curMethod, new LinkedHashMap<>());
        methodParams.get(curClass).put(curMethod, new ArrayList<>());
        n.f4.accept(this, argu); // params
        n.f7.accept(this, argu); // local vars
        curMethod = null;
        return null;
    }

    @Override
    public Object visit(FormalParameter n, Object argu) {
        String type = typeName(n.f0);
        String name = n.f1.f0.tokenImage;
        methodVars.get(curClass).get(curMethod).put(name, type);
        methodParams.get(curClass).get(curMethod).add(name);
        return null;
    }

    // Look up the type of a variable in a given scope (method locals, then class fields, then parent fields)
    public String lookupType(String cls, String meth, String varName, ClassHierarchyVisitor ch) {
        // Method locals
        Map<String, Map<String,String>> cm = methodVars.get(cls);
        if (cm != null) {
            Map<String,String> locs = cm.get(meth);
            if (locs != null && locs.containsKey(varName)) return locs.get(varName);
        }
        // Class fields (including inherited)
        for (String c : ch.ancestors(cls)) {
            Map<String,String> flds = classFields.get(c);
            if (flds != null && flds.containsKey(varName)) return flds.get(varName);
        }
        return null;
    }

    public boolean isParam(String cls, String meth, String var) {
        Map<String, List<String>> cm = methodParams.get(cls);
        if (cm == null) return false;
        List<String> ps = cm.get(meth);
        return ps != null && ps.contains(var);
    }
}
