// CallGraphVisitor.java
import visitor.*;
import syntaxtree.*;
import java.util.*;

public class CallGraphVisitor extends GJDepthFirst<Object, Object> {
    ClassHierarchyVisitor ch;
    SymbolTableVisitor st;

    // method nodes indexed by "Class.method"
    Map<String, MethodDeclaration> methodNodes = new LinkedHashMap<>();
    Map<String, MainClass> mainNode = new LinkedHashMap<>(); // single entry
    String mainClass;

    // Reachable methods
    public Set<String> reachable = new LinkedHashSet<>();

    // Side effect analysis: "Class.method" → has side effects?
    public Map<String, Boolean> hasSideEffect = new LinkedHashMap<>();

    public CallGraphVisitor(ClassHierarchyVisitor ch, SymbolTableVisitor st) {
        this.ch = ch;
        this.st = st;
    }

    // Phase 1: index all method nodes (visit the AST)
    // Phase 2: run reachability from main
    // Phase 3: run side effect analysis

    @Override
    public Object visit(MainClass n, Object argu) {
        mainClass = n.f1.f0.tokenImage;
        // Don't visit methods inside, just record
        return null;
    }

    @Override
    public Object visit(ClassDeclaration n, Object argu) {
        String cls = n.f1.f0.tokenImage;
        curClass = cls;
        n.f4.accept(this, argu);
        curClass = null;
        return null;
    }

    @Override
    public Object visit(ClassExtendsDeclaration n, Object argu) {
        String cls = n.f1.f0.tokenImage;
        curClass = cls;
        n.f6.accept(this, argu);
        curClass = null;
        return null;
    }

    private String curClass = null;

    @Override
    public Object visit(MethodDeclaration n, Object argu) {
        String sig = curClass + "." + n.f2.f0.tokenImage;
        methodNodes.put(sig, n);
        return null;
    }

    public void build(Goal root) {
        // Phase 1: index
        root.accept(this, null);

        // Phase 2: reachability
        reachable.add(mainClass + ".main");
        Deque<String> worklist = new ArrayDeque<>();
        worklist.add(mainClass + ".main");
        // Process main body
        processCallsInMain(root.f0, worklist);

        while (!worklist.isEmpty()) {
            String sig = worklist.poll();
            if (sig.endsWith(".main")) continue; // already done
            MethodDeclaration md = methodNodes.get(sig);
            if (md == null) continue;
            String cls = sig.substring(0, sig.lastIndexOf('.'));
            String meth = sig.substring(sig.lastIndexOf('.') + 1);
            processCallsInMethod(md, cls, meth, worklist);
        }

        // Phase 3: side effects
        analyzeSideEffects(root);
    }

    private void processCallsInMain(MainClass mc, Deque<String> worklist) {
        // Find all MessageSends in main body
        CallFinder finder = new CallFinder(mainClass, "main");
        mc.f15.accept(finder, null);
        for (String target : finder.targets) {
            if (reachable.add(target)) worklist.add(target);
        }
    }

    private void processCallsInMethod(MethodDeclaration md, String cls, String meth, Deque<String> worklist) {
        CallFinder finder = new CallFinder(cls, meth);
        md.f8.accept(finder, null); // statements
        // Also check the return expression? The return is just an Identifier, no calls there.
        for (String target : finder.targets) {
            if (reachable.add(target)) worklist.add(target);
        }
    }

    // Finds all CHA-resolved call targets in a subtree
    class CallFinder extends GJDepthFirst<Object, Object> {
        String callerClass, callerMethod;
        Set<String> targets = new LinkedHashSet<>();

        CallFinder(String cls, String meth) {
            callerClass = cls;
            callerMethod = meth;
        }

        @Override
        public Object visit(MessageSend n, Object argu) {
            // Resolve receiver type
            String recvType = resolveReceiverType(n.f0, callerClass, callerMethod);
            String methodName = n.f2.f0.tokenImage;
            if (recvType != null) {
                targets.addAll(chaResolve(recvType, methodName));
            }
            n.f4.accept(this, argu); // args might have calls? In TACoJava, args are just identifiers, so no
            return null;
        }
    }

    String resolveReceiverType(PrimaryExpression pe, String cls, String meth) {
        Node choice = pe.f0.choice;
        if (choice instanceof Identifier) {
            String varName = ((Identifier)choice).f0.tokenImage;
            return st.lookupType(cls, meth, varName, ch);
        }
        if (choice instanceof ThisExpression) return cls;
        if (choice instanceof AllocationExpression)
            return ((AllocationExpression)choice).f1.f0.tokenImage;
        return null;
    }

    Set<String> chaResolve(String receiverType, String methodName) {
        Set<String> result = new LinkedHashSet<>();
        // All classes including subclasses
        Set<String> allCls = new LinkedHashSet<>();
        allCls.add(receiverType);
        allCls.addAll(ch.allSubclasses(receiverType));
        for (String c : allCls) {
            String defCls = ch.resolveMethod(c, methodName);
            if (defCls != null) result.add(defCls + "." + methodName);
        }
        return result;
    }

    void analyzeSideEffects(Goal root) {
        // Initialize all reachable methods to no side effects
        for (String sig : reachable) hasSideEffect.put(sig, false);

        // Iterate to fixpoint
        boolean changed;
        do {
            changed = false;
            for (String sig : reachable) {
                if (hasSideEffect.get(sig)) continue; // already true, won't change
                boolean se;
                if (sig.endsWith(".main")) {
                    se = checkSideEffects(root.f0.f15, sig); // main statements
                } else {
                    MethodDeclaration md = methodNodes.get(sig);
                    if (md == null) { se = false; }
                    else se = checkSideEffects(md.f8, sig);
                }
                if (se) {
                    hasSideEffect.put(sig, true);
                    changed = true;
                }
            }
        } while (changed);
    }

    // Check if a NodeListOptional of statements has side effects
    boolean checkSideEffects(NodeListOptional stmts, String callerSig) {
        SideEffectChecker checker = new SideEffectChecker(callerSig);
        stmts.accept(checker, null);
        return checker.hasSE;
    }

    class SideEffectChecker extends GJDepthFirst<Object, Object> {
        boolean hasSE = false;
        String callerSig;
        SideEffectChecker(String sig) { callerSig = sig; }

        @Override
        public Object visit(PrintStatement n, Object argu) {
            hasSE = true; return null;
        }
        @Override
        public Object visit(FieldAssignmentStatement n, Object argu) {
            hasSE = true; return null;
        }
        @Override
        public Object visit(ArrayAssignmentStatement n, Object argu) {
            hasSE = true; return null;
        }
        @Override
        public Object visit(MessageSend n, Object argu) {
            String recvType = resolveReceiverType(n.f0,
                callerSig.substring(0, callerSig.lastIndexOf('.')),
                callerSig.substring(callerSig.lastIndexOf('.') + 1));
            String methName = n.f2.f0.tokenImage;
            Set<String> targets = chaResolve(recvType, methName);
            for (String t : targets) {
                Boolean se = hasSideEffect.get(t);
                if (se != null && se) { hasSE = true; return null; }
            }
            return null;
        }
    }

    public boolean isReachable(String cls, String meth) {
        return reachable.contains(cls + "." + meth);
    }

    public boolean methodHasSideEffect(String cls, String meth) {
        Boolean se = hasSideEffect.get(cls + "." + meth);
        return se != null && se;
    }
}
