// processStmt: processes statement s given stateIn, returns state after
Map<String,CPValue> processStmt(Statement s, Map<String,CPValue> stateIn) {
    Node choice = s.f0.choice;
    if (choice instanceof Block) {
        return processStmtList(((Block)choice).f1, stateIn);
    } else if (choice instanceof AssignmentStatement) {
        AssignmentStatement as = (AssignmentStatement) choice;
        String lhs = as.f0.f0.tokenImage;
        Map<String,CPValue> out = new LinkedHashMap<>(stateIn);
        CPValue rhs = evalExpr(as.f2, stateIn); // evaluate with state BEFORE assignment
        if (out.containsKey(lhs)) out.put(lhs, rhs); // flow-sensitive: replace, not meet
        else out.put(lhs, CPValue.NAC); // variable not in scope? treat as NAC
        return out;
    } else if (choice instanceof IfStatement) {
        IfStatement is = (IfStatement) choice;
        String cond = is.f2.f0.tokenImage;
        CPValue condVal = lookup(cond, stateIn);
        if (condVal.isBool()) {
            if (condVal.boolVal) {
                ifDecision.put(is, 0); // then
                return processStmt(is.f4, stateIn);
            } else {
                ifDecision.put(is, 1); // else
                return processStmt(is.f6, stateIn);
            }
        } else {
            ifDecision.put(is, -1); // both
            Map<String,CPValue> state1 = processStmt(is.f4, new LinkedHashMap<>(stateIn));
            Map<String,CPValue> state2 = processStmt(is.f6, new LinkedHashMap<>(stateIn));
            return meetStates(state1, state2);
        }
    } else if (choice instanceof WhileStatement) {
        WhileStatement ws = (WhileStatement) choice;
        String cond = ws.f2.f0.tokenImage;
        CPValue condVal = lookup(cond, stateIn);
        if (condVal.isBool() && !condVal.boolVal) {
            whileDead.put(ws, true);
            return stateIn;
        }
        whileDead.put(ws, false);
        // Fixpoint iteration for loop
        Map<String,CPValue> loopEntry = new LinkedHashMap<>(stateIn);
        while (true) {
            Map<String,CPValue> bodyExit = processStmt(ws.f4, new LinkedHashMap<>(loopEntry));
            // Meet: loop might execute 0 or more times, so state after loop = meet of all
            Map<String,CPValue> newLoopEntry = meetStates(meetStates(loopEntry, bodyExit), stateIn);
            if (newLoopEntry.equals(loopEntry)) break;
            loopEntry = newLoopEntry;
        }
        // Check if loop became dead (cond was NAC initially but converged to false?)
        // Actually, we already checked condVal at entry, if not CONST(false) then not dead
        return loopEntry;
    } else if (choice instanceof ForStatement) {
        ForStatement fs = (ForStatement) choice;
        // Init
        Map<String,CPValue> state = new LinkedHashMap<>(stateIn);
        String initVar = fs.f2.f0.tokenImage;
        CPValue initVal = evalExpr(fs.f4, state);
        if (state.containsKey(initVar)) state.put(initVar, initVal);
        // Fixpoint for for loop body + increment
        Map<String,CPValue> loopEntry = state;
        while (true) {
            Map<String,CPValue> bodyExit = processStmt(fs.f12, new LinkedHashMap<>(loopEntry));
            // Increment
            String incrVar = fs.f8.f0.tokenImage;
            CPValue incrVal = evalExpr(fs.f10, bodyExit);
            Map<String,CPValue> afterIncr = new LinkedHashMap<>(bodyExit);
            if (afterIncr.containsKey(incrVar)) afterIncr.put(incrVar, incrVal);
            // Condition evaluation (we don't use for dead code, just conservatively)
            Map<String,CPValue> newLoopEntry = meetStates(meetStates(loopEntry, afterIncr), stateIn);
            if (newLoopEntry.equals(loopEntry)) break;
            loopEntry = newLoopEntry;
        }
        return loopEntry;
    } else {
        // ArrayAssignmentStatement, FieldAssignmentStatement, PrintStatement:
        // These don't affect local variable CP values (for our purposes)
        return new LinkedHashMap<>(stateIn);
    }
}

Map<String,CPValue> processStmtList(NodeListOptional stmts, Map<String,CPValue> stateIn) {
    if (!stmts.present()) return stateIn;
    Map<String,CPValue> state = new LinkedHashMap<>(stateIn);
    for (Enumeration<Node> e = stmts.elements(); e.hasMoreElements();) {
        state = processStmt((Statement)e.nextElement(), state);
    }
    return state;
}

Map<String,CPValue> meetStates(Map<String,CPValue> s1, Map<String,CPValue> s2) {
    Map<String,CPValue> result = new LinkedHashMap<>();
    for (String key : s1.keySet()) {
        CPValue v1 = s1.get(key);
        CPValue v2 = s2.getOrDefault(key, CPValue.UNDEF);
        result.put(key, v1.meet(v2));
    }
    for (String key : s2.keySet()) {
        if (!result.containsKey(key)) result.put(key, s2.get(key));
    }
    return result;
}
