public class CodeGenVisitor extends GJDepthFirst<String, Void> {
    ConstPropVisitor cp;
    CallGraphVisitor cg;

    String curClass = null, curMethod = null;

    public CodeGenVisitor(ConstPropVisitor cp, CallGraphVisitor cg) {
        this.cp = cp; this.cg = cg;
    }

    // Returns the CP value of a variable in the current scope
    CPValue cpVal(String varName) {
        return cp.getValue(curClass, curMethod, varName);
    }

    // Returns the string to emit for an identifier (constant or var name)
    String constOrId(String varName) {
        CPValue v = cpVal(varName);
        if (v.isConst()) return v.toCode();
        return varName;
    }

    // Goal
    @Override
    public String visit(Goal n, Void argu) {
        StringBuilder sb = new StringBuilder();
        sb.append(n.f0.accept(this, argu)); // MainClass
        // TypeDeclarations
        if (n.f1.present()) {
            for (Enumeration<Node> e = n.f1.elements(); e.hasMoreElements();) {
                sb.append(e.nextElement().accept(this, argu));
            }
        }
        return sb.toString();
    }

    @Override
    public String visit(MainClass n, Void argu) {
        curClass = n.f1.f0.tokenImage;
        curMethod = "main";
        StringBuilder sb = new StringBuilder();
        sb.append("class ").append(curClass).append(" {\n");
        sb.append("  public static void main(String[] ").append(n.f11.f0.tokenImage).append(") {\n");
        // VarDeclarations
        if (n.f14.present()) {
            for (Enumeration<Node> e = n.f14.elements(); e.hasMoreElements();) {
                sb.append("    ").append(e.nextElement().accept(this, argu));
            }
        }
        // Statements
        sb.append(genStmts(n.f15, "    "));
        sb.append("  }\n}\n");
        curClass = null; curMethod = null;
        return sb.toString();
    }

    // ... etc.
