// CPValue.java
public class CPValue {
    public enum Kind { UNDEF, CONST_INT, CONST_BOOL, NAC }

    public final Kind kind;
    public final int intVal;
    public final boolean boolVal;

    private CPValue(Kind k, int i, boolean b) {
        kind = k; intVal = i; boolVal = b;
    }

    public static final CPValue UNDEF = new CPValue(Kind.UNDEF, 0, false);
    public static final CPValue NAC   = new CPValue(Kind.NAC, 0, false);

    public static CPValue ofInt(int v)    { return new CPValue(Kind.CONST_INT, v, false); }
    public static CPValue ofBool(boolean v){ return new CPValue(Kind.CONST_BOOL, 0, v); }

    public boolean isConst() { return kind == Kind.CONST_INT || kind == Kind.CONST_BOOL; }

    public CPValue meet(CPValue other) {
        if (this.kind == Kind.UNDEF) return other;
        if (other.kind == Kind.UNDEF) return this;
        if (this.kind == Kind.NAC || other.kind == Kind.NAC) return NAC;
        // both are constants
        if (this.kind == other.kind) {
            if (this.kind == Kind.CONST_INT && this.intVal == other.intVal) return this;
            if (this.kind == Kind.CONST_BOOL && this.boolVal == other.boolVal) return this;
        }
        return NAC;
    }

    public String toCode() {
        if (kind == Kind.CONST_INT) return Integer.toString(intVal);
        if (kind == Kind.CONST_BOOL) return boolVal ? "true" : "false";
        throw new RuntimeException("Not a constant: " + kind);
    }

    @Override
    public boolean equals(Object o) {
        if (!(o instanceof CPValue)) return false;
        CPValue c = (CPValue) o;
        if (kind != c.kind) return false;
        if (kind == Kind.CONST_INT) return intVal == c.intVal;
        if (kind == Kind.CONST_BOOL) return boolVal == c.boolVal;
        return true; // UNDEF == UNDEF, NAC == NAC
    }

    @Override
    public int hashCode() {
        if (kind == Kind.CONST_INT) return intVal;
        if (kind == Kind.CONST_BOOL) return boolVal ? 1 : 0;
        return kind.ordinal();
    }

    @Override
    public String toString() {
        if (kind == Kind.CONST_INT) return "INT(" + intVal + ")";
        if (kind == Kind.CONST_BOOL) return "BOOL(" + boolVal + ")";
        return kind.toString();
    }
}
```

