// ClassHierarchyVisitor.java
import visitor.*;
import syntaxtree.*;
import java.util.*;

public class ClassHierarchyVisitor extends GJDepthFirst<String, Void> {
    // class name → parent class name (null if none)
    public Map<String, String> parentOf = new LinkedHashMap<>();
    // class name → set of direct subclasses
    public Map<String, Set<String>> childrenOf = new LinkedHashMap<>();
    // class name → set of method names declared in that class
    public Map<String, Set<String>> methodsOf = new LinkedHashMap<>();

    private String currentClass = null;

    // Get all subclasses of a class (transitively)
    public Set<String> allSubclasses(String cls) {
        Set<String> result = new LinkedHashSet<>();
        Queue<String> worklist = new LinkedList<>();
        Set<String> children = childrenOf.get(cls);
        if (children != null) worklist.addAll(children);
        while (!worklist.isEmpty()) {
            String c = worklist.poll();
            if (result.add(c)) {
                Set<String> ch = childrenOf.get(c);
                if (ch != null) worklist.addAll(ch);
            }
        }
        return result;
    }

    // Get all ancestors of a class (including itself)
    public List<String> ancestorChain(String cls) {
        List<String> chain = new ArrayList<>();
        String c = cls;
        while (c != null) {
            chain.add(c);
            c = parentOf.get(c);
        }
        return chain;
    }

    // Look up method in class or ancestors
    public String resolveMethod(String cls, String method) {
        for (String c : ancestorChain(cls)) {
            Set<String> methods = methodsOf.get(c);
            if (methods != null && methods.contains(method)) return c;
        }
        return null;
    }

    @Override
    public String visit(ClassDeclaration n, Void argu) {
        currentClass = n.f1.f0.tokenImage;
        parentOf.put(currentClass, null);
        childrenOf.put(currentClass, new LinkedHashSet<>());
        methodsOf.put(currentClass, new LinkedHashSet<>());
        n.f3.accept(this, argu); // VarDeclarations
        n.f4.accept(this, argu); // MethodDeclarations
        currentClass = null;
        return null;
    }

    @Override
    public String visit(ClassExtendsDeclaration n, Void argu) {
        currentClass = n.f1.f0.tokenImage;
        String parent = n.f3.f0.tokenImage;
        parentOf.put(currentClass, parent);
        childrenOf.computeIfAbsent(parent, k -> new LinkedHashSet<>()).add(currentClass);
        childrenOf.put(currentClass, new LinkedHashSet<>());
        methodsOf.put(currentClass, new LinkedHashSet<>());
        n.f5.accept(this, argu);
        n.f6.accept(this, argu);
        currentClass = null;
        return null;
    }

    @Override
    public String visit(MethodDeclaration n, Void argu) {
        String methodName = n.f2.f0.tokenImage;
        if (currentClass != null) {
            methodsOf.get(currentClass).add(methodName);
        }
        return null;
    }
}
