import visitor.*;
import syntaxtree.*;
import java.util.*;

public class SymbolTableVisitor extends GJDepthFirst<String, Void> {
    // (className, methodName, varName) → type
    // methodName = null for fields

    // fields[class][field] = type
    public Map<String, Map<String, String>> classFields = new LinkedHashMap<>();
    // locals[class][method][var] = type (includes parameters)
    public Map<String, Map<String, Map<String, String>>> methodLocals = new LinkedHashMap<>();
    // method return types: (class, method) → type
    public Map<String, Map<String, String>> methodReturnType = new LinkedHashMap<>();
    // method parameter order: (class, method) → list of param names
    public Map<String, Map<String, List<String>>> methodParams = new LinkedHashMap<>();

    private String currentClass = null;
    private String currentMethod = null;

    private String getTypeName(Type t) {
        Node choice = t.f0.choice;
        if (choice instanceof ArrayType) return "int[]";
        if (choice instanceof BooleanType) return "boolean";
        if (choice instanceof IntegerType) return "int";
        if (choice instanceof Identifier) return ((Identifier)choice).f0.tokenImage;
        return "unknown";
    }

    @Override
    public String visit(MainClass n, Void argu) {
        currentClass = n.f1.f0.tokenImage;
        currentMethod = "main";
        classFields.put(currentClass, new LinkedHashMap<>());
        methodLocals.computeIfAbsent(currentClass, k -> new LinkedHashMap<>())
                    .put(currentMethod, new LinkedHashMap<>());
        n.f14.accept(this, argu); // VarDeclarations
        currentClass = null;
        currentMethod = null;
        return null;
    }

    @Override
    public String visit(ClassDeclaration n, Void argu) {
        currentClass = n.f1.f0.tokenImage;
        classFields.put(currentClass, new LinkedHashMap<>());
        methodLocals.put(currentClass, new LinkedHashMap<>());
        methodReturnType.put(currentClass, new LinkedHashMap<>());
        methodParams.put(currentClass, new LinkedHashMap<>());
        n.f3.accept(this, argu); // VarDeclarations (fields)
        n.f4.accept(this, argu); // MethodDeclarations
        currentClass = null;
        return null;
    }

    @Override
    public String visit(ClassExtendsDeclaration n, Void argu) {
        currentClass = n.f1.f0.tokenImage;
        classFields.put(currentClass, new LinkedHashMap<>());
        methodLocals.put(currentClass, new LinkedHashMap<>());
        methodReturnType.put(currentClass, new LinkedHashMap<>());
        methodParams.put(currentClass, new LinkedHashMap<>());
        n.f5.accept(this, argu);
        n.f6.accept(this, argu);
        currentClass = null;
        return null;
    }

    @Override
    public String visit(VarDeclaration n, Void argu) {
        String type = getTypeName(n.f0);
        String name = n.f1.f0.tokenImage;
        if (currentMethod == null) {
            // field
            classFields.get(currentClass).put(name, type);
        } else {
            // local
            methodLocals.get(currentClass).get(currentMethod).put(name, type);
        }
        return null;
    }

    @Override
    public String visit(MethodDeclaration n, Void argu) {
        currentMethod = n.f2.f0.tokenImage;
        String retType = getTypeName(n.f1);
        methodReturnType.get(currentClass).put(currentMethod, retType);
        methodLocals.get(currentClass).put(currentMethod, new LinkedHashMap<>());
        methodParams.get(currentClass).put(currentMethod, new ArrayList<>());

        n.f4.accept(this, argu); // FormalParameterList
        n.f7.accept(this, argu); // VarDeclarations

        currentMethod = null;
        return null;
    }

    @Override
    public String visit(FormalParameter n, Void argu) {
        String type = getTypeName(n.f0);
        String name = n.f1.f0.tokenImage;
        methodLocals.get(currentClass).get(currentMethod).put(name, type);
        methodParams.get(currentClass).get(currentMethod).add(name);
        return null;
    }

    // Look up variable type in given scope (method locals, then class fields, then parent fields)
    public String lookupType(String cls, String method, String varName, ClassHierarchyVisitor ch) {
        // Check method locals
        Map<String, Map<String, String>> methods = methodLocals.get(cls);
        if (methods != null) {
            Map<String, String> locals = methods.get(method);
            if (locals != null && locals.containsKey(varName)) return locals.get(varName);
        }
        // Check class fields
        for (String c : ch.ancestorChain(cls)) {
            Map<String, String> fields = classFields.get(c);
            if (fields != null && fields.containsKey(varName)) return fields.get(varName);
        }
        return null;
    }
}
