        String mainClass = root.f0.f1.f0.tokenImage;
        Map<String,CPValue> mainState = new HashMap<>();
        // main has no parameters (well it has String[] args but we don't use it)
        // Initialize locals
        initState(mainClass, "main", mainState);
        analyzeBody(mainState, root.f0);
        finalStates.put(mainClass + ".main", mainState);
        markBranches(root.f0, mainState);

        // Analyze each reachable method in each class
        root.f1.accept(new AnalyzeClassesVisitor(), null);
    }

    private void initState(String cls, String meth, Map<String,CPValue> state) {
        Map<String, Map<String,String>> classMethods = st.methodLocals.get(cls);
        if (classMethods == null) return;
        Map<String,String> locals = classMethods.get(meth);
        if (locals == null) return;
        Set<String> params = new HashSet<>();
        Map<String,List<String>> classParams = st.methodParams.get(cls);
        if (classParams != null) {
            List<String> p = classParams.get(meth);
            if (p != null) params.addAll(p);
        }
        for (String var : locals.keySet()) {
            state.put(var, params.contains(var) ? CPValue.NAC : CPValue.UNDEF);
        }
    }

    // Analyze a method body (for MethodDeclaration)
    public void analyzeMethod(String cls, String meth, MethodDeclaration md) {
        Map<String,CPValue> state = new HashMap<>();
        initState(cls, meth, state);

        // Iterate to fixpoint
        Map<String,CPValue> prevState;
        do {
            prevState = copyState(state);
            // Reset state to initial (flow-insensitive)
            initState(cls, meth, state);
            // But MEET with prev (so values only go up in lattice)
            for (String v : prevState.keySet()) {
                if (state.containsKey(v)) {
                    state.put(v, state.get(v).meet(prevState.get(v)));
                }
            }
            // Process method body
            currentClass = cls;
            currentMethod = meth;
            processStatements(md.f8, state);
        } while (!statesEqual(state, prevState));

        finalStates.put(cls + "." + meth, state);
        markBranches(md, state);
    }

