// ClassHierarchyVisitor.java
import visitor.*;
import syntaxtree.*;
import java.util.*;

public class ClassHierarchyVisitor extends GJDepthFirst<Object, Object> {
    // class name → parent class (null if no extends)
    public Map<String, String> parent = new LinkedHashMap<>();
    // class name → direct children
    public Map<String, Set<String>> children = new LinkedHashMap<>();
    // class name → method names defined in that class
    public Map<String, Set<String>> methods = new LinkedHashMap<>();

    private String curClass = null;

    @Override
    public Object visit(ClassDeclaration n, Object argu) {
        curClass = n.f1.f0.tokenImage;
        parent.put(curClass, null);
        children.computeIfAbsent(curClass, k -> new LinkedHashSet<>());
        methods.put(curClass, new LinkedHashSet<>());
        n.f4.accept(this, argu); // methods
        curClass = null;
        return null;
    }

    @Override
    public Object visit(ClassExtendsDeclaration n, Object argu) {
        curClass = n.f1.f0.tokenImage;
        String par = n.f3.f0.tokenImage;
        parent.put(curClass, par);
        children.computeIfAbsent(par, k -> new LinkedHashSet<>()).add(curClass);
        children.computeIfAbsent(curClass, k -> new LinkedHashSet<>());
        methods.put(curClass, new LinkedHashSet<>());
        n.f6.accept(this, argu); // methods
        curClass = null;
        return null;
    }

    @Override
    public Object visit(MethodDeclaration n, Object argu) {
        if (curClass != null)
            methods.get(curClass).add(n.f2.f0.tokenImage);
        return null;
    }

    // All subclasses of cls (transitively)
    public Set<String> allSubclasses(String cls) {
        Set<String> res = new LinkedHashSet<>();
        Deque<String> queue = new ArrayDeque<>();
        Set<String> ch = children.get(cls);
        if (ch != null) queue.addAll(ch);
        while (!queue.isEmpty()) {
            String c = queue.poll();
            if (res.add(c)) {
                Set<String> ch2 = children.get(c);
                if (ch2 != null) queue.addAll(ch2);
            }
        }
        return res;
    }

    // Ancestor chain from cls up (inclusive)
    public List<String> ancestors(String cls) {
        List<String> chain = new ArrayList<>();
        String c = cls;
        while (c != null) {
            chain.add(c);
            c = parent.get(c);
        }
        return chain;
    }

    // Find which class in cls's hierarchy defines method (for CHA dispatch)
    public String resolveMethod(String cls, String meth) {
        for (String c : ancestors(cls)) {
            Set<String> ms = methods.get(c);
            if (ms != null && ms.contains(meth)) return c;
        }
        return null;
    }
}
