    }

    @Override
    public Object visit(FormalParameter n, Object argu) {
        String type = typeName(n.f0);
        String name = n.f1.f0.tokenImage;
        methodVars.get(curClass).get(curMethod).put(name, type);
        methodParams.get(curClass).get(curMethod).add(name);
        return null;
    }

    // Look up the type of a variable in a given scope (method locals, then class fields, then parent fields)
    public String lookupType(String cls, String meth, String varName, ClassHierarchyVisitor ch) {
        // Method locals
        Map<String, Map<String,String>> cm = methodVars.get(cls);
        if (cm != null) {
            Map<String,String> locs = cm.get(meth);
            if (locs != null && locs.containsKey(varName)) return locs.get(varName);
        }
        // Class fields (including inherited)
        for (String c : ch.ancestors(cls)) {
            Map<String,String> flds = classFields.get(c);
            if (flds != null && flds.containsKey(varName)) return flds.get(varName);
        }
        return null;
    }

    public boolean isParam(String cls, String meth, String var) {
        Map<String, List<String>> cm = methodParams.get(cls);
        if (cm == null) return false;
        List<String> ps = cm.get(meth);
        return ps != null && ps.contains(var);
    }
