    public void build(Goal root) {
        // Phase 1: index
        root.accept(this, null);

        // Phase 2: reachability
        reachable.add(mainClass + ".main");
        Deque<String> worklist = new ArrayDeque<>();
        worklist.add(mainClass + ".main");
        // Process main body
        processCallsInMain(root.f0, worklist);

        while (!worklist.isEmpty()) {
            String sig = worklist.poll();
            if (sig.endsWith(".main")) continue; // already done
            MethodDeclaration md = methodNodes.get(sig);
            if (md == null) continue;
            String cls = sig.substring(0, sig.lastIndexOf('.'));
            String meth = sig.substring(sig.lastIndexOf('.') + 1);
            processCallsInMethod(md, cls, meth, worklist);
        }

        // Phase 3: side effects
        analyzeSideEffects(root);
    }

    private void processCallsInMain(MainClass mc, Deque<String> worklist) {
        // Find all MessageSends in main body
        CallFinder finder = new CallFinder(mainClass, "main");
        mc.f15.accept(finder, null);
        for (String target : finder.targets) {
            if (reachable.add(target)) worklist.add(target);
        }
    }

    private void processCallsInMethod(MethodDeclaration md, String cls, String meth, Deque<String> worklist) {
        CallFinder finder = new CallFinder(cls, meth);
        md.f8.accept(finder, null); // statements
        // Also check the return expression? The return is just an Identifier, no calls there.
        for (String target : finder.targets) {
            if (reachable.add(target)) worklist.add(target);
        }
    }

    // Finds all CHA-resolved call targets in a subtree
    class CallFinder extends GJDepthFirst<Object, Object> {
        String callerClass, callerMethod;
        Set<String> targets = new LinkedHashSet<>();

        CallFinder(String cls, String meth) {
            callerClass = cls;
            callerMethod = meth;
        }

        @Override
        public Object visit(MessageSend n, Object argu) {
            // Resolve receiver type
            String recvType = resolveReceiverType(n.f0, callerClass, callerMethod);
            String methodName = n.f2.f0.tokenImage;
            if (recvType != null) {
                targets.addAll(chaResolve(recvType, methodName));
            }
            n.f4.accept(this, argu); // args might have calls? In TACoJava, args are just identifiers, so no
            return null;
        }
    }

    String resolveReceiverType(PrimaryExpression pe, String cls, String meth) {
        Node choice = pe.f0.choice;
        if (choice instanceof Identifier) {
            String varName = ((Identifier)choice).f0.tokenImage;
            return st.lookupType(cls, meth, varName, ch);
        }
        if (choice instanceof ThisExpression) return cls;
        if (choice instanceof AllocationExpression)
            return ((AllocationExpression)choice).f1.f0.tokenImage;
        return null;
    }

    Set<String> chaResolve(String receiverType, String methodName) {
        Set<String> result = new LinkedHashSet<>();
        // All classes including subclasses
        Set<String> allCls = new LinkedHashSet<>();
        allCls.add(receiverType);
        allCls.addAll(ch.allSubclasses(receiverType));
        for (String c : allCls) {
            String defCls = ch.resolveMethod(c, methodName);
            if (defCls != null) result.add(defCls + "." + methodName);
