```java
// ConstPropVisitor.java
import visitor.*;
import syntaxtree.*;
import java.util.*;

public class ConstPropVisitor {
    ClassHierarchyVisitor ch;
    SymbolTableVisitor st;
    CallGraphVisitor cg;

    // Final CP states: "Class.method" → {varName → CPValue}
    public Map<String, Map<String, CPValue>> finalStates = new LinkedHashMap<>();

    // Dead branch decisions for if statements: IfStatement → 0 (then), 1 (else), -1 (both/unknown)
    public IdentityHashMap<IfStatement, Integer> ifDecision = new IdentityHashMap<>();
    // Dead while loops: WhileStatement → true if never executes
    public IdentityHashMap<WhileStatement, Boolean> whileDead = new IdentityHashMap<>();

    public ConstPropVisitor(ClassHierarchyVisitor ch, SymbolTableVisitor st, CallGraphVisitor cg) {
        this.ch = ch; this.st = st; this.cg = cg;
    }

    public void analyze(Goal root) {
        String mainCls = root.f0.f1.f0.tokenImage;
        Map<String,CPValue> mainState = initState(mainCls, "main");
        // Process main statements to fixpoint
        analyzeStmts(root.f0.f15, mainCls, "main", mainState);
        finalStates.put(mainCls + ".main", mainState);
        markBranches(root.f0.f15, mainCls, "main", mainState);

        // Analyze each reachable method
        analyzeClasses(root.f1, mainCls);
    }

    private void analyzeClasses(NodeListOptional typeDecls, String mainCls) {
        // Visit each TypeDeclaration
        if (!typeDecls.present()) return;
        for (Enumeration<Node> e = typeDecls.elements(); e.hasMoreElements();) {
            Node td = e.nextElement();
            // TypeDeclaration -> NodeChoice -> ClassDeclaration or ClassExtendsDeclaration
            TypeDeclaration tdNode = (TypeDeclaration) td;
            Node choice = tdNode.f0.choice;
            String cls;
            NodeListOptional methodList;
            if (choice instanceof ClassDeclaration) {
                ClassDeclaration cd = (ClassDeclaration) choice;
                cls = cd.f1.f0.tokenImage;
                methodList = cd.f4;
            } else {
                ClassExtendsDeclaration ced = (ClassExtendsDeclaration) choice;
                cls = ced.f1.f0.tokenImage;
                methodList = ced.f6;
            }
            // Analyze each reachable method
            if (methodList.present()) {
                for (Enumeration<Node> me = methodList.elements(); me.hasMoreElements();) {
                    MethodDeclaration md = (MethodDeclaration) me.nextElement();
                    String meth = md.f2.f0.tokenImage;
                    if (cg.isReachable(cls, meth)) {
                        Map<String,CPValue> state = initState(cls, meth);
                        analyzeStmts(md.f8, cls, meth, state);
                        finalStates.put(cls + "." + meth, state);
                        markBranches(md.f8, cls, meth, state);
                    }
                }
            }
        }
    }

    private Map<String,CPValue> initState(String cls, String meth) {
        Map<String,CPValue> state = new LinkedHashMap<>();
        Map<String,Map<String,String>> cm = st.methodVars.get(cls);
        if (cm == null) return state;
        Map<String,String> vars = cm.get(meth);
        if (vars == null) return state;
        Set<String> params = new HashSet<>();
        Map<String,List<String>> cmp = st.methodParams.get(cls);
        if (cmp != null) {
            List<String> pl = cmp.get(meth);
            if (pl != null) params.addAll(pl);
        }
        for (String v : vars.keySet()) {
            state.put(v, params.contains(v) ? CPValue.NAC : CPValue.UNDEF);
        }
        return state;
    }

    // Iteratively process statements until state fixpoint
    private void analyzeStmts(NodeListOptional stmts, String cls, String meth, Map<String,CPValue> state) {
        if (!stmts.present()) return;
        Map<String,CPValue> prev;
        do {
            prev = copyState(state);
            processStmtList(stmts, cls, meth, state);
        } while (!prev.equals(state));
    }

    private void processStmtList(NodeListOptional stmts, String cls, String meth, Map<String,CPValue> state) {
        if (!stmts.present()) return;
        for (Enumeration<Node> e = stmts.elements(); e.hasMoreElements();) {
            processStmt((Statement) e.nextElement(), cls, meth, state);
        }
    }

    private void processStmt(Statement s, String cls, String meth, Map<String,CPValue> state) {
        Node choice = s.f0.choice;
        if (choice instanceof Block) {
            processStmtList(((Block)choice).f1, cls, meth, state);
        } else if (choice instanceof AssignmentStatement) {
            AssignmentStatement as = (AssignmentStatement) choice;
            String lhs = as.f0.f0.tokenImage;
            CPValue rhs = evalExpr(as.f2, cls, meth, state);
            if (state.containsKey(lhs)) {
                state.put(lhs, state.get(lhs).meet(rhs));
            }
        } else if (choice instanceof IfStatement) {
            IfStatement is = (IfStatement) choice;
            String cond = is.f2.f0.tokenImage;
            CPValue condVal = lookup(cond, state);
            if (condVal.kind == CPValue.KIND_BOOL) {
                if (condVal.boolVal) {
                    // only then branch
                    processStmt(is.f4, cls, meth, state);
                } else {
                    // only else branch
                    processStmt(is.f6, cls, meth, state);
                }
            } else {
                // both branches
                processStmt(is.f4, cls, meth, state);
                processStmt(is.f6, cls, meth, state);
            }
        } else if (choice instanceof WhileStatement) {
            WhileStatement ws = (WhileStatement) choice;
            String cond = ws.f2.f0.tokenImage;
            CPValue condVal = lookup(cond, state);
            if (condVal.kind == CPValue.KIND_BOOL && !condVal.boolVal) {
                // loop never runs
            } else {
                processStmt(ws.f4, cls, meth, state);
            }
        } else if (choice instanceof ForStatement) {
            ForStatement fs = (ForStatement) choice;
            // Process init, condition, body, increment
            // Init: fs.f2 = Identifier, fs.f4 = Expression
            String initVar = fs.f2.f0.tokenImage;
            CPValue initVal = evalExpr(fs.f4, cls, meth, state);
            if (state.containsKey(initVar)) state.put(initVar, state.get(initVar).meet(initVal));
            // Condition: fs.f6 = Expression (we don't use its value for now)
            // Body: fs.f12 = Statement
            processStmt(fs.f12, cls, meth, state);
            // Increment: fs.f8 = Identifier, fs.f10 = Expression
            String incrVar = fs.f8.f0.tokenImage;
            CPValue incrVal = evalExpr(fs.f10, cls, meth, state);
            if (state.containsKey(incrVar)) state.put(incrVar, state.get(incrVar).meet(incrVal));
        }
        // ArrayAssignmentStatement, FieldAssignmentStatement, PrintStatement: no CP effect on locals
    }

    private CPValue lookup(String varName, Map<String,CPValue> state) {
        CPValue v = state.get(varName);
        return v != null ? v : CPValue.NAC;
    }

    private CPValue evalExpr(Expression e, String cls, String meth, Map<String,CPValue> state) {
        Node choice = e.f0.choice;
        if (choice instanceof PlusExpression) {
            PlusExpression pe = (PlusExpression) choice;
            CPValue l = lookup(pe.f0.f0.tokenImage, state);
            CPValue r = lookup(pe.f2.f0.tokenImage, state);
            if (l.isInt() && r.isInt()) return CPValue.ofInt(l.intVal + r.intVal);
            return CPValue.NAC;
        } else if (choice instanceof MinusExpression) {
            MinusExpression me = (MinusExpression) choice;
            CPValue l = lookup(me.f0.f0.tokenImage, state);
            CPValue r = lookup(me.f2.f0.tokenImage, state);
            if (l.isInt() && r.isInt()) return CPValue.ofInt(l.intVal - r.intVal);
            return CPValue.NAC;
        } else if (choice instanceof TimesExpression) {
            TimesExpression te = (TimesExpression) choice;
            CPValue l = lookup(te.f0.f0.tokenImage, state);
            CPValue r = lookup(te.f2.f0.tokenImage, state);
            if (l.isInt() && r.isInt()) return CPValue.ofInt(l.intVal * r.intVal);
            return CPValue.NAC;
        } else if (choice instanceof CompareExpression) {
            CompareExpression ce = (CompareExpression) choice;
            CPValue l = lookup(ce.f0.f0.tokenImage, state);
            CPValue r = lookup(ce.f2.f0.tokenImage, state);
            if (l.isInt() && r.isInt()) return CPValue.ofBool(l.intVal < r.intVal);
            return CPValue.NAC;
        } else if (choice instanceof PrimaryExpression) {
            return evalPrimary((PrimaryExpression)choice, state);
        } else {
            // MessageSend, ArrayLookup, ArrayLength, FieldRead → NAC
            return CPValue.NAC;
        }
    }

    private CPValue evalPrimary(PrimaryExpression pe, Map<String,CPValue> state) {
        Node choice = pe.f0.choice;
        if (choice instanceof IntegerLiteral) {
            String s = ((IntegerLiteral)choice).f0.tokenImage;
            return CPValue.ofInt(Integer.parseInt(s));
        } else if (choice instanceof TrueLiteral) {
            return CPValue.ofBool(true);
        } else if (choice instanceof FalseLiteral) {
            return CPValue.ofBool(false);
        } else if (choice instanceof Identifier) {
            return lookup(((Identifier)choice).f0.tokenImage, state);
        } else if (choice instanceof NotExpression) {
            String var = ((NotExpression)choice).f1.f0.tokenImage;
            CPValue v = lookup(var, state);
            if (v.isBool()) return CPValue.ofBool(!v.boolVal);
            return CPValue.NAC;
        } else {
            // ThisExpression, ArrayAllocationExpression, AllocationExpression → NAC
            return CPValue.NAC;
        }
    }

    // After computing final state, mark dead branches
    private void markBranches(NodeListOptional stmts, String cls, String meth, Map<String,CPValue> state) {
        if (!stmts.present()) return;
        for (Enumeration<Node> e = stmts.elements(); e.hasMoreElements();) {
            markBranchesInStmt((Statement)e.nextElement(), cls, meth, state);
        }
    }

    private void markBranchesInStmt(Statement s, String cls, String meth, Map<String,CPValue> state) {
        Node choice = s.f0.choice;
        if (choice instanceof Block) {
            markBranches(((Block)choice).f1, cls, meth, state);
        } else if (choice instanceof IfStatement) {
            IfStatement is = (IfStatement) choice;
            String cond = is.f2.f0.tokenImage;
            CPValue condVal = state.get(cond);
            if (condVal != null && condVal.isBool()) {
                ifDecision.put(is, condVal.boolVal ? 0 : 1);
            } else {
                ifDecision.put(is, -1);
            }
            // Recurse into branches
            markBranchesInStmt(is.f4, cls, meth, state);
            markBranchesInStmt(is.f6, cls, meth, state);
        } else if (choice instanceof WhileStatement) {
            WhileStatement ws = (WhileStatement) choice;
            String cond = ws.f2.f0.tokenImage;
            CPValue condVal = state.get(cond);
            boolean dead = (condVal != null && condVal.isBool() && !condVal.boolVal);
            whileDead.put(ws, dead);
            if (!dead) markBranchesInStmt(ws.f4, cls, meth, state);
        }
        // Other statements: no branching
    }

    private Map<String,CPValue> copyState(Map<String,CPValue> s) {
        return new LinkedHashMap<>(s);
    }

    // Get CP value of a variable in a method scope
    public CPValue getValue(String cls, String meth, String varName) {
        Map<String,CPValue> state = finalStates.get(cls + "." + meth);
        if (state == null) return CPValue.NAC;
        CPValue v = state.get(varName);
        return v != null ? v : CPValue.NAC;
    }
}
