```java
void genStatement(Statement s, String indent) {
    Node choice = s.f0.choice;

    if (choice instanceof Block) {
        Block b = (Block) choice;
        sb.append(indent).append("{\n");
        if (b.f1.present()) {
            for (Enumeration<Node> e = b.f1.elements(); e.hasMoreElements();) {
                genStatement((Statement) e.nextElement(), indent + "  ");
            }
        }
        sb.append(indent).append("}\n");
    } else if (choice instanceof AssignmentStatement) {
        AssignmentStatement as = (AssignmentStatement) choice;
        String lhs = as.f0.f0.tokenImage;
        CPValue lhsVal = cpVal(lhs);
        Node exprChoice = as.f2.f0.choice;
        boolean exprIsMsgSend = exprChoice instanceof MessageSend;
        boolean exprHasSideEffect = exprIsMsgSend && msgSendHasSE((MessageSend)exprChoice);

        // Check if this is a dead assignment
        // A assignment is dead if: lhs is a constant (substituted everywhere) AND rhs has no side effects
        // OR: lhs is never read (but we use the constant-substitution heuristic)
        if (lhsVal.isConst() && !exprHasSideEffect) {
            // Dead assignment, skip it
            return;
        } else if (lhsVal.isConst() && exprHasSideEffect) {
            // Lhs is constant (substituted everywhere) but RHS has side effects
            // Emit as VoidMessageSendStatement
            sb.append(indent);
            genMessageSend((MessageSend)exprChoice);
            sb.append(";\n");
        } else {
            // Normal assignment
            sb.append(indent).append(lhs).append(" = ");
            genExpr(as.f2);
            sb.append(";\n");
        }
    } else if (choice instanceof IfStatement) {
        IfStatement is = (IfStatement) choice;
        Integer decision = cp.ifDecision.get(is);
        if (decision == null || decision == -1) {
            // Full if/else
            sb.append(indent).append("if (").append(is.f2.f0.tokenImage).append(")\n");
            genStatementBody(is.f4, indent);
            sb.append(indent).append("else\n");
            genStatementBody(is.f6, indent);
        } else if (decision == 0) {
            // Then branch only
            genStatementBody(is.f4, indent);
        } else {
            // Else branch only
            genStatementBody(is.f6, indent);
        }
    } else if (choice instanceof WhileStatement) {
        WhileStatement ws = (WhileStatement) choice;
        Boolean dead = cp.whileDead.get(ws);
        if (dead != null && dead) {
            // Skip - loop never executes
        } else {
            sb.append(indent).append("while (").append(ws.f2.f0.tokenImage).append(")\n");
            genStatementBody(ws.f4, indent);
        }
    } else if (choice instanceof ForStatement) {
        ForStatement fs = (ForStatement) choice;
        // For now, emit as-is (with constant substitution for expressions)
        sb.append(indent).append("for (").append(fs.f2.f0.tokenImage).append(" = ");
        genExpr(fs.f4);
        sb.append("; ");
        genExpr(fs.f6);
        sb.append("; ").append(fs.f8.f0.tokenImage).append(" = ");
        genExpr(fs.f10);
        sb.append(")\n");
        genStatementBody(fs.f12, indent);
    } else if (choice instanceof PrintStatement) {
        PrintStatement ps = (PrintStatement) choice;
        sb.append(indent).append("System.out.println(");
        sb.append(constOrId(ps.f2.f0.tokenImage));
        sb.append(");\n");
    } else if (choice instanceof ArrayAssignmentStatement) {
        ArrayAssignmentStatement aas = (ArrayAssignmentStatement) choice;
        sb.append(indent).append(aas.f0.f0.tokenImage).append("[");
        sb.append(constOrId(aas.f2.f0.tokenImage));
        sb.append("] = ");
        sb.append(constOrId(aas.f5.f0.tokenImage));
        sb.append(";\n");
    } else if (choice instanceof FieldAssignmentStatement) {
        FieldAssignmentStatement fas = (FieldAssignmentStatement) choice;
        sb.append(indent).append(fas.f0.f0.tokenImage).append(".").append(fas.f2.f0.tokenImage);
        sb.append(" = ").append(constOrId(fas.f4.f0.tokenImage)).append(";\n");
    }
}
