```java
void genExpr(Expression e) {
    Node choice = e.f0.choice;
    if (choice instanceof PlusExpression) {
        PlusExpression pe = (PlusExpression) choice;
        sb.append(constOrId(pe.f0.f0.tokenImage)).append(" + ").append(constOrId(pe.f2.f0.tokenImage));
    } else if (choice instanceof MinusExpression) {
        MinusExpression me = (MinusExpression) choice;
        sb.append(constOrId(me.f0.f0.tokenImage)).append(" - ").append(constOrId(me.f2.f0.tokenImage));
    } else if (choice instanceof TimesExpression) {
        TimesExpression te = (TimesExpression) choice;
        sb.append(constOrId(te.f0.f0.tokenImage)).append(" * ").append(constOrId(te.f2.f0.tokenImage));
    } else if (choice instanceof CompareExpression) {
        CompareExpression ce = (CompareExpression) choice;
        sb.append(constOrId(ce.f0.f0.tokenImage)).append(" < ").append(constOrId(ce.f2.f0.tokenImage));
    } else if (choice instanceof ArrayLookup) {
        ArrayLookup al = (ArrayLookup) choice;
        sb.append(al.f0.f0.tokenImage).append("[").append(constOrId(al.f2.f0.tokenImage)).append("]");
    } else if (choice instanceof ArrayLength) {
        ArrayLength al = (ArrayLength) choice;
        sb.append(al.f0.f0.tokenImage).append(".length");
    } else if (choice instanceof MessageSend) {
        genMessageSend((MessageSend) choice);
    } else if (choice instanceof FieldRead) {
        FieldRead fr = (FieldRead) choice;
        sb.append(fr.f0.f0.tokenImage).append(".").append(fr.f2.f0.tokenImage);
    } else if (choice instanceof PrimaryExpression) {
        genPrimary((PrimaryExpression) choice);
    }
}

void genMessageSend(MessageSend ms) {
    genPrimary(ms.f0); // receiver
    sb.append(".").append(ms.f2.f0.tokenImage).append("(");
    if (ms.f4.present()) {
        ArgList al = (ArgList) ms.f4.node;
        sb.append(constOrId(al.f0.f0.tokenImage)); // first arg
        if (al.f1.present()) {
            for (Enumeration<Node> e = al.f1.elements(); e.hasMoreElements();) {
                ArgRest ar = (ArgRest) e.nextElement();
                sb.append(", ").append(constOrId(ar.f1.f0.tokenImage));
            }
        }
    }
    sb.append(")");
}

void genPrimary(PrimaryExpression pe) {
    Node choice = pe.f0.choice;
    if (choice instanceof IntegerLiteral) {
        sb.append(((IntegerLiteral)choice).f0.tokenImage);
    } else if (choice instanceof TrueLiteral) {
        sb.append("true");
    } else if (choice instanceof FalseLiteral) {
        sb.append("false");
    } else if (choice instanceof Identifier) {
        sb.append(constOrId(((Identifier)choice).f0.tokenImage));
    } else if (choice instanceof ThisExpression) {
        sb.append("this");
    } else if (choice instanceof ArrayAllocationExpression) {
        ArrayAllocationExpression aae = (ArrayAllocationExpression) choice;
        sb.append("new int[").append(constOrId(aae.f3.f0.tokenImage)).append("]");
    } else if (choice instanceof AllocationExpression) {
        AllocationExpression ae = (AllocationExpression) choice;
        sb.append("new ").append(ae.f1.f0.tokenImage).append("()");
    } else if (choice instanceof NotExpression) {
        NotExpression ne = (NotExpression) choice;
        sb.append("!").append(ne.f1.f0.tokenImage);
    }
}
```

