```java
public class CpValue {
    public enum Kind { UNDEF, INT, BOOL, NAC }

    public final Kind kind;
    public final int intVal;
    public final boolean boolVal;

    private CpValue(Kind kind, int intVal, boolean boolVal) {
        this.kind = kind;
        this.intVal = intVal;
        this.boolVal = boolVal;
    }

    public static final CpValue UNDEF = new CpValue(Kind.UNDEF, 0, false);
    public static final CpValue NAC = new CpValue(Kind.NAC, 0, false);
    public static final CpValue TRUE = new CpValue(Kind.BOOL, 0, true);
    public static final CpValue FALSE = new CpValue(Kind.BOOL, 0, false);

    public static CpValue ofInt(int v) { return new CpValue(Kind.INT, v, false); }
    public static CpValue ofBool(boolean v) { return v ? TRUE : FALSE; }

    public boolean isConst() { return kind == Kind.INT || kind == Kind.BOOL; }
    public boolean isTrue() { return kind == Kind.BOOL && boolVal; }
    public boolean isFalse() { return kind == Kind.BOOL && !boolVal; }

    public CpValue meet(CpValue other) {
        if (this.kind == Kind.UNDEF) return other;
        if (other.kind == Kind.UNDEF) return this;
        if (this.kind == Kind.NAC || other.kind == Kind.NAC) return NAC;
        // Both are constants
        if (this.kind == Kind.INT && other.kind == Kind.INT && this.intVal == other.intVal)
            return this;
        if (this.kind == Kind.BOOL && other.kind == Kind.BOOL && this.boolVal == other.boolVal)
            return this;
        return NAC;
    }

    public String toTACoJava2() {
        if (kind == Kind.INT) return Integer.toString(intVal);
        if (kind == Kind.BOOL) return boolVal ? "true" : "false";
        throw new RuntimeException("CpValue is not a constant");
    }

    @Override
    public boolean equals(Object o) {
        if (!(o instanceof CpValue)) return false;
        CpValue c = (CpValue) o;
        if (kind != c.kind) return false;
        if (kind == Kind.INT) return intVal == c.intVal;
        if (kind == Kind.BOOL) return boolVal == c.boolVal;
        return true;
    }

    @Override
    public String toString() {
        switch (kind) {
            case UNDEF: return "UNDEF";
            case NAC: return "NAC";
            case INT: return "INT(" + intVal + ")";
            case BOOL: return "BOOL(" + boolVal + ")";
        }
        return "?";
    }
}
