```java
import visitor.*;
import syntaxtree.*;
import java.util.*;

public class ClassHierarchyVisitor extends GJDepthFirst<String, Void> {
    // class name -> parent class name (null if no parent)
    public Map<String, String> parentOf = new LinkedHashMap<>();
    // class name -> direct children
    public Map<String, Set<String>> childrenOf = new LinkedHashMap<>();
    // class name -> set of method names declared in class
    public Map<String, Set<String>> methodsOf = new LinkedHashMap<>();
    // all class names (including main class)
    public Set<String> allClasses = new LinkedHashSet<>();
    // main class name
    public String mainClass;

    private String currentClass;

    @Override
    public String visit(Goal n, Void argu) {
        n.f0.accept(this, argu); // MainClass
        n.f1.accept(this, argu); // TypeDeclarations
        return null;
    }

    @Override
    public String visit(MainClass n, Void argu) {
        String name = n.f1.accept(this, argu);
        mainClass = name;
        allClasses.add(name);
        parentOf.put(name, null);
        childrenOf.put(name, new LinkedHashSet<>());
        methodsOf.put(name, new LinkedHashSet<>());
        return null;
    }

    @Override
    public String visit(ClassDeclaration n, Void argu) {
        String name = n.f1.accept(this, argu);
        currentClass = name;
        allClasses.add(name);
        parentOf.put(name, null);
        childrenOf.put(name, new LinkedHashSet<>());
        methodsOf.put(name, new LinkedHashSet<>());
        n.f4.accept(this, argu); // methods
        currentClass = null;
        return null;
    }

    @Override
    public String visit(ClassExtendsDeclaration n, Void argu) {
        String name = n.f1.accept(this, argu);
        String parent = n.f3.accept(this, argu);
        currentClass = name;
        allClasses.add(name);
        parentOf.put(name, parent);
        childrenOf.computeIfAbsent(parent, k -> new LinkedHashSet<>()).add(name);
        childrenOf.put(name, new LinkedHashSet<>());
        methodsOf.put(name, new LinkedHashSet<>());
        n.f6.accept(this, argu); // methods
        currentClass = null;
        return null;
    }

    @Override
    public String visit(MethodDeclaration n, Void argu) {
        String name = n.f2.accept(this, argu);
        if (currentClass != null) {
            methodsOf.computeIfAbsent(currentClass, k -> new LinkedHashSet<>()).add(name);
        }
        return null;
    }

    @Override
    public String visit(Identifier n, Void argu) {
        return n.f0.tokenImage;
    }

    // Get all subclasses of a class (including itself)
    public Set<String> getAllSubclasses(String className) {
        Set<String> result = new LinkedHashSet<>();
        Queue<String> worklist = new LinkedList<>();
        worklist.add(className);
        while (!worklist.isEmpty()) {
            String c = worklist.poll();
            result.add(c);
            Set<String> children = childrenOf.get(c);
            if (children != null) worklist.addAll(children);
        }
        return result;
    }

    // Find which class actually defines a method (walking up the hierarchy)
    public String findDefiningClass(String className, String methodName) {
        String c = className;
        while (c != null) {
            Set<String> methods = methodsOf.get(c);
            if (methods != null && methods.contains(methodName)) return c;
            c = parentOf.get(c);
        }
        return null;
    }
}
