import visitor.*;
import syntaxtree.*;
import java.util.*;

public class ClassHierarchyVisitor extends GJDepthFirst<String, Void> {
    public Map<String, String> parentOf = new LinkedHashMap<>();
    public Map<String, Set<String>> childrenOf = new LinkedHashMap<>();
    public Map<String, Set<String>> methodsOf = new LinkedHashMap<>();
    public Set<String> allClasses = new LinkedHashSet<>();
    public String mainClass;

    private String currentClass;

    @Override
    public String visit(Goal n, Void argu) {
        n.f0.accept(this, argu);
        n.f1.accept(this, argu);
        return null;
    }

    @Override
    public String visit(MainClass n, Void argu) {
        mainClass = n.f1.f0.tokenImage;
        registerClass(mainClass, null);
        return null;
    }

    @Override
    public String visit(TypeDeclaration n, Void argu) {
        return n.f0.accept(this, argu);
    }

    @Override
    public String visit(ClassDeclaration n, Void argu) {
        String name = n.f1.f0.tokenImage;
        currentClass = name;
        registerClass(name, null);
        n.f4.accept(this, argu); // method declarations
        currentClass = null;
        return null;
    }

    @Override
    public String visit(ClassExtendsDeclaration n, Void argu) {
        String name = n.f1.f0.tokenImage;
        String parent = n.f3.f0.tokenImage;
        currentClass = name;
        registerClass(name, parent);
        childrenOf.computeIfAbsent(parent, k -> new LinkedHashSet<>()).add(name);
        n.f6.accept(this, argu); // method declarations
        currentClass = null;
        return null;
    }

    @Override
    public String visit(MethodDeclaration n, Void argu) {
        if (currentClass != null) {
            methodsOf.get(currentClass).add(n.f2.f0.tokenImage);
        }
        return null;
    }

    private void registerClass(String name, String parent) {
        allClasses.add(name);
        parentOf.put(name, parent);
        childrenOf.computeIfAbsent(name, k -> new LinkedHashSet<>());
        methodsOf.put(name, new LinkedHashSet<>());
    }

    public Set<String> getAllSubclasses(String className) {
        Set<String> result = new LinkedHashSet<>();
        Queue<String> worklist = new LinkedList<>();
        worklist.add(className);
        while (!worklist.isEmpty()) {
            String c = worklist.poll();
            if (result.add(c)) {
                Set<String> ch = childrenOf.get(c);
                if (ch != null) worklist.addAll(ch);
            }
        }
        return result;
    }

    // Find the class that actually defines method `methodName` starting from `className` walking up hierarchy
    public String resolveMethod(String className, String methodName) {
        String c = className;
        while (c != null) {
            Set<String> methods = methodsOf.get(c);
            if (methods != null && methods.contains(methodName)) return c;
            c = parentOf.get(c);
        }
        return null;
    }
}
