public class CallGraphVisitor extends GJDepthFirst<String, Void> {
    private ClassHierarchyVisitor hier;
    private SymbolTableVisitor sym;

    // All method declaration nodes indexed by "class#method"
    public Map<String, MethodDeclaration> methodDecls = new LinkedHashMap<>();
    // The AST of the main class (for scanning main method)
    public MainClass mainClassNode;

    // Reachable methods as "class#method"
    public Set<String> reachableMethods = new LinkedHashSet<>();

    // Methods that have side effects (print, field-write, or call to method with side effects)
    public Set<String> sideEffectMethods = new LinkedHashSet<>();

    private String currentClass;
    private String currentMethod;

    public CallGraphVisitor(ClassHierarchyVisitor hier, SymbolTableVisitor sym) {
        this.hier = hier;
        this.sym = sym;
    }

    // Phase 1: Index all method declaration nodes
    @Override
    public String visit(Goal n, Void argu) {
        n.f0.accept(this, argu); // MainClass
        n.f1.accept(this, argu); // TypeDeclarations
        return null;
    }

    @Override
    public String visit(MainClass n, Void argu) {
        mainClassNode = n;
        currentClass = n.f1.f0.tokenImage;
        // Don't index main as a MethodDeclaration - it's special
        currentClass = null;
        return null;
    }

    @Override
    public String visit(ClassDeclaration n, Void argu) {
        currentClass = n.f1.f0.tokenImage;
        n.f4.accept(this, argu);
        currentClass = null;
        return null;
    }

    @Override
    public String visit(ClassExtendsDeclaration n, Void argu) {
        currentClass = n.f1.f0.tokenImage;
        n.f6.accept(this, argu);
        currentClass = null;
        return null;
    }

    @Override
    public String visit(MethodDeclaration n, Void argu) {
        String methodName = n.f2.f0.tokenImage;
        String key = currentClass + "#" + methodName;
        methodDecls.put(key, n);
        return null;
    }

    // Phase 2: Compute reachability starting from main using BFS
    public void computeReachability() {
        // Compute side effects first (needed for elision)
        computeSideEffects();

        // BFS from main
        Queue<String> worklist = new LinkedList<>();
        String mainKey = hier.mainClass + "#main";
        reachableMethods.add(mainKey);
        worklist.add(mainKey);

        while (!worklist.isEmpty()) {
            String mk = worklist.poll();
            Set<String> callees = findCallees(mk);
            for (String callee : callees) {
                if (reachableMethods.add(callee)) {
                    worklist.add(callee);
                }
            }
        }
    }

    // Find all methods called from the given method key
    private Set<String> findCallees(String methodKey) {
        Set<String> callees = new LinkedHashSet<>();
        // Get the method body to scan
        MethodDeclaration md = methodDecls.get(methodKey);
        if (md == null) {
            // It's main - scan mainClassNode
            if (methodKey.endsWith("#main")) {
                scanForCalls(mainClassNode, callees, hier.mainClass, "main");
            }
            return callees;
        }
        // Extract class from key
        String cls = methodKey.split("#")[0];
        scanForCalls(md, callees, cls, methodKey.split("#")[1]);
        return callees;
    }

    // Visitor to scan a method body for MessageSend nodes
    private void scanForCalls(Node startNode, Set<String> callees, String inClass, String inMethod) {
        CallScanVisitor scanner = new CallScanVisitor(hier, sym, inClass, inMethod, callees);
        startNode.accept(scanner, null);
    }

    // Compute which methods have side effects
    private void computeSideEffects() {
        // A method has side effects if:
        // 1. It contains a PrintStatement
        // 2. It contains a FieldAssignmentStatement
        // 3. It contains an ArrayAssignmentStatement (might be writing to a field array)
        // 4. It calls a method that has side effects (computed iteratively)

        // First pass: mark methods with direct side effects
        for (Map.Entry<String, MethodDeclaration> e : methodDecls.entrySet()) {
            DirectSideEffectVisitor sv = new DirectSideEffectVisitor();
            e.getValue().accept(sv, null);
            if (sv.hasDirectSideEffect) {
                sideEffectMethods.add(e.getKey());
            }
        }

        // Check main too
        DirectSideEffectVisitor sv = new DirectSideEffectVisitor();
        if (mainClassNode != null) mainClassNode.accept(sv, null);
        if (sv.hasDirectSideEffect) sideEffectMethods.add(hier.mainClass + "#main");

        // Fixpoint: propagate side effects through calls
        boolean changed;
        do {
            changed = false;
            for (Map.Entry<String, MethodDeclaration> e : methodDecls.entrySet()) {
                String mk = e.getKey();
                if (sideEffectMethods.contains(mk)) continue;
                // Check if any called method has side effects
                CalleeCheckVisitor cv = new CalleeCheckVisitor(hier, sym, mk.split("#")[0], mk.split("#")[1], sideEffectMethods);
                e.getValue().accept(cv, null);
                if (cv.callsSideEffectMethod) {
                    sideEffectMethods.add(mk);
                    changed = true;
                }
            }
        } while (changed);
    }
}
```

