Now I need to write `CallGraphVisitor.java`. This one needs to scan method bodies for MessageSend calls.

The tricky part is that `MessageSend` has a `PrimaryExpression` as the receiver. To do CHA, I need to find the receiver's type.

```
MessageSend: PrimaryExpression "." Identifier "(" (ArgList)? ")"
PrimaryExpression.f0 is NodeChoice among:
  IntegerLiteral | TrueLiteral | FalseLiteral | Identifier | ThisExpression | ArrayAllocationExpression | AllocationExpression | NotExpression
```

For receiver type:
- `Identifier`: look up var type in current scope
- `ThisExpression`: currentClass
- `AllocationExpression`: the class being allocated (n.f1.f0.tokenImage)
- Others: can't have methods → return null

```java
import visitor.*;
import syntaxtree.*;
import java.util.*;

public class CallGraphVisitor extends GJDepthFirst<Void, String[]> {
    // String[] argu = {currentClass, currentMethod}

    private ClassHierarchyVisitor hier;
    private SymbolTableVisitor sym;

    // All MethodDeclaration nodes indexed by "cls#mth"
    public final Map<String, MethodDeclaration> allMethods = new LinkedHashMap<>();
    public MainClass mainClassNode;

    // Reachable method keys
    public final Set<String> reachable = new LinkedHashSet<>();

    // Methods that MIGHT have side effects
    public final Set<String> sideEffects = new LinkedHashSet<>();

    public CallGraphVisitor(ClassHierarchyVisitor h, SymbolTableVisitor s) { hier=h; sym=s; }

    //--------------------------------------------------
    // Phase 1: Index all method declarations
    //--------------------------------------------------
    @Override public Void visit(Goal n, String[] a) {
        n.f0.accept(this,a); n.f1.accept(this,a); return null;
    }
    @Override public Void visit(MainClass n, String[] a) {
        mainClassNode = n; return null;
    }
    @Override public Void visit(TypeDeclaration n, String[] a) { n.f0.accept(this,a); return null; }
    @Override public Void visit(ClassDeclaration n, String[] a) {
        String cls = n.f1.f0.tokenImage;
        n.f4.accept(this, new String[]{cls, null});
        return null;
    }
    @Override public Void visit(ClassExtendsDeclaration n, String[] a) {
        String cls = n.f1.f0.tokenImage;
        n.f6.accept(this, new String[]{cls, null});
        return null;
    }
    @Override public Void visit(MethodDeclaration n, String[] a) {
        String cls = a[0];
        String mth = n.f2.f0.tokenImage;
        allMethods.put(cls+"#"+mth, n);
        return null;
    }

    //--------------------------------------------------
    // Phase 2: Compute reachability via BFS
    //--------------------------------------------------
    public void computeReachability() {
        // First determine direct side effects
        computeSideEffects();

        Queue<String> wl = new LinkedList<>();
        String mainKey = hier.mainClass + "#main";
        reachable.add(mainKey);
        wl.add(mainKey);
        while (!wl.isEmpty()) {
            String mk = wl.poll();
            for (String callee : calleesOf(mk)) {
                if (reachable.add(callee)) wl.add(callee);
            }
        }
    }

    private Set<String> calleesOf(String methodKey) {
        Set<String> res = new LinkedHashSet<>();
        String cls = methodKey.split("#")[0];
        String mth = methodKey.split("#")[1];
        Node body;
        if (mth.equals("main") && methodKey.startsWith(hier.mainClass+"#")) {
            body = mainClassNode;
        } else {
            body = allMethods.get(methodKey);
            if (body == null) return res;
        }
        // Use a scanner visitor to find all MessageSend nodes
        CallScanVisitor scanner = new CallScanVisitor(cls, mth);
        body.accept(scanner, null);
        return scanner.callees;
    }

    private class CallScanVisitor extends GJDepthFirst<Void, Void> {
        String cls, mth;
        Set<String> callees = new LinkedHashSet<>();
        CallScanVisitor(String cls, String mth) { this.cls=cls; this.mth=mth; }

        @Override public Void visit(MessageSend n, Void a) {
            // Determine receiver type
            String recvType = receiverType(n.f0, cls, mth);
            String methodName = n.f2.f0.tokenImage;
            callees.addAll(hier.chaResolve(recvType, methodName));
            n.f4.accept(this, a); // scan args too (for nested calls - but in TACoJava args are Identifiers, so no nested calls)
            return null;
        }
    }

    //--------------------------------------------------
    // Side effect computation
    //--------------------------------------------------
    private void computeSideEffects() {
        // Mark methods with direct side effects (println, field writes, array writes)
        for (Map.Entry<String, MethodDeclaration> e : allMethods.entrySet()) {
            if (hasDirectSideEffect(e.getValue())) sideEffects.add(e.getKey());
        }
        // Check main
        if (mainClassNode != null && hasDirectSideEffect(mainClassNode))
            sideEffects.add(hier.mainClass + "#main");

        // Propagate: if m calls n and n has side effects, then m has side effects
        boolean changed;
        do {
            changed = false;
            for (Map.Entry<String, MethodDeclaration> e : allMethods.entrySet()) {
                String mk = e.getKey();
                if (sideEffects.contains(mk)) continue;
                String cls = mk.split("#")[0], mth = mk.split("#")[1];
                CallScanVisitor sc = new CallScanVisitor(cls, mth);
                e.getValue().accept(sc, null);
                for (String callee : sc.callees) {
                    if (sideEffects.contains(callee)) {
                        sideEffects.add(mk); changed = true; break;
                    }
                }
            }
        } while (changed);
    }

    private boolean hasDirectSideEffect(Node n) {
        DirectSEVisitor sv = new DirectSEVisitor();
        n.accept(sv, null);
        return sv.hasSE;
    }

    private class DirectSEVisitor extends GJDepthFirst<Void, Void> {
        boolean hasSE = false;
        @Override public Void visit(PrintStatement n, Void a)          { hasSE=true; return null; }
        @Override public Void visit(FieldAssignmentStatement n, Void a){ hasSE=true; return null; }
        @Override public Void visit(ArrayAssignmentStatement n, Void a){ hasSE=true; return null; }
    }

    //--------------------------------------------------
    // Helper: determine declared type of a PrimaryExpression's result
    //--------------------------------------------------
    public String receiverType(PrimaryExpression pe, String cls, String mth) {
        Node choice = pe.f0.choice;
        if (choice instanceof Identifier)
            return sym.varType(cls, mth, ((Identifier)choice).f0.tokenImage);
        if (choice instanceof ThisExpression)
            return cls;
        if (choice instanceof AllocationExpression)
            return ((AllocationExpression)choice).f1.f0.tokenImage;
        return null; // literal or other - won't have methods
    }

    /** Returns true if calling methodKey as a VoidMessageSend can be elided */
    public boolean isPure(String methodKey) {
        return !sideEffects.contains(methodKey);
    }
}
