void markDeadAssignments(MethodDeclaration md, String cls, String mth) {
    // Find forced vars
    Set<String> forcedVars = findForcedVars(md, cls, mth);

    // Mark dead assignments
    if (md.f8.present()) {
        for (Enumeration<Node> e = md.f8.elements(); e.hasMoreElements();) {
            Node stmtNode = e.nextElement();
            // Recursively check each statement
            checkDeadAssignments(stmtNode, forcedVars);
        }
    }
}

void checkDeadAssignments(Node stmtNode, Set<String> forcedVars) {
    Node ch = ((Statement)stmtNode).f0.choice;
    if (ch instanceof AssignmentStatement) {
        AssignmentStatement a = (AssignmentStatement)ch;
        String lhs = a.f0.f0.tokenImage;
        CpValue rhsVal = assignRhsCpValue.get(a);
        boolean noSideEffect = !exprHasSideEffect(a.f2);
        if (rhsVal != null && rhsVal.isConst() && !forcedVars.contains(lhs) && noSideEffect) {
            deadAssigns.add(a);
        }
    } else if (ch instanceof Block) {
        if (((Block)ch).f1.present()) {
            for (Enumeration<Node> e = ((Block)ch).f1.elements(); e.hasMoreElements();) {
                checkDeadAssignments(e.nextElement(), forcedVars);
            }
        }
    } else if (ch instanceof IfStatement) {
        IfStatement is = (IfStatement)ch;
        if (!ifFolded.containsKey(is)) {
            checkDeadAssignments(is.f4, forcedVars);
            checkDeadAssignments(is.f6, forcedVars);
        } else if (ifFolded.get(is)) {
            checkDeadAssignments(is.f4, forcedVars);
        } else {
            checkDeadAssignments(is.f6, forcedVars);
        }
    } else if (ch instanceof WhileStatement) {
        WhileStatement ws = (WhileStatement)ch;
        if (!deadWhile.contains(ws)) {
            checkDeadAssignments(ws.f4, forcedVars);
        }
    } else if (ch instanceof ForStatement) {
        ForStatement fs = (ForStatement)ch;
        checkDeadAssignments(fs.f12, forcedVars);
    }
}
