void emitExpr(Expression e) {
    Node choice = e.f0.choice;
    if (choice instanceof CompareExpression) {
        CompareExpression ce = (CompareExpression)choice;
        emitConstOrId(ce.f0);
        print(" < ");
        emitConstOrId(ce.f2);
    } else if (choice instanceof PlusExpression) {
        PlusExpression pe = (PlusExpression)choice;
        emitConstOrId(pe.f0);
        print(" + ");
        emitConstOrId(pe.f2);
    }
    // ... etc.
}

void emitConstOrId(Identifier id) {
    CpValue cv = cp.cpValues.get(id);
    if (cv != null && cv.isConst()) {
        print(cv.toLiteral());
    } else {
        print(id.f0.tokenImage);
    }
}
