import visitor.*;
import syntaxtree.*;
import java.util.*;

public class SymbolTableVisitor extends GJDepthFirst<String, Void> {
    // class -> field -> type
    public Map<String, Map<String, String>> classFields = new LinkedHashMap<>();
    // "class#method" -> param/local -> type
    public Map<String, Map<String, String>> methodVars = new LinkedHashMap<>();
    // "class#method" -> ordered list of param names
    public Map<String, List<String>> methodParams = new LinkedHashMap<>();
    // "class#method" -> return type
    public Map<String, String> methodReturnType = new LinkedHashMap<>();

    private String currentClass;
    private String currentMethod;
    private boolean inParams;

    // Helper
    private String key(String cls, String method) { return cls + "#" + method; }

    @Override
    public String visit(MainClass n, Void argu) {
        currentClass = n.f1.accept(this, argu);
        classFields.put(currentClass, new LinkedHashMap<>());
        // main method
        currentMethod = "main";
        String mk = key(currentClass, "main");
        methodVars.put(mk, new LinkedHashMap<>());
        methodParams.put(mk, new ArrayList<>());
        methodReturnType.put(mk, "void");
        n.f14.accept(this, argu); // var declarations
        currentMethod = null;
        currentClass = null;
        return null;
    }

    @Override
    public String visit(ClassDeclaration n, Void argu) {
        currentClass = n.f1.accept(this, argu);
        classFields.put(currentClass, new LinkedHashMap<>());
        n.f3.accept(this, argu); // field var declarations
        n.f4.accept(this, argu); // method declarations
        currentClass = null;
        return null;
    }

    @Override
    public String visit(ClassExtendsDeclaration n, Void argu) {
        currentClass = n.f1.accept(this, argu);
        classFields.put(currentClass, new LinkedHashMap<>());
        n.f5.accept(this, argu); // field var declarations
        n.f6.accept(this, argu); // method declarations
        currentClass = null;
        return null;
    }

    @Override
    public String visit(VarDeclaration n, Void argu) {
        String type = n.f0.accept(this, argu); // Type
        String name = n.f1.accept(this, argu); // Identifier
        if (currentMethod != null) {
            // local variable
            String mk = key(currentClass, currentMethod);
            methodVars.get(mk).put(name, type);
        } else {
            // field
            classFields.get(currentClass).put(name, type);
        }
        return null;
    }

    @Override
    public String visit(MethodDeclaration n, Void argu) {
        String returnType = n.f1.accept(this, argu);
        currentMethod = n.f2.accept(this, argu);
        String mk = key(currentClass, currentMethod);
        methodVars.put(mk, new LinkedHashMap<>());
        methodParams.put(mk, new ArrayList<>());
        methodReturnType.put(mk, returnType);

        // params
        inParams = true;
        n.f4.accept(this, argu); // FormalParameterList (optional)
        inParams = false;

        // local vars
        n.f7.accept(this, argu); // VarDeclarations

        currentMethod = null;
        return null;
    }

    @Override
    public String visit(FormalParameter n, Void argu) {
        String type = n.f0.accept(this, argu);
        String name = n.f1.accept(this, argu);
        String mk = key(currentClass, currentMethod);
        methodVars.get(mk).put(name, type);
        methodParams.get(mk).add(name);
        return null;
    }

    @Override
    public String visit(FormalParameterRest n, Void argu) {
        return n.f1.accept(this, argu); // visits FormalParameter
    }

    // Type visitors - return the type as a string
