    private String currentMethod;

    public CallGraphVisitor(ClassHierarchyVisitor hierarchy, SymbolTableVisitor symTable) {
        this.hierarchy = hierarchy;
        this.symTable = symTable;
    }

    // Phase 1: index all methods
    public void indexMethods(Goal g) {
        // Visit goal to collect all method nodes
        indexGoal(g);
    }

    // ... (indexing pass)

    // Phase 2: compute reachability starting from main
    public void computeReachability(Goal g) {
        String mainKey = hierarchy.mainClass + "#main";
        worklist.add(mainKey);
        reachableMethods.add(mainKey);

        while (!worklist.isEmpty()) {
            String mk = worklist.poll();
            MethodDeclaration md = methodNodes.get(mk);
            if (md == null) continue; // main doesn't have a MethodDeclaration node
            // Visit the method to find callees
            // ... 
        }
    }

    // Resolve a call x.foo() where x has declared type T
    private Set<String> resolveCHA(String receiverType, String methodName) {
        Set<String> result = new LinkedHashSet<>();
        Set<String> candidates = hierarchy.getAllSubclasses(receiverType);
        candidates.add(receiverType);
        for (String c : candidates) {
            String defClass = hierarchy.findDefiningClass(c, methodName);
            if (defClass != null) {
                result.add(defClass + "#" + methodName);
            }
        }
        return result;
    }
}
