// CpValue.java
public class CpValue {
    public enum Kind { UNDEF, INT, BOOL, NAC }

    public final Kind kind;
    private final int intVal;
    private final boolean boolVal;

    private CpValue(Kind kind, int intVal, boolean boolVal) {
        this.kind = kind; this.intVal = intVal; this.boolVal = boolVal;
    }

    public static final CpValue UNDEF = new CpValue(Kind.UNDEF, 0, false);
    public static final CpValue NAC = new CpValue(Kind.NAC, 0, false);

    public static CpValue ofInt(int v) { return new CpValue(Kind.INT, v, false); }
    public static CpValue ofBool(boolean v) { return new CpValue(Kind.BOOL, 0, v); }

    public int getInt() { return intVal; }
    public boolean getBool() { return boolVal; }

    public boolean isConst() { return kind == Kind.INT || kind == Kind.BOOL; }

    public CpValue meet(CpValue other) {
        if (this.kind == Kind.UNDEF) return other;
        if (other.kind == Kind.UNDEF) return this;
        if (this.kind == Kind.NAC || other.kind == Kind.NAC) return NAC;
        if (this.equals(other)) return this;
        return NAC;
    }

    public String asLiteral() {
        if (kind == Kind.INT) {
            if (intVal < 0) return "-" + (-intVal);  // for TACoJava2 signed literals
            return String.valueOf(intVal);
        }
        if (kind == Kind.BOOL) return boolVal ? "true" : "false";
        throw new RuntimeException("Not a constant: " + this);
    }

    @Override
    public boolean equals(Object o) {
        if (!(o instanceof CpValue)) return false;
        CpValue c = (CpValue) o;
        if (kind != c.kind) return false;
        if (kind == Kind.INT) return intVal == c.intVal;
        if (kind == Kind.BOOL) return boolVal == c.boolVal;
        return true; // Both UNDEF or both NAC
    }

    @Override
    public int hashCode() {
        switch (kind) {
            case INT: return Integer.hashCode(intVal);
            case BOOL: return Boolean.hashCode(boolVal);
            default: return kind.hashCode();
        }
    }

    @Override
    public String toString() {
        switch (kind) {
            case UNDEF: return "UNDEF";
            case NAC: return "NAC";
            case INT: return "INT(" + intVal + ")";
            case BOOL: return "BOOL(" + boolVal + ")";
        }
        return "?";
    }
}
