import visitor.*;
import syntaxtree.*;
import java.util.*;

public class SymbolTableVisitor extends GJDepthFirst<String, Void> {
    // class -> field -> type string
    public Map<String, Map<String, String>> classFields = new LinkedHashMap<>();
    // "class#method" -> var -> type string (params + locals)
    public Map<String, Map<String, String>> methodScope = new LinkedHashMap<>();
    // "class#method" -> list of param names in order
    public Map<String, List<String>> methodParams = new LinkedHashMap<>();
    // "class#method" -> return type
    public Map<String, String> returnTypes = new LinkedHashMap<>();
    // "class#method" -> list of local var names in declaration order
    public Map<String, List<String>> methodLocals = new LinkedHashMap<>();

    private String currentClass;
    private String currentMethod;
    private boolean visitingParams;

    private String methodKey() { return currentClass + "#" + currentMethod; }

    @Override
    public String visit(MainClass n, Void argu) {
        currentClass = n.f1.f0.tokenImage;
        classFields.put(currentClass, new LinkedHashMap<>());
        currentMethod = "main";
        String mk = methodKey();
        methodScope.put(mk, new LinkedHashMap<>());
        methodParams.put(mk, new ArrayList<>());
        methodLocals.put(mk, new ArrayList<>());
        returnTypes.put(mk, "void");
        n.f14.accept(this, argu); // var declarations in main
        currentMethod = null;
        currentClass = null;
        return null;
    }

    @Override
    public String visit(ClassDeclaration n, Void argu) {
        currentClass = n.f1.f0.tokenImage;
        classFields.put(currentClass, new LinkedHashMap<>());
        n.f3.accept(this, argu); // field declarations
        currentMethod = null;
        n.f4.accept(this, argu); // method declarations
        currentClass = null;
        return null;
    }

    @Override
    public String visit(ClassExtendsDeclaration n, Void argu) {
        currentClass = n.f1.f0.tokenImage;
        classFields.put(currentClass, new LinkedHashMap<>());
        n.f5.accept(this, argu); // field declarations
        currentMethod = null;
        n.f6.accept(this, argu); // method declarations
        currentClass = null;
        return null;
    }

    @Override
    public String visit(VarDeclaration n, Void argu) {
        String type = typeString(n.f0);
        String name = n.f1.f0.tokenImage;
        if (currentMethod != null) {
            String mk = methodKey();
            methodScope.get(mk).put(name, type);
            methodLocals.get(mk).add(name);
        } else {
            classFields.get(currentClass).put(name, type);
        }
        return null;
    }

    @Override
    public String visit(MethodDeclaration n, Void argu) {
        String retType = typeString(n.f1);
        currentMethod = n.f2.f0.tokenImage;
        String mk = methodKey();
        methodScope.put(mk, new LinkedHashMap<>());
        methodParams.put(mk, new ArrayList<>());
        methodLocals.put(mk, new ArrayList<>());
        returnTypes.put(mk, retType);
        visitingParams = true;
        n.f4.accept(this, argu); // optional param list
        visitingParams = false;
        n.f7.accept(this, argu); // local var declarations
        currentMethod = null;
        return null;
    }

    @Override
    public String visit(FormalParameter n, Void argu) {
        String type = typeString(n.f0);
        String name = n.f1.f0.tokenImage;
        String mk = methodKey();
        methodScope.get(mk).put(name, type);
        methodParams.get(mk).add(name);
        return null;
    }

    @Override
    public String visit(FormalParameterRest n, Void argu) {
        return n.f1.accept(this, argu);
    }

    // Helper to get type string from Type node
    private String typeString(Type t) {
        Node inner = t.f0.choice;
        if (inner instanceof ArrayType) return "int[]";
        if (inner instanceof BooleanType) return "boolean";
        if (inner instanceof IntegerType) return "int";
        if (inner instanceof Identifier) return ((Identifier)inner).f0.tokenImage;
        return "unknown";
    }

    // Look up the declared type of a variable in a method scope (params + locals + fields)
    public String lookupVarType(String cls, String method, String varName) {
        String mk = cls + "#" + method;
        Map<String, String> scope = methodScope.get(mk);
        if (scope != null && scope.containsKey(varName)) return scope.get(varName);
        // Check fields (own class)
        Map<String, String> fields = classFields.get(cls);
        if (fields != null && fields.containsKey(varName)) return fields.get(varName);
        return null;
    }
}
