```java
public class ChaResolver {
    private ClassHierarchyVisitor hier;
    private SymbolTableVisitor sym;

    public Set<String> resolve(PrimaryExpression receiver, String receiverMethodName, String inClass, String inMethod) {
        String receiverType = getTypeOfPrimaryExpr(receiver, inClass, inMethod);
        return resolveCHA(receiverType, receiverMethodName);
    }

    private String getTypeOfPrimaryExpr(PrimaryExpression pe, String inClass, String inMethod) {
        Node choice = pe.f0.choice;
        if (choice instanceof Identifier) {
            String varName = ((Identifier)choice).f0.tokenImage;
            return sym.lookupVarType(inClass, inMethod, varName);
        }
        if (choice instanceof ThisExpression) return inClass;
        if (choice instanceof AllocationExpression) {
            return ((AllocationExpression)choice).f1.f0.tokenImage;
        }
        // IntegerLiteral, TrueLiteral, FalseLiteral, etc. → can't have methods
        return null;
    }

    private Set<String> resolveCHA(String type, String methodName) {
        Set<String> result = new LinkedHashSet<>();
        if (type == null) return result;
        Set<String> candidates = hier.getAllSubclasses(type);
        for (String c : candidates) {
            String defClass = hier.resolveMethod(c, methodName);
            if (defClass != null) result.add(defClass + "#" + methodName);
        }
        return result;
    }
}
