public class CpValue {
    public enum Kind { UNDEF, INT, BOOL, NAC }
    public final Kind kind;
    private final int intVal;
    private final boolean boolVal;

    private CpValue(Kind k, int i, boolean b) { kind=k; intVal=i; boolVal=b; }

    public static final CpValue UNDEF = new CpValue(Kind.UNDEF, 0, false);
    public static final CpValue NAC   = new CpValue(Kind.NAC,   0, false);
    public static CpValue ofInt(int v)     { return new CpValue(Kind.INT,  v, false); }
    public static CpValue ofBool(boolean v){ return new CpValue(Kind.BOOL, 0, v); }

    public int    getInt()  { return intVal;  }
    public boolean getBool(){ return boolVal; }
    public boolean isConst(){ return kind==Kind.INT || kind==Kind.BOOL; }
    public boolean isInt()  { return kind==Kind.INT;  }
    public boolean isBool() { return kind==Kind.BOOL; }

    public CpValue meet(CpValue o) {
        if (kind==Kind.UNDEF) return o;
        if (o.kind==Kind.UNDEF) return this;
        if (kind==Kind.NAC || o.kind==Kind.NAC) return NAC;
        if (equals(o)) return this;
        return NAC;
    }

    /** Format as TACoJava2 literal */
    public String toLiteral() {
        if (kind==Kind.INT)  return intVal < 0 ? "- " + (-intVal) : String.valueOf(intVal);
        if (kind==Kind.BOOL) return boolVal ? "true" : "false";
        throw new RuntimeException("CpValue.toLiteral() called on " + this);
    }

    @Override public boolean equals(Object o) {
        if (!(o instanceof CpValue)) return false;
        CpValue c = (CpValue) o;
        if (kind != c.kind) return false;
        if (kind==Kind.INT)  return intVal  == c.intVal;
        if (kind==Kind.BOOL) return boolVal == c.boolVal;
        return true;
    }
    @Override public int hashCode() {
        return kind==Kind.INT ? Integer.hashCode(intVal) :
               kind==Kind.BOOL ? Boolean.hashCode(boolVal) : kind.hashCode();
    }
    @Override public String toString() {
        return kind==Kind.INT ? "INT("+intVal+")" :
               kind==Kind.BOOL ? "BOOL("+boolVal+")" : kind.toString();
    }
}
