import visitor.*;
import syntaxtree.*;
import java.util.*;

public class ClassHierarchyVisitor extends GJDepthFirst<String, Void> {
    // Maps for the class hierarchy
    public final Map<String, String>         parentOf    = new LinkedHashMap<>();
    public final Map<String, Set<String>>    childrenOf  = new LinkedHashMap<>();
    public final Map<String, Set<String>>    methodsOf   = new LinkedHashMap<>();
    public final Set<String>                 allClasses  = new LinkedHashSet<>();
    public String mainClass;
    private String currentClass;

    @Override public String visit(Goal n, Void a) {
        n.f0.accept(this,a); n.f1.accept(this,a); return null;
    }
    @Override public String visit(MainClass n, Void a) {
        mainClass = n.f1.f0.tokenImage;
        register(mainClass, null);
        return null;
    }
    @Override public String visit(TypeDeclaration n, Void a) { return n.f0.accept(this,a); }
    @Override public String visit(ClassDeclaration n, Void a) {
        currentClass = n.f1.f0.tokenImage;
        register(currentClass, null);
        n.f4.accept(this,a);
        currentClass = null; return null;
    }
    @Override public String visit(ClassExtendsDeclaration n, Void a) {
        currentClass = n.f1.f0.tokenImage;
        String parent = n.f3.f0.tokenImage;
        register(currentClass, parent);
        childrenOf.computeIfAbsent(parent, k->new LinkedHashSet<>()).add(currentClass);
        n.f6.accept(this,a);
        currentClass = null; return null;
    }
    @Override public String visit(MethodDeclaration n, Void a) {
        if (currentClass != null) methodsOf.get(currentClass).add(n.f2.f0.tokenImage);
        return null;
    }

    private void register(String name, String parent) {
        allClasses.add(name);
        parentOf.put(name, parent);
        childrenOf.computeIfAbsent(name, k->new LinkedHashSet<>());
        methodsOf.computeIfAbsent(name, k->new LinkedHashSet<>());
    }

    /** All subclasses of cls, including cls itself */
    public Set<String> allSubclasses(String cls) {
        Set<String> res = new LinkedHashSet<>();
        Queue<String> q = new LinkedList<>();
        q.add(cls);
        while (!q.isEmpty()) {
            String c = q.poll();
            if (res.add(c)) {
                Set<String> ch = childrenOf.get(c);
                if (ch != null) q.addAll(ch);
            }
        }
        return res;
    }

    /** Walk up hierarchy to find which class first declares methodName */
    public String resolveMethod(String cls, String methodName) {
        for (String c = cls; c != null; c = parentOf.get(c)) {
            Set<String> ms = methodsOf.get(c);
            if (ms != null && ms.contains(methodName)) return c;
        }
        return null;
    }

    /** CHA: all possible dispatch targets for receiver type T calling method m */
    public Set<String> chaResolve(String receiverType, String methodName) {
        Set<String> res = new LinkedHashSet<>();
        if (receiverType == null) return res;
        for (String sub : allSubclasses(receiverType)) {
            String def = resolveMethod(sub, methodName);
            if (def != null) res.add(def + "#" + methodName);
        }
        return res;
    }
}
