import visitor.*;
import syntaxtree.*;
import java.util.*;

public class SymbolTableVisitor extends GJDepthFirst<String, Void> {
    // class → {field → type}
    public final Map<String, Map<String,String>> classFields = new LinkedHashMap<>();
    // "cls#mth" → {var → type}   (params + locals)
    public final Map<String, Map<String,String>> methodScope = new LinkedHashMap<>();
    // "cls#mth" → ordered list of param names
    public final Map<String, List<String>>       methodParams  = new LinkedHashMap<>();
    // "cls#mth" → return type string
    public final Map<String, String>             returnType    = new LinkedHashMap<>();

    private String currentClass, currentMethod;

    private String mk() { return currentClass + "#" + currentMethod; }

    @Override public String visit(MainClass n, Void a) {
        currentClass = n.f1.f0.tokenImage;
        classFields.put(currentClass, new LinkedHashMap<>());
        currentMethod = "main";
        methodScope.put(mk(), new LinkedHashMap<>());
        methodParams.put(mk(), new ArrayList<>());
        returnType.put(mk(), "void");
        n.f14.accept(this,a);   // VarDeclarations in main
        currentMethod = null; currentClass = null; return null;
    }
    @Override public String visit(ClassDeclaration n, Void a) {
        currentClass = n.f1.f0.tokenImage;
        classFields.put(currentClass, new LinkedHashMap<>());
        n.f3.accept(this,a);   // field VarDeclarations
        n.f4.accept(this,a);   // MethodDeclarations
        currentClass = null; return null;
    }
    @Override public String visit(ClassExtendsDeclaration n, Void a) {
        currentClass = n.f1.f0.tokenImage;
        classFields.put(currentClass, new LinkedHashMap<>());
        n.f5.accept(this,a);   // field VarDeclarations
        n.f6.accept(this,a);   // MethodDeclarations
        currentClass = null; return null;
    }
    @Override public String visit(VarDeclaration n, Void a) {
        String type = typeStr(n.f0);
        String name = n.f1.f0.tokenImage;
        if (currentMethod != null) methodScope.get(mk()).put(name, type);
        else                       classFields.get(currentClass).put(name, type);
        return null;
    }
    @Override public String visit(MethodDeclaration n, Void a) {
        currentMethod = n.f2.f0.tokenImage;
        methodScope.put(mk(), new LinkedHashMap<>());
        methodParams.put(mk(), new ArrayList<>());
        returnType.put(mk(), typeStr(n.f1));
        n.f4.accept(this,a);   // FormalParameterList (optional)
        n.f7.accept(this,a);   // VarDeclarations (locals)
        currentMethod = null; return null;
    }
    @Override public String visit(FormalParameter n, Void a) {
        String type = typeStr(n.f0);
        String name = n.f1.f0.tokenImage;
        methodScope.get(mk()).put(name, type);
        methodParams.get(mk()).add(name);
        return null;
    }
    @Override public String visit(FormalParameterRest n, Void a) {
        return n.f1.accept(this,a);
    }

    /** Return the declared type of var in class/method (params + locals + own fields) */
    public String varType(String cls, String method, String var) {
        Map<String,String> sc = methodScope.get(cls+"#"+method);
        if (sc != null && sc.containsKey(var)) return sc.get(var);
        Map<String,String> fi = classFields.get(cls);
        if (fi != null && fi.containsKey(var)) return fi.get(var);
        return null;
    }

    public static String typeStr(Type t) {
        Node ch = t.f0.choice;
        if (ch instanceof ArrayType)   return "int[]";
        if (ch instanceof BooleanType) return "boolean";
        if (ch instanceof IntegerType) return "int";
        if (ch instanceof Identifier)  return ((Identifier)ch).f0.tokenImage;
        return "?";
    }
}
