```java
public class ConstPropVisitor {
    final SymbolTableVisitor sym;
    final ClassHierarchyVisitor hier;

    // Results accessible by CodeGenVisitor
    // CP value at each Identifier USE node
    final IdentityHashMap<Identifier, CpValue> cpValues = new IdentityHashMap<>();
    // Whether an if's condition is always true/false (for elimination)
    final IdentityHashMap<IfStatement, Boolean> ifFolded = new IdentityHashMap<>(); // true=always-true, false=always-false
    // Whether a while's condition is always false (loop is dead)
    final IdentityHashSet<WhileStatement> deadWhile = Collections.newSetFromMap(new IdentityHashMap<>());
    // Dead assignments
    final IdentityHashSet<AssignmentStatement> deadAssigns = Collections.newSetFromMap(new IdentityHashMap<>());

    String currentClass, currentMethod;

    public ConstPropVisitor(SymbolTableVisitor sym, ClassHierarchyVisitor hier) {
        this.sym = sym; this.hier = hier;
    }

    public void analyze(Goal g) {
        // Analyze main class
        analyzeMain(g.f0);
        // Analyze all type declarations
        if (g.f1.present()) {
            for (Enumeration<Node> e = g.f1.elements(); e.hasMoreElements();) {
                Node n = e.nextElement();
                analyzeTypeDecl((TypeDeclaration) n);
            }
        }
    }

    void analyzeMain(MainClass n) {
        currentClass = n.f1.f0.tokenImage;
        currentMethod = "main";
        Map<String,CpValue> initState = initMethodState();
        analyzeVarDecls(n.f14, initState); // no-op: var decls don't change state
        analyzeStmtList(n.f15, initState);
        currentClass = currentMethod = null;
    }

    void analyzeTypeDecl(TypeDeclaration n) {
        Node choice = n.f0.choice;
        if (choice instanceof ClassDeclaration) analyzeClass((ClassDeclaration)choice);
        else analyzeClassExtends((ClassExtendsDeclaration)choice);
    }

    void analyzeClass(ClassDeclaration n) {
        currentClass = n.f1.f0.tokenImage;
        if (n.f4.present()) {
            for (Enumeration<Node> e = n.f4.elements(); e.hasMoreElements();)
                analyzeMethod((MethodDeclaration)e.nextElement());
        }
        currentClass = null;
    }

    void analyzeClassExtends(ClassExtendsDeclaration n) {
        currentClass = n.f1.f0.tokenImage;
        if (n.f6.present()) {
            for (Enumeration<Node> e = n.f6.elements(); e.hasMoreElements();)
                analyzeMethod((MethodDeclaration)e.nextElement());
        }
        currentClass = null;
    }

    void analyzeMethod(MethodDeclaration n) {
        currentMethod = n.f2.f0.tokenImage;
        Map<String,CpValue> state = initMethodState();
        analyzeStmtList(n.f8, state);
        // Record return value
        recordUse(n.f10, state);
        currentMethod = null;
    }

    Map<String,CpValue> initMethodState() {
        Map<String,CpValue> state = new HashMap<>();
        String mk = currentClass + "#" + currentMethod;
        List<String> params = sym.methodParams.getOrDefault(mk, Collections.emptyList());
        Map<String,String> scope = sym.methodScope.getOrDefault(mk, Collections.emptyMap());
        for (String p : params) state.put(p, CpValue.NAC);
        for (String v : scope.keySet()) if (!state.containsKey(v)) state.put(v, CpValue.UNDEF);
        return state;
    }

    Map<String,CpValue> analyzeStmtList(NodeListOptional stmts, Map<String,CpValue> inState) {
        Map<String,CpValue> state = new HashMap<>(inState);
        if (stmts.present()) {
            for (Enumeration<Node> e = stmts.elements(); e.hasMoreElements();)
                state = analyzeStmt((Statement) e.nextElement(), state);
        }
        return state;
    }

    Map<String,CpValue> analyzeStmt(Statement s, Map<String,CpValue> inState) {
        Node ch = s.f0.choice;
        if (ch instanceof Block) {
            return analyzeStmtList(((Block)ch).f1, inState);
        }
        if (ch instanceof AssignmentStatement) {
            return analyzeAssign((AssignmentStatement)ch, inState);
        }
        if (ch instanceof ArrayAssignmentStatement) {
            ArrayAssignmentStatement a = (ArrayAssignmentStatement)ch;
            // Uses: array name, index, value
            recordUse(a.f0, inState); // array (forced use, but we record)
            recordUse(a.f2, inState); // index
            recordUse(a.f5, inState); // value
            return inState;
        }
        if (ch instanceof FieldAssignmentStatement) {
            FieldAssignmentStatement f = (FieldAssignmentStatement)ch;
            recordUse(f.f0, inState); // object receiver
            recordUse(f.f4, inState); // value
            return inState;
        }
        if (ch instanceof IfStatement) {
            return analyzeIf((IfStatement)ch, inState);
        }
        if (ch instanceof WhileStatement) {
            return analyzeWhile((WhileStatement)ch, inState);
        }
        if (ch instanceof ForStatement) {
            return analyzeFor((ForStatement)ch, inState);
        }
        if (ch instanceof PrintStatement) {
            PrintStatement p = (PrintStatement)ch;
            recordUse(p.f2, inState);
            return inState;
        }
        return inState;
    }

    Map<String,CpValue> analyzeAssign(AssignmentStatement n, Map<String,CpValue> inState) {
        String lhs = n.f0.f0.tokenImage;
        CpValue rhs = evalExpr(n.f2, inState);

        Map<String,CpValue> outState = new HashMap<>(inState);
        CpValue prev = inState.getOrDefault(lhs, CpValue.UNDEF);
        outState.put(lhs, rhs); // Strong update for sequential statements

        // Record RHS uses
        recordExprUses(n.f2, inState);

        return outState;
    }

    Map<String,CpValue> analyzeIf(IfStatement n, Map<String,CpValue> inState) {
        String condVar = n.f2.f0.tokenImage;
        recordUse(n.f2, inState);
        CpValue cond = inState.getOrDefault(condVar, CpValue.UNDEF);

        if (cond.isBool()) {
            boolean val = cond.getBool();
            ifFolded.put(n, val);
            if (val) {
                return analyzeStmt((Statement)n.f4, inState);
            } else {
                return analyzeStmt((Statement)n.f6, inState);
            }
        } else {
            Map<String,CpValue> s1 = analyzeStmt((Statement)n.f4, inState);
            Map<String,CpValue> s2 = analyzeStmt((Statement)n.f6, inState);
            return meetStates(s1, s2);
        }
    }

    Map<String,CpValue> analyzeWhile(WhileStatement n, Map<String,CpValue> inState) {
        String condVar = n.f2.f0.tokenImage;
        CpValue cond = inState.getOrDefault(condVar, CpValue.UNDEF);

        if (cond.isBool() && !cond.getBool()) {
            // Condition is statically false, loop never executes
            deadWhile.add(n);
            recordUse(n.f2, inState);
            return inState;
        }

        // Iterate loop body to fixpoint
        Map<String,CpValue> loopState = new HashMap<>(inState);
        Map<String,CpValue> prevState;
        do {
            prevState = new HashMap<>(loopState);
            recordUse(n.f2, loopState); // condition use each iteration
            Map<String,CpValue> afterBody = analyzeStmt((Statement)n.f4, loopState);
            loopState = meetStates(loopState, afterBody);
        } while (!loopState.equals(prevState));

        // Record condition use at fixpoint state
        recordUse(n.f2, loopState);
        return loopState;
    }

    Map<String,CpValue> analyzeFor(ForStatement n, Map<String,CpValue> inState) {
        // for (id1 = expr1; expr2; id2 = expr3) body
        String id1 = n.f2.f0.tokenImage;

        // Record uses in init expression, then update state
        recordExprUses(n.f4, inState);
        CpValue initVal = evalExpr(n.f4, inState);
        Map<String,CpValue> afterInit = new HashMap<>(inState);
        afterInit.put(id1, initVal);

        // Check condition
        CpValue condVal = evalExpr(n.f6, afterInit);
        recordExprUses(n.f6, afterInit);

        if (condVal.isBool() && !condVal.getBool()) {
            // Loop never executes
            return afterInit;
        }

