    CpValue evalExpr(Expression e, Map<String,CpValue> state) {
        Node choice = e.f0.choice;
        if (choice instanceof CompareExpression) {
            CompareExpression ce = (CompareExpression)choice;
            CpValue left = lookup(ce.f0, state);
            CpValue right = lookup(ce.f2, state);
            if (left.isInt() && right.isInt()) return CpValue.ofBool(left.getInt() < right.getInt());
            return CpValue.NAC;
        }
        if (choice instanceof PlusExpression) {
            PlusExpression pe = (PlusExpression)choice;
            CpValue left = lookup(pe.f0, state);
            CpValue right = lookup(pe.f2, state);
            if (left.isInt() && right.isInt()) return CpValue.ofInt(left.getInt() + right.getInt());
            return CpValue.NAC;
        }
        if (choice instanceof MinusExpression) {
            MinusExpression me = (MinusExpression)choice;
            CpValue left = lookup(me.f0, state);
            CpValue right = lookup(me.f2, state);
            if (left.isInt() && right.isInt()) return CpValue.ofInt(left.getInt() - right.getInt());
            return CpValue.NAC;
        }
        if (choice instanceof TimesExpression) {
            TimesExpression te = (TimesExpression)choice;
            CpValue left = lookup(te.f0, state);
            CpValue right = lookup(te.f2, state);
            if (left.isInt() && right.isInt()) return CpValue.ofInt(left.getInt() * right.getInt());
            return CpValue.NAC;
        }
        if (choice instanceof ArrayLookup) return CpValue.NAC;
        if (choice instanceof ArrayLength) return CpValue.NAC;
        if (choice instanceof MessageSend) return CpValue.NAC;
        if (choice instanceof FieldRead) return CpValue.NAC;
        if (choice instanceof PrimaryExpression) return evalPrimary((PrimaryExpression)choice, state);
        return CpValue.NAC;
    }

    CpValue evalPrimary(PrimaryExpression pe, Map<String,CpValue> state) {
        Node choice = pe.f0.choice;
        if (choice instanceof IntegerLiteral) {
            return CpValue.ofInt(Integer.parseInt(((IntegerLiteral)choice).f0.tokenImage));
        }
        if (choice instanceof TrueLiteral) return CpValue.ofBool(true);
        if (choice instanceof FalseLiteral) return CpValue.ofBool(false);
        if (choice instanceof Identifier) return lookup((Identifier)choice, state);
        if (choice instanceof NotExpression) {
            CpValue v = lookup(((NotExpression)choice).f1, state);
            if (v.isBool()) return CpValue.ofBool(!v.getBool());
            return CpValue.NAC;
        }
        return CpValue.NAC; // this, new, etc.
    }

    CpValue lookup(Identifier id, Map<String,CpValue> state) {
        String name = id.f0.tokenImage;
        return state.getOrDefault(name, CpValue.UNDEF);
    }

    void recordUse(Identifier id, Map<String,CpValue> state) {
        cpValues.put(id, lookup(id, state));
    }

    void recordExprUses(Expression e, Map<String,CpValue> state) {
        Node choice = e.f0.choice;
        if (choice instanceof CompareExpression) {
            recordUse(((CompareExpression)choice).f0, state);
            recordUse(((CompareExpression)choice).f2, state);
        } else if (choice instanceof PlusExpression) {
            recordUse(((PlusExpression)choice).f0, state);
            recordUse(((PlusExpression)choice).f2, state);
        } else if (choice instanceof MinusExpression) {
            recordUse(((MinusExpression)choice).f0, state);
            recordUse(((MinusExpression)choice).f2, state);
        } else if (choice instanceof TimesExpression) {
            recordUse(((TimesExpression)choice).f0, state);
            recordUse(((TimesExpression)choice).f2, state);
        } else if (choice instanceof ArrayLookup) {
            recordUse(((ArrayLookup)choice).f0, state); // array
            recordUse(((ArrayLookup)choice).f2, state); // index
        } else if (choice instanceof ArrayLength) {
            recordUse(((ArrayLength)choice).f0, state);
        } else if (choice instanceof FieldRead) {
            recordUse(((FieldRead)choice).f0, state);
        } else if (choice instanceof MessageSend) {
            MessageSend ms = (MessageSend)choice;
            // Record receiver if it's an Identifier
            Node recvChoice = ms.f0.f0.choice;
            if (recvChoice instanceof Identifier) recordUse((Identifier)recvChoice, state);
            // Record args
            if (ms.f4.present()) {
                ArgList al = (ArgList) ms.f4.node;
                recordUse(al.f0, state);
                if (al.f1.present()) {
                    for (Enumeration<Node> en = al.f1.elements(); en.hasMoreElements();) {
                        recordUse(((ArgRest)en.nextElement()).f1, state);
                    }
                }
            }
        } else if (choice instanceof PrimaryExpression) {
            PrimaryExpression pe = (PrimaryExpression)choice;
            Node pChoice = pe.f0.choice;
            if (pChoice instanceof Identifier) recordUse((Identifier)pChoice, state);
            else if (pChoice instanceof NotExpression) recordUse(((NotExpression)pChoice).f1, state);
            else if (pChoice instanceof ArrayAllocationExpression) 
                recordUse(((ArrayAllocationExpression)pChoice).f3, state);
        }
    }

    Map<String,CpValue> meetStates(Map<String,CpValue> s1, Map<String,CpValue> s2) {
        Map<String,CpValue> res = new HashMap<>();
        Set<String> vars = new HashSet<>(s1.keySet());
        vars.addAll(s2.keySet());
        for (String v : vars)
            res.put(v, s1.getOrDefault(v, CpValue.UNDEF).meet(s2.getOrDefault(v, CpValue.UNDEF)));
        return res;
    }
}
