    if (ch instanceof AssignmentStatement) {
        AssignmentStatement a = (AssignmentStatement)ch;
        String lhs = a.f0.f0.tokenImage;
        CpValue rhsVal = assignRhsCpValue.get(a);
        boolean noSideEffect = !exprHasSideEffect(a.f2);
