            deadAssigns.add(a);
        }
    } else if (ch instanceof Block) {
        if (((Block)ch).f1.present()) {
            for (Enumeration<Node> e = ((Block)ch).f1.elements(); e.hasMoreElements();) {
                checkDeadAssignments(e.nextElement(), forcedVars);
            }
        }
    } else if (ch instanceof IfStatement) {
        IfStatement is = (IfStatement)ch;
        if (!ifFolded.containsKey(is)) {
            checkDeadAssignments(is.f4, forcedVars);
            checkDeadAssignments(is.f6, forcedVars);
        } else if (ifFolded.get(is)) {
            checkDeadAssignments(is.f4, forcedVars);
        } else {
            checkDeadAssignments(is.f6, forcedVars);
        }
    } else if (ch instanceof WhileStatement) {
        WhileStatement ws = (WhileStatement)ch;
        if (!deadWhile.contains(ws)) {
            checkDeadAssignments(ws.f4, forcedVars);
        }
    } else if (ch instanceof ForStatement) {
        ForStatement fs = (ForStatement)ch;
        checkDeadAssignments(fs.f12, forcedVars);
    }
}
