package visitor;

import syntaxtree.*;
import java.util.*;

/**
 * Pass 3: Call Graph construction via Class Hierarchy Analysis (CHA).
 *
 * CHA resolution rule for a call  x.foo(args)  where x has declared type T:
 *   - Include T.foo if T declares foo (or inherits it)
 *   - Include C.foo for every subclass C of T (transitively) that declares foo
 *
 * Algorithm:
 *   1. Seed worklist with ("main-class", "main")
 *   2. For each reachable method, scan its body for MessageSend nodes
 *   3. Resolve each call via CHA -> add newly found callees to worklist
 *   4. Repeat until fixpoint
 *
 * After visiting, reachable(className, methodName) tells you whether
 * a method is live.
 *
 * Usage:
 *   CallGraphVisitor cg = new CallGraphVisitor(ch, st, mainClassName);
 *   goal.accept(cg, null);       // two-phase: first index, then propagate
 */
public class CallGraphVisitor extends GJDepthFirst<Object, Object> {

    private final ClassHierarchyVisitor ch;
    private final SymbolTableVisitor    st;
    private final String                mainClassName;

    // ---------------------------------------------------------------
    // Phase 1 index: className -> methodName -> MethodDeclaration node
    // Lets us look up the AST body of any method during propagation.
    // ---------------------------------------------------------------
    private final Map<String, Map<String, MethodDeclaration>> methodIndex
        = new LinkedHashMap<>();

    // ---------------------------------------------------------------
    // Reachable set: pairs (className, methodName)
    // ---------------------------------------------------------------
    private final Set<String> reachableSet = new LinkedHashSet<>(); // "Class::method"

    // ---------------------------------------------------------------
    // Constructor
    // ---------------------------------------------------------------
    public CallGraphVisitor(ClassHierarchyVisitor ch,
                            SymbolTableVisitor st,
                            String mainClassName) {
        this.ch            = ch;
        this.st            = st;
        this.mainClassName = mainClassName;
    }

    // ---------------------------------------------------------------
    // Public query API
    // ---------------------------------------------------------------

    /** Is (className, methodName) reachable from main? */
    public boolean reachable(String className, String methodName) {
        return reachableSet.contains(key(className, methodName));
    }

    /** Full reachable set as "ClassName::methodName" strings. */
    public Set<String> reachableSet() {
        return Collections.unmodifiableSet(reachableSet);
    }

    // ---------------------------------------------------------------
    // Phase 1: Index all MethodDeclaration nodes
    // We override Goal so we run indexing first, then propagate.
    // ---------------------------------------------------------------

    /**
     * f0 -> MainClass()
     * f1 -> ( TypeDeclaration() )*
     * f2 -> <EOF>
     */
    @Override
    public Object visit(Goal n, Object argu) {
        // Phase 1: walk the whole tree to build the method index
        n.f0.accept(this, "INDEX");
        n.f1.accept(this, "INDEX");

        // Phase 2: worklist propagation from main
        propagate();
        return null;
    }

    // ---- Phase 1 indexing visitors --------------------------------

    @Override
    public Object visit(ClassDeclaration n, Object argu) {
        if (!"INDEX".equals(argu)) return null;
        String className = n.f1.f0.tokenImage;
        n.f4.accept(this, className);   // visit MethodDeclarations with class name
        return null;
    }

    @Override
    public Object visit(ClassExtendsDeclaration n, Object argu) {
        if (!"INDEX".equals(argu)) return null;
        String className = n.f1.f0.tokenImage;
        n.f6.accept(this, className);
        return null;
    }

    @Override
    public Object visit(MainClass n, Object argu) {
        // main class has no indexable MethodDeclarations
        return null;
    }

    /**
     * Index this method under its enclosing class.
     * argu = class name (String) during indexing phase.
     *
     * f0 -> "public"
     * f1 -> Type()
     * f2 -> Identifier()   <- method name
     * ...
     */
    @Override
    public Object visit(MethodDeclaration n, Object argu) {
        if (argu instanceof String && !argu.equals("INDEX")) {
            // argu is a class name — index the node
            String className  = (String) argu;
            String methodName = n.f2.f0.tokenImage;
            methodIndex.computeIfAbsent(className, k -> new LinkedHashMap<>())
                       .put(methodName, n);
        }
        return null;
    }

    // ---------------------------------------------------------------
    // Phase 2: worklist propagation
    // ---------------------------------------------------------------

    private void propagate() {
        Deque<String[]> worklist = new ArrayDeque<>();

        // Seed with main (main class body is not a MethodDeclaration,
        // so we handle it specially via a sentinel)
        worklist.add(new String[]{mainClassName, "main"});

        while (!worklist.isEmpty()) {
            String[] entry  = worklist.poll();
            String cls      = entry[0];
            String method   = entry[1];
            String k        = key(cls, method);

            if (!reachableSet.add(k)) continue;   // already processed

            // Collect all MessageSend nodes in this method's body
            List<MessageSend> calls = new ArrayList<>();
            if ("main".equals(method)) {
                // Scan main class body statements
                // We need the Goal node's MainClass — re-traverse lazily
                // Instead, we stored the Goal: use a helper scan visitor
                collectCallsInMain(calls);
            } else {
                MethodDeclaration md = getMethod(cls, method);
                if (md != null) {
                    MessageSendCollector collector = new MessageSendCollector();
                    md.accept(collector, calls);
                }
            }

            // CHA-resolve each call site
            for (MessageSend ms : calls) {
                String methodName = ms.f2.f0.tokenImage;  // called method name

                // Determine declared type of receiver
                String receiverType = resolveReceiverType(ms, cls, method);
                if (receiverType == null) continue;       // can't resolve — skip

                // CHA: receiverType itself + all subclasses
                Set<String> candidates = new LinkedHashSet<>();
                candidates.add(receiverType);
                candidates.addAll(ch.allSubclasses(receiverType));

                for (String candidate : candidates) {
                    // Find the class in candidate's hierarchy that declares methodName
                    String declaringCls = ch.declaringClass(candidate, methodName);
                    if (declaringCls != null) {
                        String ck = key(declaringCls, methodName);
                        if (!reachableSet.contains(ck)) {
                            worklist.add(new String[]{declaringCls, methodName});
                        }
                    }
                }
            }
        }
    }

    // ---------------------------------------------------------------
    // Receiver type resolution
    // ---------------------------------------------------------------

    /**
     * Given a MessageSend, figure out the declared type of the receiver.
     *
     * In TACoJava, MessageSend is:
     *   PrimaryExpression "." Identifier "(" ArgList? ")"
     *
     * PrimaryExpression can be:
     *   IntegerLiteral | TrueLiteral | FalseLiteral | Identifier
     *   | ThisExpression | ArrayAllocationExpression
     *   | AllocationExpression | NotExpression
     *
     * For CHA we only need the DECLARED type of the receiver object.
     *   - Identifier  -> look up in symbol table
     *   - ThisExpression -> type is the enclosing class
     *   - AllocationExpression (new Foo()) -> type is Foo
     *   - Others -> unknown (return null, skip conservatively)
     */
    private String resolveReceiverType(MessageSend ms,
                                       String enclosingClass,
                                       String enclosingMethod) {
        PrimaryExpression pe = ms.f0;
        Node choice = pe.f0.choice;

        if (choice instanceof Identifier) {
            String varName = ((Identifier) choice).f0.tokenImage;
            return st.typeOf(enclosingClass, enclosingMethod, varName);
        }
        if (choice instanceof ThisExpression) {
            return enclosingClass;
        }
        if (choice instanceof AllocationExpression) {
            // new Foo() -> type is Foo
            return ((AllocationExpression) choice).f1.f0.tokenImage;
        }
        // IntegerLiteral, TrueLiteral, FalseLiteral, ArrayAlloc, NotExpression
        // — these can't have user-defined methods called on them in valid programs
        return null;
    }

    // ---------------------------------------------------------------
    // Helper: collect MessageSend nodes from main class body
    // We do this lazily: store the MainClass node on first visit.
    // ---------------------------------------------------------------
    private MainClass mainClassNode = null;

    // Override Goal's MainClass child visit to capture the node
    // We override visit(MainClass) only during INDEX phase
    // (Goal.visit routes here during indexing)
    // We re-assign mainClassNode here:
    private void collectCallsInMain(List<MessageSend> out) {
        if (mainClassNode == null) return;
        MessageSendCollector collector = new MessageSendCollector();
        mainClassNode.f15.accept(collector, out);   // f15 = ( Statement() )*
    }

    // We need to capture mainClassNode during indexing.
    // Override Goal to do both indexing and capture:
    // (We already override Goal above, but MainClass is visited with "INDEX" argu)
    // Let's capture it in visit(MainClass):
    //   (the INDEX guard at the top of visit(MainClass) returns null early —
    //    we fix that here by capturing before the guard)
    // Override is already present — we update it to capture:
    // NOTE: Java doesn't allow two @Override of same method.
    // We handle this by NOT early-returning in visit(MainClass).
    // So the visit(MainClass) above should capture:
    //   -> see corrected visit(MainClass) below (replaces the one above).

    // ---------------------------------------------------------------
    // Utility
    // ---------------------------------------------------------------

    private MethodDeclaration getMethod(String className, String methodName) {
        // First try the class itself, then walk up hierarchy
        String cur = className;
        while (cur != null) {
            Map<String, MethodDeclaration> m = methodIndex.get(cur);
            if (m != null && m.containsKey(methodName)) return m.get(methodName);
            cur = ch.parentOf(cur);
        }
        return null;
    }

    private static String key(String cls, String method) {
        return cls + "::" + method;
    }

    // ---------------------------------------------------------------
    // Inner class: collects all MessageSend nodes under a subtree
    // ---------------------------------------------------------------
    private static class MessageSendCollector extends GJDepthFirst<Object, Object> {

        @SuppressWarnings("unchecked")
        @Override
        public Object visit(MessageSend n, Object argu) {
            ((List<MessageSend>) argu).add(n);
            // Also recurse into arguments in case of nested calls
            // (TACoJava args are Identifiers so no nesting, but be safe)
            n.f4.accept(this, argu);
            return null;
        }
    }
}

