package visitor;

import syntaxtree.*;
import java.util.*;

/**
 * Pass 4: Intraprocedural Conditional Constant Propagation.
 *
 * For each reachable method (per the call graph), iterates dataflow
 * equations to a fixpoint, then records:
 *   - cpValue(class, method, var)  : CPValue for each variable
 *   - constOfExpr(node)            : CPValue for each Expression node
 *
 * Key design choices:
 *   - Context-insensitive: parameters are initialised to NAC (we don't
 *     know what callers pass).
 *   - Fields are always NAC (aliasing — any call could mutate them).
 *   - MessageSend return value is NAC.
 *   - Conditional CP: if the condition of an if/while is a known
 *     constant we analyse only the live branch.
 *   - Iteration: we loop each method's statements until the state
 *     map stops changing (monotone, so guaranteed to terminate).
 *
 * After visiting the Goal node, use:
 *   getVarValue(cls, method, var)  -> CPValue
 *   getExprValue(node)             -> CPValue  (for Expression nodes)
 *   getIdValue(cls, method, name)  -> CPValue  (for identifier uses)
 */
public class ConstPropVisitor extends GJDepthFirst<Object, Object> {

    private final ClassHierarchyVisitor ch;
    private final SymbolTableVisitor    st;
    private final CallGraphVisitor      cg;

    // ---------------------------------------------------------------
    // Results: per-method variable states at fixpoint
    // className -> methodName -> varName -> CPValue
    // ---------------------------------------------------------------
    private final Map<String, Map<String, Map<String, CPValue>>> methodStates
            = new LinkedHashMap<>();

    // ---------------------------------------------------------------
    // Per-expression results (keyed by node identity)
    // ---------------------------------------------------------------
    private final Map<Node, CPValue> exprValues = new IdentityHashMap<>();

    // ---------------------------------------------------------------
    // Context during analysis of one method
    // ---------------------------------------------------------------
    private String              currentClass;
    private String              currentMethod;
    private Map<String, CPValue> state;   // mutable during iteration

    // ---------------------------------------------------------------
    // Index of method AST nodes (populated in Phase 1)
    // ---------------------------------------------------------------
    private final Map<String, Map<String, MethodDeclaration>> methodIndex
            = new LinkedHashMap<>();
    private MainClass mainClassNode;

    // ---------------------------------------------------------------
    // Constructor
    // ---------------------------------------------------------------
    public ConstPropVisitor(ClassHierarchyVisitor ch,
                            SymbolTableVisitor    st,
                            CallGraphVisitor      cg) {
        this.ch = ch;
        this.st = st;
        this.cg = cg;
    }

    // ---------------------------------------------------------------
    // Public query API
    // ---------------------------------------------------------------

    /** CPValue of variable varName at the end of (cls, method). */
    public CPValue getVarValue(String cls, String method, String varName) {
        Map<String, Map<String, CPValue>> m1 = methodStates.get(cls);
        if (m1 == null) return CPValue.NAC;
        Map<String, CPValue> m2 = m1.get(method);
        if (m2 == null) return CPValue.NAC;
        CPValue v = m2.get(varName);
        return v == null ? CPValue.UNDEF : v;
    }

    /**
     * CPValue for an identifier used inside (cls, method).
     * Fields are always NAC; locals/params look up the state map.
     */
    public CPValue getIdValue(String cls, String method, String name) {
        // If it's a field of any enclosing class -> NAC
        String cur = cls;
        while (cur != null) {
            if (st.fieldsOf(cur).containsKey(name)) return CPValue.NAC;
            cur = ch.parentOf(cur);
        }
        return getVarValue(cls, method, name);
    }

    /** CPValue stored for an Expression AST node. */
    public CPValue getExprValue(Node n) {
        CPValue v = exprValues.get(n);
        return v == null ? CPValue.NAC : v;
    }

    // ---------------------------------------------------------------
    // Phase 1 + Phase 2 entry via Goal
    // ---------------------------------------------------------------

    @Override
    public Object visit(Goal n, Object argu) {
        // Phase 1: index method nodes
        n.f0.accept(this, "INDEX");
        n.f1.accept(this, "INDEX");

        // Phase 2: analyse each reachable method
        for (String reachKey : cg.reachableSet()) {
            String[] parts  = reachKey.split("::");
            String   cls    = parts[0];
            String   method = parts[1];
            analyseMethod(cls, method);
        }
        return null;
    }

    // ---------------------------------------------------------------
    // Phase 1: indexing
    // ---------------------------------------------------------------

    @Override
    public Object visit(MainClass n, Object argu) {
        mainClassNode = n;
        return null;
    }

    @Override
    public Object visit(ClassDeclaration n, Object argu) {
        if (!"INDEX".equals(argu)) return null;
        String cls = n.f1.f0.tokenImage;
        n.f4.accept(this, cls);
        return null;
    }

    @Override
    public Object visit(ClassExtendsDeclaration n, Object argu) {
        if (!"INDEX".equals(argu)) return null;
        String cls = n.f1.f0.tokenImage;
        n.f6.accept(this, cls);
        return null;
    }

    @Override
    public Object visit(MethodDeclaration n, Object argu) {
        if (!(argu instanceof String)) return null;
        String cls    = (String) argu;
        String method = n.f2.f0.tokenImage;
        methodIndex.computeIfAbsent(cls, k -> new LinkedHashMap<>()).put(method, n);
        return null;
    }

    // ---------------------------------------------------------------
    // Phase 2: per-method fixpoint iteration
    // ---------------------------------------------------------------

    private void analyseMethod(String cls, String method) {
        currentClass  = cls;
        currentMethod = method;

        // Initialise state
        state = new LinkedHashMap<>();

        if ("main".equals(method)) {
            // main has no parameters; locals start UNDEF
            initLocals(cls, method);
            iterateStatements(mainClassNode.f15, cls, method);
        } else {
            MethodDeclaration md = lookupMethod(cls, method);
            if (md == null) return;

            // Parameters -> NAC (context-insensitive)
            for (String param : st.paramsOf(cls, method)) {
                state.put(param, CPValue.NAC);
            }
            // Locals -> UNDEF
            initLocals(cls, method);

            // Iterate until fixpoint
            iterateStatements(md.f8, cls, method);
        }

        // Store final state
        methodStates.computeIfAbsent(cls, k -> new LinkedHashMap<>())
                    .put(method, new LinkedHashMap<>(state));

        currentClass  = null;
        currentMethod = null;
        state         = null;
    }

    /**
     * Iterate over the statement list repeatedly until the state
     * stops changing. Needed for loops (while/for).
     */
    private void iterateStatements(NodeListOptional stmts,
                                   String cls, String method) {
        boolean changed = true;
        while (changed) {
            Map<String, CPValue> before = new LinkedHashMap<>(state);
            analyseStatementList(stmts);
            changed = !state.equals(before);
        }
    }

    private void initLocals(String cls, String method) {
        for (String local : st.localsOf(cls, method).keySet()) {
            if (!state.containsKey(local))    // don't overwrite params
                state.put(local, CPValue.UNDEF);
        }
    }

    // ---------------------------------------------------------------
    // Statement analysis
    // ---------------------------------------------------------------

    private void analyseStatementList(NodeListOptional stmts) {
        if (!stmts.present()) return;
        for (Enumeration<Node> e = stmts.elements(); e.hasMoreElements();) {
            Node s = e.nextElement();
            s.accept(this, null);
        }
    }

    /**
     * f0 -> Identifier()
     * f1 -> "="
     * f2 -> Expression()
     * f3 -> ";"
     */
    @Override
    public Object visit(AssignmentStatement n, Object argu) {
        String   lhs = n.f0.f0.tokenImage;
        CPValue  rhs = evalExpression(n.f2);
        exprValues.put(n.f2, rhs);

        // Fields are always NAC (don't track them in local state)
        if (isField(lhs)) return null;

        // Meet new value into current state (monotone)
        CPValue old = state.getOrDefault(lhs, CPValue.UNDEF);
        state.put(lhs, CPValue.meet(old, rhs));
        return null;
    }

    /**
     * ArrayAssignmentStatement: no constant info flows from this
     * f0 -> Identifier() "[" Identifier() "]" "=" Identifier() ";"
     */
    @Override
    public Object visit(ArrayAssignmentStatement n, Object argu) {
        // Nothing to propagate; array contents are always NAC
        return null;
    }

    /**
     * FieldAssignmentStatement: could mutate fields of any object
     * f0 -> Identifier() "." Identifier() "=" Identifier() ";"
     */
    @Override
    public Object visit(FieldAssignmentStatement n, Object argu) {
        // Fields are always NAC — no state update needed
        return null;
    }

    /**
     * if (cond) S1 else S2
     *
     * f0 -> "if"
     * f1 -> "("
     * f2 -> Identifier()   <- condition
     * f3 -> ")"
     * f4 -> Statement()    <- then branch
     * f5 -> "else"
     * f6 -> Statement()    <- else branch
     */
    @Override
    public Object visit(IfStatement n, Object argu) {
        String  condName = n.f2.f0.tokenImage;
        CPValue condVal  = lookupVar(condName);

        if (condVal.isTrue()) {
            // Only then branch is reachable
            n.f4.accept(this, argu);
        } else if (condVal.isFalse()) {
            // Only else branch is reachable
            n.f6.accept(this, argu);
        } else {
            // Both branches reachable — analyse each on a copy, then meet
            Map<String, CPValue> snapBefore = new LinkedHashMap<>(state);

            n.f4.accept(this, argu);
            Map<String, CPValue> afterThen = new LinkedHashMap<>(state);

            state = new LinkedHashMap<>(snapBefore);
            n.f6.accept(this, argu);
            Map<String, CPValue> afterElse = new LinkedHashMap<>(state);

            // Join (meet) states from both branches
            state = meetMaps(afterThen, afterElse);
        }
        return null;
    }

    /**
     * while (cond) S
     *
     * f0 -> "while"
     * f1 -> "("
     * f2 -> Identifier()
     * f3 -> ")"
     * f4 -> Statement()
     */
    @Override
    public Object visit(WhileStatement n, Object argu) {
        String  condName = n.f2.f0.tokenImage;
        CPValue condVal  = lookupVar(condName);

        if (condVal.isFalse()) {
            // Loop body is unreachable — skip entirely
            return null;
        }

        // Analyse body; outer iterateStatements loop handles fixpoint
        // For a single while, iterate body until state stabilises
        boolean changed = true;
        while (changed) {
            Map<String, CPValue> before = new LinkedHashMap<>(state);
            n.f4.accept(this, argu);
            changed = !state.equals(before);
        }
        return null;
    }

    /**
     * for (id = init; cond; id = step) body
     *
     * f0 -> "for"
     * f1 -> "("
     * f2 -> Identifier()    <- loop var
     * f3 -> "="
     * f4 -> Expression()    <- init
     * f5 -> ";"
     * f6 -> Expression()    <- condition (evaluated each iteration)
     * f7 -> ";"
     * f8 -> Identifier()    <- loop var (for increment)
     * f9 -> "="
     * f10 -> Expression()   <- step
     * f11 -> ")"
     * f12 -> Statement()    <- body
     */
    @Override
    public Object visit(ForStatement n, Object argu) {
        String  loopVar  = n.f2.f0.tokenImage;
        CPValue initVal  = evalExpression(n.f4);
        exprValues.put(n.f4, initVal);

        if (!isField(loopVar)) {
            CPValue old = state.getOrDefault(loopVar, CPValue.UNDEF);
            state.put(loopVar, CPValue.meet(old, initVal));
        }

        // Condition — evaluated before each iteration; conservatively NAC
        // after the first because loop var gets reassigned
        // We evaluate cond once to check for statically false loops
        CPValue condVal = evalExpression(n.f6);
        exprValues.put(n.f6, condVal);

        if (condVal.isFalse()) {
            // Body never executes
            return null;
        }

        // General case: iterate body + step until fixpoint
        boolean changed = true;
        while (changed) {
            Map<String, CPValue> before = new LinkedHashMap<>(state);

            // Body
            n.f12.accept(this, argu);

            // Step assignment: loopVar = stepExpr
            String  stepVar  = n.f8.f0.tokenImage;
            CPValue stepVal  = evalExpression(n.f10);
            exprValues.put(n.f10, stepVal);
            if (!isField(stepVar)) {
                CPValue old = state.getOrDefault(stepVar, CPValue.UNDEF);
                state.put(stepVar, CPValue.meet(old, stepVal));
            }

            changed = !state.equals(before);
        }
        return null;
    }

    /**
     * System.out.println(id);
     *
     * f0 -> "System.out.println"
     * f1 -> "("
     * f2 -> Identifier()
     * f3 -> ")"
     * f4 -> ";"
     */
    @Override
    public Object visit(PrintStatement n, Object argu) {
        // No state change; just record the value for the code gen pass
        String  varName = n.f2.f0.tokenImage;
        CPValue val     = lookupVar(varName);
        exprValues.put(n, val);   // code gen can query this
        return null;
    }

    /** Block: just recurse into statements */
    @Override
    public Object visit(Block n, Object argu) {
        analyseStatementList(n.f1);
        return null;
    }

    // ---------------------------------------------------------------
    // Expression evaluation  (returns a CPValue)
    // ---------------------------------------------------------------

    /**
     * Evaluate an Expression node under the current state.
     * Records result in exprValues and returns it.
     */
    private CPValue evalExpression(Expression n) {
        Node choice = n.f0.choice;
        CPValue result;

        if (choice instanceof CompareExpression) {
            result = evalCompare((CompareExpression) choice);
        } else if (choice instanceof PlusExpression) {
            result = evalPlus((PlusExpression) choice);
        } else if (choice instanceof MinusExpression) {
            result = evalMinus((MinusExpression) choice);
        } else if (choice instanceof TimesExpression) {
            result = evalTimes((TimesExpression) choice);
        } else if (choice instanceof ArrayLookup) {
            result = CPValue.NAC;   // array contents unknown
        } else if (choice instanceof ArrayLength) {
            result = CPValue.NAC;   // array length unknown
        } else if (choice instanceof MessageSend) {
            result = CPValue.NAC;   // return value unknown
        } else if (choice instanceof FieldRead) {
            result = CPValue.NAC;   // field value unknown
        } else if (choice instanceof PrimaryExpression) {
            result = evalPrimary((PrimaryExpression) choice);
        } else {
            result = CPValue.NAC;
        }

        exprValues.put(n, result);
        return result;
    }

    private CPValue evalCompare(CompareExpression n) {
        CPValue left  = lookupVar(n.f0.f0.tokenImage);
        CPValue right = lookupVar(n.f2.f0.tokenImage);
        if (left.isInt() && right.isInt())
            return CPValue.ofBool(left.intValue() < right.intValue());
        return CPValue.NAC;
    }

    private CPValue evalPlus(PlusExpression n) {
        CPValue left  = lookupVar(n.f0.f0.tokenImage);
        CPValue right = lookupVar(n.f2.f0.tokenImage);
        if (left.isInt() && right.isInt())
            return CPValue.ofInt(left.intValue() + right.intValue());
        return CPValue.NAC;
    }

    private CPValue evalMinus(MinusExpression n) {
        CPValue left  = lookupVar(n.f0.f0.tokenImage);
        CPValue right = lookupVar(n.f2.f0.tokenImage);
        if (left.isInt() && right.isInt())
            return CPValue.ofInt(left.intValue() - right.intValue());
        return CPValue.NAC;
    }

    private CPValue evalTimes(TimesExpression n) {
        CPValue left  = lookupVar(n.f0.f0.tokenImage);
        CPValue right = lookupVar(n.f2.f0.tokenImage);
        if (left.isInt() && right.isInt())
            return CPValue.ofInt(left.intValue() * right.intValue());
        return CPValue.NAC;
    }

    private CPValue evalPrimary(PrimaryExpression n) {
        Node choice = n.f0.choice;
        if (choice instanceof IntegerLiteral) {
            String tok = ((IntegerLiteral) choice).f0.tokenImage;
            return CPValue.ofInt(Integer.parseInt(tok));
        }
        if (choice instanceof TrueLiteral)  return CPValue.TRUE_VAL;
        if (choice instanceof FalseLiteral) return CPValue.FALSE_VAL;
        if (choice instanceof Identifier) {
            return lookupVar(((Identifier) choice).f0.tokenImage);
        }
        if (choice instanceof NotExpression) {
            String inner = ((NotExpression) choice).f1.f0.tokenImage;
            CPValue v = lookupVar(inner);
            if (v.isBool()) return CPValue.ofBool(!v.boolValue());
            return CPValue.NAC;
        }
        // ThisExpression, AllocationExpression, ArrayAllocationExpression
        return CPValue.NAC;
    }

    // ---------------------------------------------------------------
    // Helpers
    // ---------------------------------------------------------------

    /**
     * Look up a variable name: fields -> NAC, locals/params -> state map.
     */
    private CPValue lookupVar(String name) {
        if (isField(name)) return CPValue.NAC;
        CPValue v = state.get(name);
        return v == null ? CPValue.UNDEF : v;
    }

    /** Is this name a field of the current class (or any ancestor)? */
    private boolean isField(String name) {
        String cur = currentClass;
        while (cur != null) {
            if (st.fieldsOf(cur).containsKey(name)) return true;
            cur = ch.parentOf(cur);
        }
        return false;
    }

    /**
     * Component-wise meet of two state maps.
     * Variables present in only one map are treated as UNDEF in the other.
     */
    private static Map<String, CPValue> meetMaps(Map<String, CPValue> a,
                                                  Map<String, CPValue> b) {
        Map<String, CPValue> result = new LinkedHashMap<>();
        Set<String> allKeys = new LinkedHashSet<>(a.keySet());
        allKeys.addAll(b.keySet());
        for (String k : allKeys) {
            CPValue va = a.getOrDefault(k, CPValue.UNDEF);
            CPValue vb = b.getOrDefault(k, CPValue.UNDEF);
            result.put(k, CPValue.meet(va, vb));
        }
        return result;
    }

    /** Look up a MethodDeclaration by (class, method), walking hierarchy. */
    private MethodDeclaration lookupMethod(String className, String methodName) {
        String cur = className;
        while (cur != null) {
            Map<String, MethodDeclaration> m = methodIndex.get(cur);
            if (m != null && m.containsKey(methodName)) return m.get(methodName);
            cur = ch.parentOf(cur);
        }
        return null;
    }
}

