{"language": "java", "code": "package visitor;

import syntaxtree.*;
import java.util.*;

/**
 * Pass 5: Liveness Analysis + Dead Code Marking.
 *
 * Identifies and marks three categories of dead code:
 *
 *  (A) Dead assignments:  x = expr;
 *      Dropped when x is not live after this point AND expr has no
 *      side effects (i.e. is not a MessageSend).
 *
 *  (B) Unreachable branches:
 *        if (true)  S1 else S2  -> keep only S1
 *        if (false) S1 else S2  -> keep only S2
 *        while (false) { S }    -> drop entirely
 *
 *  (C) Dead methods: any method not in the call graph's reachable set.
 *
 * Liveness is computed BACKWARDS per method (standard backward dataflow).
 * A variable x is live at a point if it is used before being overwritten
 * on some path from that point forward.
 *
 * After visiting Goal, query:
 *   isDead(node)           -> true if this Statement node should be dropped
 *   isDeadMethod(cls, m)   -> true if this method should be dropped
 *   getDeadBranch(ifNode)  -> "then", "else", or null (neither is dead)
 *   isDeadWhile(whileNode) -> true if while body is unreachable
 */
public class DeadCodeVisitor extends GJDepthFirst<Object, Object> {

    private final ClassHierarchyVisitor ch;
    private final SymbolTableVisitor    st;
    private final CallGraphVisitor      cg;
    private final ConstPropVisitor      cp;

    // ---------------------------------------------------------------
    // Results
    // ---------------------------------------------------------------

    /** AssignmentStatement nodes marked as dead (drop entirely). */
    private final Set<Node> deadStatements = Collections.newSetFromMap(
            new IdentityHashMap<>());

    /** IfStatement -> "then" means else is live, "else" means then is live.
     *  Absent = both branches live (emit normal if/else). */
    private final Map<Node, String> deadIfBranch = new IdentityHashMap<>();

    /** WhileStatement nodes whose body is unreachable. */
    private final Set<Node> deadWhiles = Collections.newSetFromMap(
            new IdentityHashMap<>());

    /** (className, methodName) pairs that are dead. */
    private final Set<String> deadMethods = new LinkedHashSet<>();

    // ---------------------------------------------------------------
    // Method AST index (built in Phase 1)
    // ---------------------------------------------------------------
    private final Map<String, Map<String, MethodDeclaration>> methodIndex
            = new LinkedHashMap<>();
    private MainClass mainClassNode;

    // ---------------------------------------------------------------
    // Constructor
    // ---------------------------------------------------------------
    public DeadCodeVisitor(ClassHierarchyVisitor ch,
                           SymbolTableVisitor    st,
                           CallGraphVisitor      cg,
                           ConstPropVisitor      cp) {
        this.ch = ch;
        this.st = st;
        this.cg = cg;
        this.cp = cp;
    }

    // ---------------------------------------------------------------
    // Public query API
    // ---------------------------------------------------------------

    /** Should this AssignmentStatement be dropped? */
    public boolean isDead(Node n) {
        return deadStatements.contains(n);
    }

    /**
     * For an IfStatement, returns:
     *   "then"  -> the then-branch is dead; emit only the else-branch
     *   "else"  -> the else-branch is dead; emit only the then-branch
     *   null    -> both branches live; emit normal if/else
     */
    public String getDeadBranch(IfStatement n) {
        return deadIfBranch.get(n);
    }

    /** Should this WhileStatement's body be dropped (condition always false)? */
    public boolean isDeadWhile(WhileStatement n) {
        return deadWhiles.contains(n);
    }

    /** Should this method be omitted from the output? */
    public boolean isDeadMethod(String className, String methodName) {
        return deadMethods.contains(className + "::" + methodName);
    }

    // ---------------------------------------------------------------
    // Entry point
    // ---------------------------------------------------------------

    @Override
    public Object visit(Goal n, Object argu) {
        // Phase 1: index method nodes
        n.f0.accept(this, "INDEX");
        n.f1.accept(this, "INDEX");

        // Phase 2: mark dead methods
        markDeadMethods();

        // Phase 3: liveness + dead-code marking per reachable method
        for (String key : cg.reachableSet()) {
            String[] parts  = key.split("::");
            String   cls    = parts[0];
            String   method = parts[1];
            analyseMethod(cls, method);
        }
        return null;
    }

    // ---------------------------------------------------------------
    // Phase 1: indexing
    // ---------------------------------------------------------------

    @Override
    public Object visit(MainClass n, Object argu) {
        mainClassNode = n;
        return null;
    }

    @Override
    public Object visit(ClassDeclaration n, Object argu) {
        if (!"INDEX".equals(argu)) return null;
        String cls = n.f1.f0.tokenImage;
        n.f4.accept(this, cls);
        return null;
    }

    @Override
    public Object visit(ClassExtendsDeclaration n, Object argu) {
        if (!"INDEX".equals(argu)) return null;
        String cls = n.f1.f0.tokenImage;
        n.f6.accept(this, cls);
        return null;
    }

    @Override
    public Object visit(MethodDeclaration n, Object argu) {
        if (!(argu instanceof String)) return null;
        String cls    = (String) argu;
        String method = n.f2.f0.tokenImage;
        methodIndex.computeIfAbsent(cls, k -> new LinkedHashMap<>())
                   .put(method, n);
        return null;
    }

    // ---------------------------------------------------------------
    // Phase 2: mark dead methods
    // ---------------------------------------------------------------

    private void markDeadMethods() {
        // Every method in the program that is NOT in cg.reachableSet() is dead
        for (String cls : ch.classNames()) {
            for (String method : ch.methodsOf(cls)) {
                if (!cg.reachable(cls, method)) {
                    deadMethods.add(cls + "::" + method);
                }
            }
        }
    }

    // ---------------------------------------------------------------
    // Phase 3: per-method liveness + dead-assignment marking
    // ---------------------------------------------------------------

    private void analyseMethod(String cls, String method) {
        List<Node> stmts = getStatementList(cls, method);
        if (stmts == null) return;

        // Compute the live-out set for each statement via backward scan
        // liveOut[i] = variables live immediately AFTER stmts[i]
        // We iterate until fixpoint (needed for loops)
        int n = stmts.size();
        @SuppressWarnings("unchecked")
        Set<String>[] liveOut = new Set[n];
        for (int i = 0; i < n; i++)
            liveOut[i] = new LinkedHashSet<>();

        // The return variable is live at method exit
        Set<String> exitLive = new LinkedHashSet<>();
        if (!"main".equals(method)) {
            MethodDeclaration md = lookupMethod(cls, method);
            if (md != null) {
                String retVar = md.f10.f0.tokenImage;
                exitLive.add(retVar);
            }
        }

        boolean changed = true;
        while (changed) {
            changed = false;
            // Backward pass
            Set<String> live = new LinkedHashSet<>(exitLive);
            for (int i = n - 1; i >= 0; i--) {
                Set<String> newLiveOut = new LinkedHashSet<>(live);
                if (!newLiveOut.equals(liveOut[i])) {
                    liveOut[i] = newLiveOut;
                    changed = true;
                }
                // Update live = liveIn[i] = (liveOut[i] - defs[i]) ∪ uses[i]
                live = liveIn(stmts.get(i), new LinkedHashSet<>(live), cls, method);
            }
        }

        // Now mark dead assignments
        for (int i = 0; i < n; i++) {
            Node stmt = stmts.get(i);
            markDeadStatement(stmt, liveOut[i], cls, method);
        }
    }

    /**
     * Compute liveIn for a single statement given its liveOut set.
     * liveIn = (liveOut - defs(stmt)) ∪ uses(stmt)
     *
     * We also mark unreachable if/while branches here (they don't
     * affect liveness but are natural to detect in the same pass).
     */
    private Set<String> liveIn(Node stmt, Set<String> liveOut,
                                String cls, String method) {
        if (stmt instanceof Statement) {
            Node inner = ((Statement) stmt).f0.choice;
            return liveInInner(inner, liveOut, cls, method);
        }
        return liveInInner(stmt, liveOut, cls, method);
    }

    private Set<String> liveInInner(Node stmt, Set<String> liveOut,
                                     String cls, String method) {
        Set<String> live = new LinkedHashSet<>(liveOut);

        if (stmt instanceof AssignmentStatement) {
            AssignmentStatement as = (AssignmentStatement) stmt;
            String lhs = as.f0.f0.tokenImage;
            // def: remove lhs (if it's not a field)
            live.remove(lhs);
            // use: add variables used in rhs
            live.addAll(usesOfExpression(as.f2));

        } else if (stmt instanceof ArrayAssignmentStatement) {
            ArrayAssignmentStatement aas = (ArrayAssignmentStatement) stmt;
            // arr[idx] = val  -> uses: arr, idx, val
            live.add(aas.f0.f0.tokenImage);  // array
            live.add(aas.f2.f0.tokenImage);  // index
            live.add(aas.f5.f0.tokenImage);  // value

        } else if (stmt instanceof FieldAssignmentStatement) {
            FieldAssignmentStatement fas = (FieldAssignmentStatement) stmt;
            // obj.field = val -> uses: obj, val
            live.add(fas.f0.f0.tokenImage);  // object
            live.add(fas.f4.f0.tokenImage);  // value

        } else if (stmt instanceof PrintStatement) {
            PrintStatement ps = (PrintStatement) stmt;
            live.add(ps.f2.f0.tokenImage);

        } else if (stmt instanceof IfStatement) {
            IfStatement is = (IfStatement) stmt;
            String condName = is.f2.f0.tokenImage;
            CPValue condVal = cp.getVarValue(cls, method, condName);

            if (condVal.isTrue()) {
                // only then branch executes
                live = liveIn(is.f4, new LinkedHashSet<>(liveOut), cls, method);
                live.add(condName);
            } else if (condVal.isFalse()) {
                // only else branch executes
                live = liveIn(is.f6, new LinkedHashSet<>(liveOut), cls, method);
                live.add(condName);
            } else {
                // both branches
                Set<String> liveThen = liveIn(is.f4,
                        new LinkedHashSet<>(liveOut), cls, method);
                Set<String> liveElse = liveIn(is.f6,
                        new LinkedHashSet<>(liveOut), cls, method);
                live = union(liveThen, liveElse);
                live.add(condName);
            }

        } else if (stmt instanceof WhileStatement) {
            WhileStatement ws = (WhileStatement) stmt;
            String condName = ws.f2.f0.tokenImage;
            CPValue condVal = cp.getVarValue(cls, method, condName);

            live.add(condName);
            if (!condVal.isFalse()) {
                // Body may execute — conservatively add body's uses
                Set<String> bodyLive = liveIn(ws.f4,
                        new LinkedHashSet<>(liveOut), cls, method);
                live.addAll(bodyLive);
            }

        } else if (stmt instanceof ForStatement) {
            ForStatement fs = (ForStatement) stmt;
            // uses: init expr vars, cond expr vars, step expr vars, body vars
            live.addAll(usesOfExpression(fs.f4));   // init
            live.addAll(usesOfExpression(fs.f6));   // cond
            live.addAll(usesOfExpression(fs.f10));  // step
            live.remove(fs.f2.f0.tokenImage);       // loop var is defined by init
            live.remove(fs.f8.f0.tokenImage);       // loop var redefined by step
            Set<String> bodyLive = liveIn(fs.f12,
                    new LinkedHashSet<>(liveOut), cls, method);
            live.addAll(bodyLive);

        } else if (stmt instanceof Block) {
            Block b = (Block) stmt;
            List<Node> inner = nodeListToList(b.f1);
            // Backward through block's statements
            Set<String> cur = new LinkedHashSet<>(liveOut);
            for (int i = inner.size() - 1; i >= 0; i--) {
                cur = liveIn(inner.get(i), cur, cls, method);
            }
            live = cur;
        }
        // MessageSend-as-statement: treat all args as uses (handled
        // in the expression uses helper if it appears in an assignment)

        return live;
    }

    /**
     * Mark a single statement as dead if appropriate.
     */
    private void markDeadStatement(Node stmt, Set<String> liveOut,
                                    String cls, String method) {
        Node inner = stmt;
        if (stmt instanceof Statement) inner = ((Statement) stmt).f0.choice;

        if (inner instanceof AssignmentStatement) {
            AssignmentStatement as = (AssignmentStatement) inner;
            String lhs = as.f0.f0.tokenImage;

            // Dead if: lhs is not live after this point
            //      AND rhs has no side effects
            if (!liveOut.contains(lhs) && !hasSideEffects(as.f2)) {
                deadStatements.add(stmt);
            }

        } else if (inner instanceof IfStatement) {
            IfStatement is = (IfStatement) inner;
            String  condName = is.f2.f0.tokenImage;
            CPValue condVal  = cp.getVarValue(cls, method, condName);

            if (condVal.isTrue())  deadIfBranch.put(stmt, "then");  // else is dead
            if (condVal.isFalse()) deadIfBranch.put(stmt, "else");  // then is dead

        } else if (inner instanceof WhileStatement) {
            WhileStatement ws = (WhileStatement) inner;
            String  condName = ws.f2.f0.tokenImage;
            CPValue condVal  = cp.getVarValue(cls, method, condName);

            if (condVal.isFalse()) deadWhiles.add(stmt);
        }
        // Other statement types (print, array assign, field assign)
        // always have observable side effects — never mark dead.
    }

    // ---------------------------------------------------------------
    // Side-effect check
    // ---------------------------------------------------------------

    /**
     * An expression has side effects iff it contains a MessageSend.
     * (new, array operations etc. have no side effects on program state
     *  visible to the caller in TACoJava.)
     */
    private boolean hasSideEffects(Expression expr) {
        Node choice = expr.f0.choice;
        return choice instanceof MessageSend;
    }

    // ---------------------------------------------------------------
    // Uses of an expression (variables READ by evaluating it)
    // ---------------------------------------------------------------

    private Set<String> usesOfExpression(Expression expr) {
        Set<String> uses = new LinkedHashSet<>();
        Node choice = expr.f0.choice;

        if (choice instanceof CompareExpression) {
            CompareExpression ce = (CompareExpression) choice;
            uses.add(ce.f0.f0.tokenImage);
            uses.add(ce.f2.f0.tokenImage);
        } else if (choice instanceof PlusExpression) {
            PlusExpression pe = (PlusExpression) choice;
            uses.add(pe.f0.f0.tokenImage);
            uses.add(pe.f2.f0.tokenImage);
        } else if (choice instanceof MinusExpression) {
            MinusExpression me = (MinusExpression) choice;
            uses.add(me.f0.f0.tokenImage);
            uses.add(me.f2.f0.tokenImage);
        } else if (choice instanceof TimesExpression) {
            TimesExpression te = (TimesExpression) choice;
            uses.add(te.f0.f0.tokenImage);
            uses.add(te.f2.f0.tokenImage);
        } else if (choice instanceof ArrayLookup) {
            ArrayLookup al = (ArrayLookup) choice;
            uses.add(al.f0.f0.tokenImage);  // array
            uses.add(al.f2.f0.tokenImage);  // index
        } else if (choice instanceof ArrayLength) {
            uses.add(((ArrayLength) choice).f0.f0.tokenImage);
        } else if (choice instanceof MessageSend) {
            MessageSend ms = (MessageSend) choice;
            // receiver (if Identifier)
            Node recv = ms.f0.f0.choice;
            if (recv instanceof Identifier)
                uses.add(((Identifier) recv).f0.tokenImage);
            // all arguments
            if (ms.f4.present()) {
                ArgList al = (ArgList) ms.f4.node;
                uses.add(al.f0.f0.tokenImage);  // first arg
                // rest args
                if (al.f1.present()) {
                    for (Enumeration<Node> e = al.f1.elements();
                         e.hasMoreElements();) {
                        ArgRest ar = (ArgRest) e.nextElement();
                        uses.add(ar.f1.f0.tokenImage);
                    }
                }
            }
        } else if (choice instanceof FieldRead) {
            uses.add(((FieldRead) choice).f0.f0.tokenImage);
        } else if (choice instanceof PrimaryExpression) {
            Node prim = ((PrimaryExpression) choice).f0.choice;
            if (prim instanceof Identifier)
                uses.add(((Identifier) prim).f0.tokenImage);
            else if (prim instanceof NotExpression)
                uses.add(((NotExpression) prim).f1.f0.tokenImage);
            else if (prim instanceof ArrayAllocationExpression)
                uses.add(((ArrayAllocationExpression) prim).f3.f0.tokenImage);
        }
        return uses;
    }

    // ---------------------------------------------------------------
    // Helpers
    // ---------------------------------------------------------------

    /** Get the ordered list of Statement nodes for a method body. */
    private List<Node> getStatementList(String cls, String method) {
        NodeListOptional nlo;
        if ("main".equals(method) && mainClassNode != null) {
            nlo = mainClassNode.f15;
        } else {
            MethodDeclaration md = lookupMethod(cls, method);
            if (md == null) return null;
            nlo = md.f8;
        }
        return nodeListToList(nlo);
    }

    private List<Node> nodeListToList(NodeListOptional nlo) {
        List<Node> list = new ArrayList<>();
        if (nlo.present()) {
            for (Enumeration<Node> e = nlo.elements(); e.hasMoreElements();)
                list.add(e.nextElement());
        }
        return list;
    }

    private MethodDeclaration lookupMethod(String cls, String method) {
        String cur = cls;
        while (cur != null) {
            Map<String, MethodDeclaration> m = methodIndex.get(cur);
            if (m != null && m.containsKey(method)) return m.get(method);
            cur = ch.parentOf(cur);
        }
        return null;
    }

    private static Set<String> union(Set<String> a, Set<String> b) {
        Set<String> r = new LinkedHashSet<>(a);
        r.addAll(b);
        return r;
    }
}
