package visitor;

import syntaxtree.*;
import java.util.*;

/**
 * Pass 6: Code Generation — pretty-prints the optimized AST as TACoJava2.
 *
 * Key responsibilities:
 *  (1) Substitute constants for identifiers wherever TACoJava2 allows
 *      a ConstOrId (arguments, return, print arg, arithmetic operands,
 *      array index, field assignment RHS).
 *  (2) Elide dead AssignmentStatements.
 *  (3) Replace dead if/while branches with only the live branch.
 *  (4) Drop dead MethodDeclarations entirely.
 *  (5) Emit VoidMessageSendStatement for standalone calls
 *      (TACoJava2 addition — assignments whose LHS is dead and RHS
 *       is a MessageSend become standalone call statements).
 *
 * Output goes to System.out via a StringBuilder flushed at the end.
 *
 * Usage:
 *   CodeGenVisitor cg = new CodeGenVisitor(ch, st, cp, dc);
 *   goal.accept(cg, null);
 *   cg.flush();
 */
public class CodeGenVisitor extends GJDepthFirst<Object, Object> {

    private final ClassHierarchyVisitor ch;
    private final SymbolTableVisitor    st;
    private final ConstPropVisitor      cp;
    private final DeadCodeVisitor       dc;

    // ---------------------------------------------------------------
    // Output buffer + indentation
    // ---------------------------------------------------------------
    private final StringBuilder out   = new StringBuilder();
    private int                 indent = 0;

    private static final String INDENT_UNIT = "   "; // 3 spaces

    // ---------------------------------------------------------------
    // Context
    // ---------------------------------------------------------------
    private String currentClass;
    private String currentMethod;

    // ---------------------------------------------------------------
    // Constructor
    // ---------------------------------------------------------------
    public CodeGenVisitor(ClassHierarchyVisitor ch,
                          SymbolTableVisitor    st,
                          ConstPropVisitor      cp,
                          DeadCodeVisitor       dc) {
        this.ch = ch;
        this.st = st;
        this.cp = cp;
        this.dc = dc;
    }

    /** Write accumulated output to stdout. */
    public void flush() {
        System.out.print(out);
    }

    // ---------------------------------------------------------------
    // Output helpers
    // ---------------------------------------------------------------

    private void emit(String s)   { out.append(s); }
    private void emitLn(String s) { out.append(s).append("\n"); }
    private void nl()             { out.append("\n"); }

    private String ind() {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < indent; i++) sb.append(INDENT_UNIT);
        return sb.toString();
    }

    // ---------------------------------------------------------------
    // Goal
    // f0 -> MainClass()
    // f1 -> ( TypeDeclaration() )*
    // f2 -> <EOF>
    // ---------------------------------------------------------------
    @Override
    public Object visit(Goal n, Object argu) {
        n.f0.accept(this, argu);
        n.f1.accept(this, argu);
        return null;
    }

    // ---------------------------------------------------------------
    // MainClass
    // f0  -> "class"
    // f1  -> Identifier()        <- class name
    // f11 -> Identifier()        <- args param name
    // f14 -> ( VarDeclaration() )*
    // f15 -> ( Statement() )*
    // ---------------------------------------------------------------
    @Override
    public Object visit(MainClass n, Object argu) {
        currentClass  = n.f1.f0.tokenImage;
        currentMethod = "main";

        emitLn("class " + currentClass + " {");
        indent++;
        emitLn(ind() + "public static void main(String [] "
                + n.f11.f0.tokenImage + ") {");
        indent++;

        n.f14.accept(this, argu);   // var declarations
        n.f15.accept(this, argu);   // statements

        indent--;
        emitLn(ind() + "}");
        indent--;
        emitLn("}");
        nl();

        currentClass  = null;
        currentMethod = null;
        return null;
    }

    // ---------------------------------------------------------------
    // TypeDeclaration  (just delegates to the choice)
    // ---------------------------------------------------------------
    @Override
    public Object visit(TypeDeclaration n, Object argu) {
        n.f0.accept(this, argu);
        return null;
    }

    // ---------------------------------------------------------------
    // ClassDeclaration
    // f0 -> "class"  f1 -> Identifier()
    // f3 -> ( VarDeclaration() )*
    // f4 -> ( MethodDeclaration() )*
    // ---------------------------------------------------------------
    @Override
    public Object visit(ClassDeclaration n, Object argu) {
        currentClass = n.f1.f0.tokenImage;

        emitLn("class " + currentClass + " {");
        indent++;
        n.f3.accept(this, argu);
        n.f4.accept(this, argu);
        indent--;
        emitLn("}");
        nl();

        currentClass = null;
        return null;
    }

    // ---------------------------------------------------------------
    // ClassExtendsDeclaration
    // f1 -> Identifier() (name)   f3 -> Identifier() (parent)
    // f5 -> ( VarDeclaration() )*
    // f6 -> ( MethodDeclaration() )*
    // ---------------------------------------------------------------
    @Override
    public Object visit(ClassExtendsDeclaration n, Object argu) {
        currentClass = n.f1.f0.tokenImage;

        emitLn("class " + currentClass + " extends "
                + n.f3.f0.tokenImage + " {");
        indent++;
        n.f5.accept(this, argu);
        n.f6.accept(this, argu);
        indent--;
        emitLn("}");
        nl();

        currentClass = null;
        return null;
    }

    // ---------------------------------------------------------------
    // VarDeclaration  — always emitted (declarations are never dead)
    // f0 -> Type()  f1 -> Identifier()  f2 -> ";"
    // ---------------------------------------------------------------
    @Override
    public Object visit(VarDeclaration n, Object argu) {
        emit(ind());
        emitType(n.f0);
        emitLn(" " + n.f1.f0.tokenImage + ";");
        return null;
    }

    // ---------------------------------------------------------------
    // MethodDeclaration
    // f1  -> Type()           (return type)
    // f2  -> Identifier()     (method name)
    // f4  -> ( FormalParameterList() )?
    // f7  -> ( VarDeclaration() )*
    // f8  -> ( Statement() )*
    // f10 -> Identifier()     (return var)
    // ---------------------------------------------------------------
    @Override
    public Object visit(MethodDeclaration n, Object argu) {
        String methodName = n.f2.f0.tokenImage;

        // Drop dead methods entirely
        if (dc.isDeadMethod(currentClass, methodName)) return null;

        currentMethod = methodName;

        emit(ind() + "public ");
        emitType(n.f1);
        emit(" " + methodName + "(");
        n.f4.accept(this, argu);   // formal params
        emitLn(") {");
        indent++;

        n.f7.accept(this, argu);   // var declarations
        n.f8.accept(this, argu);   // statements

        // return  -- may be a constant
        String retVar = n.f10.f0.tokenImage;
        emitLn(ind() + "return " + constOrId(retVar) + ";");

        indent--;
        emitLn(ind() + "}");
        nl();

        currentMethod = null;
        return null;
    }

    // ---------------------------------------------------------------
    // FormalParameterList / FormalParameter / FormalParameterRest
    // ---------------------------------------------------------------
    @Override
    public Object visit(FormalParameterList n, Object argu) {
        n.f0.accept(this, argu);
        n.f1.accept(this, argu);
        return null;
    }

    @Override
    public Object visit(FormalParameter n, Object argu) {
        emitType(n.f0);
        emit(" " + n.f1.f0.tokenImage);
        return null;
    }

    @Override
    public Object visit(FormalParameterRest n, Object argu) {
        emit(", ");
        n.f1.accept(this, argu);
        return null;
    }

    // ---------------------------------------------------------------
    // Statement dispatcher
    // ---------------------------------------------------------------
    @Override
    public Object visit(Statement n, Object argu) {
        n.f0.accept(this, argu);
        return null;
    }

    // ---------------------------------------------------------------
    // Block
    // ---------------------------------------------------------------
    @Override
    public Object visit(Block n, Object argu) {
        emitLn(ind() + "{");
        indent++;
        n.f1.accept(this, argu);
        indent--;
        emitLn(ind() + "}");
        return null;
    }

    // ---------------------------------------------------------------
    // AssignmentStatement
    // f0 -> Identifier()  f2 -> Expression()
    //
    // Three cases:
    //  (A) Marked dead AND rhs is a MessageSend -> emit VoidMessageSend
    //  (B) Marked dead AND rhs is side-effect-free -> drop entirely
    //  (C) Live -> emit  lhs = rhs;  with constant substitution
    // ---------------------------------------------------------------
    @Override
    public Object visit(AssignmentStatement n, Object argu) {
        // dc.isDead checks the wrapping Statement node; here we receive
        // the inner node, so check by walking up — we handle this by
        // having the Statement visitor check before delegating.
        // (See visit(Statement) override below — we override it to
        //  intercept dead-statement checks before dispatching.)
        //
        // If we reach here the statement is LIVE.
        String lhs = n.f0.f0.tokenImage;
        emit(ind() + lhs + " = ");
        emitExpression(n.f2);
        emitLn(";");
        return null;
    }

    // ---------------------------------------------------------------
    // ArrayAssignmentStatement
    // f0 -> Identifier()  f2 -> Identifier() (index)  f5 -> Identifier() (val)
    // ---------------------------------------------------------------
    @Override
    public Object visit(ArrayAssignmentStatement n, Object argu) {
        String arr = n.f0.f0.tokenImage;
        String idx = n.f2.f0.tokenImage;
        String val = n.f5.f0.tokenImage;
        emitLn(ind() + arr + "[" + constOrId(idx) + "] = " + constOrId(val) + ";");
        return null;
    }

    // ---------------------------------------------------------------
    // FieldAssignmentStatement
    // f0 -> Identifier() (obj)  f2 -> Identifier() (field)  f4 -> Identifier() (val)
    // ---------------------------------------------------------------
    @Override
    public Object visit(FieldAssignmentStatement n, Object argu) {
        String obj   = n.f0.f0.tokenImage;
        String field = n.f2.f0.tokenImage;
        String val   = n.f4.f0.tokenImage;
        emitLn(ind() + obj + "." + field + " = " + constOrId(val) + ";");
        return null;
    }

    // ---------------------------------------------------------------
    // IfStatement
    //
    // deadBranch == "else" -> emit only then-body  (condition was true)
    // deadBranch == "then" -> emit only else-body  (condition was false)
    // null                 -> emit full if/else
    // ---------------------------------------------------------------
    @Override
    public Object visit(IfStatement n, Object argu) {
        // We need the wrapping Statement node for dc.getDeadBranch.
        // We pass the IfStatement node directly — DeadCodeVisitor stores
        // both the wrapper and the inner node; we check both.
        String dead = dc.getDeadBranch(n);

        if ("else".equals(dead)) {
            // condition was true — emit only then-branch
            n.f4.accept(this, argu);
        } else if ("then".equals(dead)) {
            // condition was false — emit only else-branch
            n.f6.accept(this, argu);
        } else {
            // Both branches live
            String cond = n.f2.f0.tokenImage;
            emitLn(ind() + "if (" + cond + ")");
            indent++;
            n.f4.accept(this, argu);
            indent--;
            emitLn(ind() + "else");
            indent++;
            n.f6.accept(this, argu);
            indent--;
        }
        return null;
    }

    // ---------------------------------------------------------------
    // WhileStatement
    // ---------------------------------------------------------------
    @Override
    public Object visit(WhileStatement n, Object argu) {
        if (dc.isDeadWhile(n)) return null;   // condition was false — drop

        String cond = n.f2.f0.tokenImage;
        emitLn(ind() + "while (" + cond + ")");
        indent++;
        n.f4.accept(this, argu);
        indent--;
        return null;
    }

    // ---------------------------------------------------------------
    // ForStatement
    // f2 -> Identifier() (loopVar init)
    // f4 -> Expression() (init expr)
    // f6 -> Expression() (condition)
    // f8 -> Identifier() (loopVar step)
    // f10 -> Expression() (step expr)
    // f12 -> Statement() (body)
    // ---------------------------------------------------------------
    @Override
    public Object visit(ForStatement n, Object argu) {
        String initVar = n.f2.f0.tokenImage;
        String stepVar = n.f8.f0.tokenImage;

        emit(ind() + "for (" + initVar + " = ");
        emitExpressionInline(n.f4);
        emit("; ");
        emitExpressionInline(n.f6);
        emit("; " + stepVar + " = ");
        emitExpressionInline(n.f10);
        emitLn(")");
        indent++;
        n.f12.accept(this, argu);
        indent--;
        return null;
    }

    // ---------------------------------------------------------------
    // PrintStatement
    // f2 -> Identifier()
    // ---------------------------------------------------------------
    @Override
    public Object visit(PrintStatement n, Object argu) {
        String varName = n.f2.f0.tokenImage;
        emitLn(ind() + "System.out.println(" + constOrId(varName) + ");");
        return null;
    }

    // ---------------------------------------------------------------
    // Expression emitters
    // ---------------------------------------------------------------

    /** Emit an Expression node, substituting constants where possible. */
    private void emitExpression(Expression n) {
        Node choice = n.f0.choice;

        if (choice instanceof CompareExpression) {
            CompareExpression ce = (CompareExpression) choice;
            emit(constOrId(ce.f0.f0.tokenImage) + " < "
                    + constOrId(ce.f2.f0.tokenImage));

        } else if (choice instanceof PlusExpression) {
            PlusExpression pe = (PlusExpression) choice;
            emit(constOrId(pe.f0.f0.tokenImage) + " + "
                    + constOrId(pe.f2.f0.tokenImage));

        } else if (choice instanceof MinusExpression) {
            MinusExpression me = (MinusExpression) choice;
            emit(constOrId(me.f0.f0.tokenImage) + " - "
                    + constOrId(me.f2.f0.tokenImage));

        } else if (choice instanceof TimesExpression) {
            TimesExpression te = (TimesExpression) choice;
            emit(constOrId(te.f0.f0.tokenImage) + " * "
                    + constOrId(te.f2.f0.tokenImage));

        } else if (choice instanceof ArrayLookup) {
            ArrayLookup al = (ArrayLookup) choice;
            emit(al.f0.f0.tokenImage + "["
                    + constOrId(al.f2.f0.tokenImage) + "]");

        } else if (choice instanceof ArrayLength) {
            emit(((ArrayLength) choice).f0.f0.tokenImage + ".length");

        } else if (choice instanceof MessageSend) {
            emitMessageSend((MessageSend) choice);

        } else if (choice instanceof FieldRead) {
            FieldRead fr = (FieldRead) choice;
            emit(fr.f0.f0.tokenImage + "." + fr.f2.f0.tokenImage);

        } else if (choice instanceof PrimaryExpression) {
            emitPrimary((PrimaryExpression) choice);
        }
    }

    /** Same as emitExpression but used inline (no trailing newline). */
    private void emitExpressionInline(Expression n) {
        emitExpression(n);   // emitExpression never adds newlines itself
    }

    private void emitMessageSend(MessageSend ms) {
        emitPrimary(ms.f0);           // receiver
        emit("." + ms.f2.f0.tokenImage + "(");
        if (ms.f4.present()) {
            ArgList al = (ArgList) ms.f4.node;
            emit(constOrId(al.f0.f0.tokenImage));   // first arg
            if (al.f1.present()) {
                for (Enumeration<Node> e = al.f1.elements();
                     e.hasMoreElements();) {
                    ArgRest ar = (ArgRest) e.nextElement();
                    emit(", " + constOrId(ar.f1.f0.tokenImage));
                }
            }
        }
        emit(")");
    }

    private void emitPrimary(PrimaryExpression pe) {
        Node choice = pe.f0.choice;

        if (choice instanceof IntegerLiteral) {
            emit(((IntegerLiteral) choice).f0.tokenImage);
        } else if (choice instanceof TrueLiteral) {
            emit("true");
        } else if (choice instanceof FalseLiteral) {
            emit("false");
        } else if (choice instanceof Identifier) {
            emit(constOrId(((Identifier) choice).f0.tokenImage));
        } else if (choice instanceof ThisExpression) {
            emit("this");
        } else if (choice instanceof ArrayAllocationExpression) {
            ArrayAllocationExpression aae = (ArrayAllocationExpression) choice;
            emit("new int[" + constOrId(aae.f3.f0.tokenImage) + "]");
        } else if (choice instanceof AllocationExpression) {
            AllocationExpression ae = (AllocationExpression) choice;
            emit("new " + ae.f1.f0.tokenImage + "()");
        } else if (choice instanceof NotExpression) {
            NotExpression ne = (NotExpression) choice;
            emit("!" + ne.f1.f0.tokenImage);
        }
    }

    // ---------------------------------------------------------------
    // Statement-level dead code interception
    //
    // We override the NodeListOptional visitor so that each Statement
    // in a list is checked for deadness before being dispatched.
    // ---------------------------------------------------------------

    /**
     * Intercept each Statement node before dispatch so we can:
     *  - Drop dead AssignmentStatements
     *  - Emit VoidMessageSendStatement for dead-lhs MessageSend assignments
     *  - Pass live statements to their normal visit methods
     */
    private void emitStatement(Node stmtNode) {
        // Unwrap the Statement wrapper to get the concrete node
        Node inner = stmtNode;
        if (stmtNode instanceof Statement)
            inner = ((Statement) stmtNode).f0.choice;

        if (inner instanceof AssignmentStatement) {
            AssignmentStatement as = (AssignmentStatement) inner;

            if (dc.isDead(stmtNode)) {
                // Dead assignment:
                // If RHS is a MessageSend it still has side effects —
                // emit as a VoidMessageSendStatement.
                Node exprChoice = as.f2.f0.choice;
                if (exprChoice instanceof MessageSend) {
                    emit(ind());
                    emitMessageSend((MessageSend) exprChoice);
                    emitLn(";");
                }
                // Otherwise: pure RHS — drop entirely (emit nothing)
                return;
            }
            // Live assignment — emit normally
            as.accept(this, null);

        } else if (inner instanceof IfStatement) {
            inner.accept(this, null);

        } else if (inner instanceof WhileStatement) {
            inner.accept(this, null);

        } else {
            // Block, ArrayAssign, FieldAssign, Print, For — always live
            inner.accept(this, null);
        }
    }

    /**
     * Override NodeListOptional so statement lists go through emitStatement.
     * This intercepts both MainClass.f15 and MethodDeclaration.f8.
     */
    @Override
    public Object visit(NodeListOptional n, Object argu) {
        if (!n.present()) return null;
        for (Enumeration<Node> e = n.elements(); e.hasMoreElements();) {
            Node node = e.nextElement();
            // Only apply dead-code logic to Statement nodes
            if (node instanceof Statement) {
                emitStatement(node);
            } else {
                // VarDeclaration lists etc. — visit normally
                node.accept(this, argu);
            }
        }
        return null;
    }

    // ---------------------------------------------------------------
    // Type emitter
    // ---------------------------------------------------------------
    private void emitType(Type t) {
        Node choice = t.f0.choice;
        if      (choice instanceof ArrayType)   emit("int []");
        else if (choice instanceof BooleanType) emit("boolean");
        else if (choice instanceof IntegerType) emit("int");
        else if (choice instanceof Identifier)
            emit(((Identifier) choice).f0.tokenImage);
    }

    // ---------------------------------------------------------------
    // Core helper: emit a constant if known, else the identifier name
    // ---------------------------------------------------------------

    /**
     * For a variable name used in a ConstOrId position:
     * if CP says it's a constant, emit the constant literal;
     * otherwise emit the identifier as-is.
     */
    private String constOrId(String varName) {
        if (currentClass == null || currentMethod == null) return varName;
        CPValue val = cp.getIdValue(currentClass, currentMethod, varName);
        if (val.isConst()) return val.toTokenString();
        return varName;
    }
}

