import syntaxtree.*;
import java.util.*;

/**
 * Pass 6: Code Generation — pretty-prints the optimized AST as TACoJava2.
 *
 * Key responsibilities:
 *  (1) Substitute constants for identifiers wherever TACoJava2 allows
 *      a ConstOrId (arguments, return, print arg, arithmetic operands,
 *      array index, field assignment RHS).
 *  (2) Elide dead AssignmentStatements.
 *  (3) Replace dead if/while branches with only the live branch.
 *  (4) Drop dead MethodDeclarations entirely.
 *  (5) Emit VoidMessageSendStatement for standalone calls
 *      (TACoJava2 addition — assignments whose LHS is dead and RHS
 *       is a MessageSend become standalone call statements).
 *
 * Output goes to System.out via a StringBuilder flushed at the end.
 *
 * Usage:
 *   CodeGenVisitor cg = new CodeGenVisitor(ch, st, cp, dc);
 *   goal.accept(cg, null);
 *   cg.flush();
 */
public class CodeGenVisitor extends GJDepthFirst<Object, Object> {

    private final ClassHierarchyVisitor ch;
    private final SymbolTableVisitor    st;
    private final ConstPropVisitor      cp;
    private final DeadCodeVisitor       dc;

    // ---------------------------------------------------------------
    // Output buffer + indentation
    // ---------------------------------------------------------------
    private final StringBuilder out   = new StringBuilder();
    private int                 indent = 0;

    private static final String INDENT_UNIT = "   "; // 3 spaces

    // ---------------------------------------------------------------
    // Context
    // ---------------------------------------------------------------
    private String currentClass;
    private String currentMethod;

    // ---------------------------------------------------------------
    // Constructor
    // ---------------------------------------------------------------
    public CodeGenVisitor(ClassHierarchyVisitor ch,
                          SymbolTableVisitor    st,
                          ConstPropVisitor      cp,
                          DeadCodeVisitor       dc) {
        this.ch = ch;
        this.st = st;
        this.cp = cp;
        this.dc = dc;
