        for (int i = 0; i < indent; i++) sb.append(INDENT_UNIT);
        return sb.toString();
    }

    // ---------------------------------------------------------------
    // Goal
    // f0 -> MainClass()
    // f1 -> ( TypeDeclaration() )*
    // f2 -> <EOF>
