    // ---------------------------------------------------------------
    // MainClass
    // f0  -> "class"
    // f1  -> Identifier()        <- class name
    // f11 -> Identifier()        <- args param name
    // f14 -> ( VarDeclaration() )*
    // f15 -> ( Statement() )*
