    /** Same as emitExpression but used inline (no trailing newline). */
    private void emitExpressionInline(Expression n) {
        emitExpression(n);   // emitExpression never adds newlines itself
    }

    private void emitMessageSend(MessageSend ms) {
        emitPrimary(ms.f0);           // receiver
        emit("." + ms.f2.f0.tokenImage + "(");
        if (ms.f4.present()) {
            ArgList al = (ArgList) ms.f4.node;
            emit(constOrId(al.f0.f0.tokenImage));   // first arg
            if (al.f1.present()) {
                for (Enumeration<Node> e = al.f1.elements();
                     e.hasMoreElements();) {
                    ArgRest ar = (ArgRest) e.nextElement();
                    emit(", " + constOrId(ar.f1.f0.tokenImage));
                }
            }
        }
        emit(")");
    }

    private void emitPrimary(PrimaryExpression pe) {
        Node choice = pe.f0.choice;

        if (choice instanceof IntegerLiteral) {
            emit(((IntegerLiteral) choice).f0.tokenImage);
        } else if (choice instanceof TrueLiteral) {
            emit("true");
        } else if (choice instanceof FalseLiteral) {
            emit("false");
        } else if (choice instanceof Identifier) {
            emit(constOrId(((Identifier) choice).f0.tokenImage));
        } else if (choice instanceof ThisExpression) {
            emit("this");
        } else if (choice instanceof ArrayAllocationExpression) {
            ArrayAllocationExpression aae = (ArrayAllocationExpression) choice;
            emit("new int[" + constOrId(aae.f3.f0.tokenImage) + "]");
        } else if (choice instanceof AllocationExpression) {
            AllocationExpression ae = (AllocationExpression) choice;
            emit("new " + ae.f1.f0.tokenImage + "()");
        } else if (choice instanceof NotExpression) {
            NotExpression ne = (NotExpression) choice;
            emit("!" + ne.f1.f0.tokenImage);
        }
    }

    // ---------------------------------------------------------------
    // Statement-level dead code interception
    //
    // We override the NodeListOptional visitor so that each Statement
    // in a list is checked for deadness before being dispatched.
    // ---------------------------------------------------------------

    /**
     * Intercept each Statement node before dispatch so we can:
     *  - Drop dead AssignmentStatements
     *  - Emit VoidMessageSendStatement for dead-lhs MessageSend assignments
     *  - Pass live statements to their normal visit methods
     */
    private void emitStatement(Node stmtNode) {
        // Unwrap the Statement wrapper to get the concrete node
        Node inner = stmtNode;
        if (stmtNode instanceof Statement)
            inner = ((Statement) stmtNode).f0.choice;

        if (inner instanceof AssignmentStatement) {
            AssignmentStatement as = (AssignmentStatement) inner;

            if (dc.isDead(stmtNode)) {
                // Dead assignment:
                // If RHS is a MessageSend it still has side effects —
                // emit as a VoidMessageSendStatement.
                Node exprChoice = as.f2.f0.choice;
                if (exprChoice instanceof MessageSend) {
                    emit(ind());
                    emitMessageSend((MessageSend) exprChoice);
                    emitLn(";");
                }
                // Otherwise: pure RHS — drop entirely (emit nothing)
                return;
            }
            // Live assignment — emit normally
            as.accept(this, null);

        } else if (inner instanceof IfStatement) {
            inner.accept(this, null);

        } else if (inner instanceof WhileStatement) {
            inner.accept(this, null);

        } else {
            // Block, ArrayAssign, FieldAssign, Print, For — always live
            inner.accept(this, null);
        }
    }

    /**
     * Override NodeListOptional so statement lists go through emitStatement.
     * This intercepts both MainClass.f15 and MethodDeclaration.f8.
     */
    @Override
    public Object visit(NodeListOptional n, Object argu) {
        if (!n.present()) return null;
        for (Enumeration<Node> e = n.elements(); e.hasMoreElements();) {
            Node node = e.nextElement();
            // Only apply dead-code logic to Statement nodes
            if (node instanceof Statement) {
                emitStatement(node);
            } else {
                // VarDeclaration lists etc. — visit normally
                node.accept(this, argu);
            }
        }
        return null;
    }

    // ---------------------------------------------------------------
    // Type emitter
    // ---------------------------------------------------------------
    private void emitType(Type t) {
        Node choice = t.f0.choice;
        if      (choice instanceof ArrayType)   emit("int []");
        else if (choice instanceof BooleanType) emit("boolean");
        else if (choice instanceof IntegerType) emit("int");
        else if (choice instanceof Identifier)
            emit(((Identifier) choice).f0.tokenImage);
    }

    // ---------------------------------------------------------------
    // Core helper: emit a constant if known, else the identifier name
    // ---------------------------------------------------------------

    /**
     * For a variable name used in a ConstOrId position:
     * if CP says it's a constant, emit the constant literal;
     * otherwise emit the identifier as-is.
     */
    private String constOrId(String varName) {
        if (currentClass == null || currentMethod == null) return varName;
        CPValue val = cp.getIdValue(currentClass, currentMethod, varName);
        if (val.isConst()) return val.toTokenString();
        return varName;
    }
}
