package visitor;

import syntaxtree.*;
import java.util.*;

/**
 * Pass 5: Liveness Analysis + Dead Code Marking.
 *
 * Grammar field layout (from GJDepthFirst / tacojava.jj):
 *   ArrayAssignmentStatement:
 *     f0=arr(Id) f1="[" f2=index(Id) f3="]" f4="=" f5=val(Id) f6=";"
 *   FieldAssignmentStatement:
 *     f0=obj(Id) f1="." f2=field(Id) f3="=" f4=val(Id) f5=";"
 *   IfStatement:
 *     f0="if" f1="(" f2=cond(Id) f3=")" f4=thenStmt f5="else" f6=elseStmt
 *   WhileStatement:
 *     f0="while" f1="(" f2=cond(Id) f3=")" f4=body
 *   ForStatement:
 *     f0="for" f1="(" f2=initVar(Id) f3="=" f4=initExpr
 *     f5=";" f6=condExpr f7=";" f8=stepVar(Id) f9="=" f10=stepExpr
 *     f11=")" f12=body
 *   MessageSend:
 *     f0=receiver(PrimaryExpr) f1="." f2=method(Id) f3="(" f4=ArgList? f5=")"
 *   ArgList:
 *     f0=firstArg(Id) f1=( ArgRest() )*
 *   ArgRest:
 *     f0="," f1=arg(Id)
 *
 * Dead-code categories marked:
 *  (A) Dead AssignmentStatement: lhs not live after AND rhs has no side effects
 *  (B) Unreachable if-branch: condition is a known constant
 *  (C) Unreachable while: condition is statically false
 *  (D) Dead methods: not reachable from call graph
 *
 * Keys in deadIfBranch:
 *   "else" -> the else-branch is dead (condition was true  -> keep then)
 *   "then" -> the then-branch is dead (condition was false -> keep else)
 *
 * IMPORTANT: all dead-node sets are keyed on the INNER concrete node
 * (AssignmentStatement / IfStatement / WhileStatement), NOT the
 * Statement wrapper. CodeGenVisitor unwraps before querying.
 */
public class DeadCodeVisitor extends GJDepthFirst<Object, Object> {

    private final ClassHierarchyVisitor ch;
    private final SymbolTableVisitor    st;
    private final CallGraphVisitor      cg;
    private final ConstPropVisitor      cp;

    // ---------------------------------------------------------------
    // Results — keyed on INNER concrete node (not Statement wrapper)
    // ---------------------------------------------------------------

    /** Inner AssignmentStatement nodes that should be dropped or promoted. */
    private final Set<Node> deadAssignments = Collections.newSetFromMap(
            new IdentityHashMap<>());

    /**
     * Inner IfStatement -> "else" (else-branch dead, keep then)
     *                   or "then" (then-branch dead, keep else).
     * Absent = both branches live.
     */
    private final Map<Node, String> deadIfBranch = new IdentityHashMap<>();

    /** Inner WhileStatement nodes whose body is unreachable. */
    private final Set<Node> deadWhiles = Collections.newSetFromMap(
            new IdentityHashMap<>());

    /** "ClassName::methodName" strings for dead methods. */
    private final Set<String> deadMethods = new LinkedHashSet<>();

    // ---------------------------------------------------------------
    // Method AST index (built in Phase 1)
    // ---------------------------------------------------------------
    private final Map<String, Map<String, MethodDeclaration>> methodIndex
            = new LinkedHashMap<>();
    private MainClass mainClassNode;

    // ---------------------------------------------------------------
    // Constructor
    // ---------------------------------------------------------------
    public DeadCodeVisitor(ClassHierarchyVisitor ch,
                           SymbolTableVisitor    st,
                           CallGraphVisitor      cg,
                           ConstPropVisitor      cp) {
        this.ch = ch;
        this.st = st;
        this.cg = cg;
        this.cp = cp;
    }

    // ---------------------------------------------------------------
    // Public query API — all take INNER concrete nodes
    // ---------------------------------------------------------------

    /** Should this inner AssignmentStatement node be dropped / promoted? */
    public boolean isDeadAssignment(AssignmentStatement n) {
        return deadAssignments.contains(n);
    }

    /**
     * For an inner IfStatement node:
     *   "else" -> else-branch dead; emit only then-branch
     *   "then" -> then-branch dead; emit only else-branch
     *   null   -> both live
     */
    public String getDeadBranch(IfStatement n) {
        return deadIfBranch.get(n);
    }

    /** Should this inner WhileStatement's body be dropped? */
    public boolean isDeadWhile(WhileStatement n) {
        return deadWhiles.contains(n);
    }

    /** Should this method be omitted from the output? */
    public boolean isDeadMethod(String className, String methodName) {
        return deadMethods.contains(className + "::" + methodName);
    }

    // ---------------------------------------------------------------
    // Entry point
    // ---------------------------------------------------------------

    @Override
    public Object visit(Goal n, Object argu) {
        // Phase 1: index method AST nodes
        n.f0.accept(this, "INDEX");
        n.f1.accept(this, "INDEX");

        // Phase 2: mark dead methods
        markDeadMethods();

        // Phase 3: per-method liveness + dead-code marking
        for (String key : cg.reachableSet()) {
            String[] parts  = key.split("::");
            String   cls    = parts[0];
            String   method = parts[1];
            analyseMethod(cls, method);
        }
        return null;
    }

    // ---------------------------------------------------------------
    // Phase 1: indexing
    // ---------------------------------------------------------------

    @Override
    public Object visit(MainClass n, Object argu) {
        mainClassNode = n;
        return null;
    }

    @Override
    public Object visit(ClassDeclaration n, Object argu) {
        if (!"INDEX".equals(argu)) return null;
        n.f4.accept(this, n.f1.f0.tokenImage);
        return null;
    }

    @Override
    public Object visit(ClassExtendsDeclaration n, Object argu) {
        if (!"INDEX".equals(argu)) return null;
        n.f6.accept(this, n.f1.f0.tokenImage);
        return null;
    }

    @Override
    public Object visit(MethodDeclaration n, Object argu) {
        if (!(argu instanceof String)) return null;
        String cls    = (String) argu;
        String method = n.f2.f0.tokenImage;
        methodIndex.computeIfAbsent(cls, k -> new LinkedHashMap<>())
                   .put(method, n);
        return null;
    }

    // ---------------------------------------------------------------
    // Phase 2: mark dead methods
    // ---------------------------------------------------------------

    private void markDeadMethods() {
        for (String cls : ch.classNames()) {
            for (String method : ch.methodsOf(cls)) {
                if (!cg.reachable(cls, method))
                    deadMethods.add(cls + "::" + method);
            }
        }
    }

    // ---------------------------------------------------------------
    // Phase 3: per-method backward liveness + marking
    // ---------------------------------------------------------------

    private void analyseMethod(String cls, String method) {
        List<Node> stmts = getStatementList(cls, method);
        if (stmts == null || stmts.isEmpty()) return;

        int n = stmts.size();
        @SuppressWarnings("unchecked")
        Set<String>[] liveOut = new Set[n];
        for (int i = 0; i < n; i++)
            liveOut[i] = new LinkedHashSet<>();

        // The return variable is live at method exit
        Set<String> exitLive = new LinkedHashSet<>();
        if (!"main".equals(method)) {
            MethodDeclaration md = lookupMethod(cls, method);
            if (md != null)
                exitLive.add(md.f10.f0.tokenImage);
        }

        // Backward fixpoint over the flat statement list
        boolean changed = true;
        while (changed) {
            changed = false;
            Set<String> live = new LinkedHashSet<>(exitLive);
            for (int i = n - 1; i >= 0; i--) {
                if (!live.equals(liveOut[i])) {
                    liveOut[i] = new LinkedHashSet<>(live);
                    changed = true;
                }
                live = liveIn(unwrap(stmts.get(i)), live, cls, method);
            }
        }

        // Mark dead statements using final liveOut sets
        for (int i = 0; i < n; i++) {
            markDeadStatement(unwrap(stmts.get(i)), liveOut[i], cls, method);
        }
    }

    /**
     * Unwrap a Statement wrapper to get the inner concrete node.
     * If already unwrapped, return as-is.
     */
    private static Node unwrap(Node n) {
        if (n instanceof Statement) return ((Statement) n).f0.choice;
        return n;
    }

    // ---------------------------------------------------------------
    // Transfer function: liveIn(stmt, liveOut) = (liveOut - defs) ∪ uses
    // Takes the INNER concrete node (already unwrapped).
    // ---------------------------------------------------------------

    private Set<String> liveIn(Node inner, Set<String> liveOut,
                                String cls, String method) {
        Set<String> live = new LinkedHashSet<>(liveOut);

        if (inner instanceof AssignmentStatement) {
            AssignmentStatement as = (AssignmentStatement) inner;
            // def
            live.remove(as.f0.f0.tokenImage);
            // uses of rhs expression
            live.addAll(usesOfExpression(as.f2));

        } else if (inner instanceof ArrayAssignmentStatement) {
            // arr[index] = val
            // f0=arr f1="[" f2=index(Id) f3="]" f4="=" f5=val(Id) f6=";"
            ArrayAssignmentStatement aas = (ArrayAssignmentStatement) inner;
            live.add(aas.f0.f0.tokenImage);  // arr
            live.add(aas.f2.f0.tokenImage);  // index
            live.add(aas.f5.f0.tokenImage);  // val

        } else if (inner instanceof FieldAssignmentStatement) {
            // obj.field = val
            // f0=obj f1="." f2=field(Id) f3="=" f4=val(Id) f5=";"
            FieldAssignmentStatement fas = (FieldAssignmentStatement) inner;
            live.add(fas.f0.f0.tokenImage);  // obj
            live.add(fas.f4.f0.tokenImage);  // val

        } else if (inner instanceof PrintStatement) {
            // f2 = printed Identifier
            live.add(((PrintStatement) inner).f2.f0.tokenImage);

        } else if (inner instanceof IfStatement) {
            IfStatement is = (IfStatement) inner;
            String  condName = is.f2.f0.tokenImage;
            CPValue condVal  = cp.getVarValue(cls, method, condName);

            if (condVal.isTrue()) {
                live = liveIn(unwrap(is.f4), new LinkedHashSet<>(liveOut), cls, method);
            } else if (condVal.isFalse()) {
                live = liveIn(unwrap(is.f6), new LinkedHashSet<>(liveOut), cls, method);
            } else {
                Set<String> thenLive = liveIn(unwrap(is.f4),
                        new LinkedHashSet<>(liveOut), cls, method);
                Set<String> elseLive = liveIn(unwrap(is.f6),
                        new LinkedHashSet<>(liveOut), cls, method);
                live = union(thenLive, elseLive);
            }
            live.add(condName);

        } else if (inner instanceof WhileStatement) {
            WhileStatement ws = (WhileStatement) inner;
            String  condName = ws.f2.f0.tokenImage;
            CPValue condVal  = cp.getVarValue(cls, method, condName);

            live.add(condName);
            if (!condVal.isFalse()) {
                // Body may execute — add its uses conservatively
                Set<String> bodyLive = liveIn(unwrap(ws.f4),
                        new LinkedHashSet<>(liveOut), cls, method);
                live.addAll(bodyLive);
            }

        } else if (inner instanceof ForStatement) {
            ForStatement fs = (ForStatement) inner;
            // f2=initVar f4=initExpr f6=condExpr f8=stepVar f10=stepExpr f12=body
            String initVar = fs.f2.f0.tokenImage;
            String stepVar = fs.f8.f0.tokenImage;

            live.addAll(usesOfExpression(fs.f4));   // init expr uses
            live.addAll(usesOfExpression(fs.f6));   // cond expr uses
            live.addAll(usesOfExpression(fs.f10));  // step expr uses
            // initVar and stepVar are defined — remove them after adding uses
            live.remove(initVar);
            live.remove(stepVar);
            // Body uses
            Set<String> bodyLive = liveIn(unwrap(fs.f12),
                    new LinkedHashSet<>(liveOut), cls, method);
            live.addAll(bodyLive);

        } else if (inner instanceof Block) {
            Block b = (Block) inner;
            List<Node> innerStmts = nodeListToList(b.f1);
            // Backward through block
            Set<String> cur = new LinkedHashSet<>(liveOut);
            for (int i = innerStmts.size() - 1; i >= 0; i--) {
                cur = liveIn(unwrap(innerStmts.get(i)), cur, cls, method);
            }
            live = cur;
        }
        // Note: MessageSend-as-void-statement doesn't appear in TACoJava
        // (only in TACoJava2 output). In TACoJava it's always inside an
        // AssignmentStatement, handled above via usesOfExpression.

        return live;
    }

    // ---------------------------------------------------------------
    // Dead-code marking — takes the INNER concrete node
    // ---------------------------------------------------------------

    private void markDeadStatement(Node inner, Set<String> liveOut,
                                   String cls, String method) {
        if (inner instanceof AssignmentStatement) {
            AssignmentStatement as = (AssignmentStatement) inner;
            String lhs = as.f0.f0.tokenImage;
            // Dead iff lhs is not live AND rhs is side-effect-free
            if (!liveOut.contains(lhs) && !hasSideEffects(as.f2))
                deadAssignments.add(inner);

        } else if (inner instanceof IfStatement) {
            IfStatement is = (IfStatement) inner;
            CPValue condVal = cp.getVarValue(cls, method, is.f2.f0.tokenImage);
            if (condVal.isTrue())  deadIfBranch.put(inner, "else"); // else dead
            if (condVal.isFalse()) deadIfBranch.put(inner, "then"); // then dead

        } else if (inner instanceof WhileStatement) {
            WhileStatement ws = (WhileStatement) inner;
            CPValue condVal = cp.getVarValue(cls, method, ws.f2.f0.tokenImage);
            if (condVal.isFalse()) deadWhiles.add(inner);
        }
        // PrintStatement, ArrayAssignmentStatement, FieldAssignmentStatement,
        // ForStatement, Block — always have visible effects; never mark dead.
    }

    // ---------------------------------------------------------------
    // Side-effect check
    // ---------------------------------------------------------------

    /** An expression has side effects iff its top-level form is a MessageSend. */
    private boolean hasSideEffects(Expression expr) {
        return expr.f0.choice instanceof MessageSend;
    }

    // ---------------------------------------------------------------
    // Uses of an Expression node (all variable names read)
    // ---------------------------------------------------------------

    private Set<String> usesOfExpression(Expression expr) {
        Set<String> uses = new LinkedHashSet<>();
        Node choice = expr.f0.choice;

        if (choice instanceof CompareExpression) {
            CompareExpression ce = (CompareExpression) choice;
            uses.add(ce.f0.f0.tokenImage);
            uses.add(ce.f2.f0.tokenImage);

        } else if (choice instanceof PlusExpression) {
            PlusExpression pe = (PlusExpression) choice;
            uses.add(pe.f0.f0.tokenImage);
            uses.add(pe.f2.f0.tokenImage);

        } else if (choice instanceof MinusExpression) {
            MinusExpression me = (MinusExpression) choice;
            uses.add(me.f0.f0.tokenImage);
            uses.add(me.f2.f0.tokenImage);

        } else if (choice instanceof TimesExpression) {
            TimesExpression te = (TimesExpression) choice;
            uses.add(te.f0.f0.tokenImage);
            uses.add(te.f2.f0.tokenImage);

        } else if (choice instanceof ArrayLookup) {
            // f0=arr(Id) f1="[" f2=index(Id) f3="]"
            ArrayLookup al = (ArrayLookup) choice;
            uses.add(al.f0.f0.tokenImage);
            uses.add(al.f2.f0.tokenImage);

        } else if (choice instanceof ArrayLength) {
            // f0=arr(Id) f1="." f2="length"
            uses.add(((ArrayLength) choice).f0.f0.tokenImage);

        } else if (choice instanceof MessageSend) {
            // f0=receiver(PrimaryExpr) f1="." f2=method f3="(" f4=ArgList? f5=")"
            MessageSend ms = (MessageSend) choice;
            Node recv = ms.f0.f0.choice;
            if (recv instanceof Identifier)
                uses.add(((Identifier) recv).f0.tokenImage);
            if (ms.f4.present()) {
                ArgList al = (ArgList) ms.f4.node;
                uses.add(al.f0.f0.tokenImage);   // first arg
                if (al.f1.present()) {
                    for (Enumeration<Node> e = al.f1.elements();
                         e.hasMoreElements();) {
                        ArgRest ar = (ArgRest) e.nextElement();
                        uses.add(ar.f1.f0.tokenImage);
                    }
                }
            }

        } else if (choice instanceof FieldRead) {
            // f0=obj(Id) f1="." f2=field(Id)
            uses.add(((FieldRead) choice).f0.f0.tokenImage);

        } else if (choice instanceof PrimaryExpression) {
            Node prim = ((PrimaryExpression) choice).f0.choice;
            if (prim instanceof Identifier)
                uses.add(((Identifier) prim).f0.tokenImage);
            else if (prim instanceof NotExpression)
                uses.add(((NotExpression) prim).f1.f0.tokenImage);
            else if (prim instanceof ArrayAllocationExpression)
                uses.add(((ArrayAllocationExpression) prim).f3.f0.tokenImage);
        }
        return uses;
    }

    // ---------------------------------------------------------------
    // Helpers
    // ---------------------------------------------------------------

    private List<Node> getStatementList(String cls, String method) {
        NodeListOptional nlo;
        if ("main".equals(method) && mainClassNode != null) {
            nlo = mainClassNode.f15;
        } else {
            MethodDeclaration md = lookupMethod(cls, method);
            if (md == null) return null;
            nlo = md.f8;
        }
        return nodeListToList(nlo);
    }

    private List<Node> nodeListToList(NodeListOptional nlo) {
        List<Node> list = new ArrayList<>();
        if (nlo.present()) {
            for (Enumeration<Node> e = nlo.elements(); e.hasMoreElements();)
                list.add(e.nextElement());
        }
        return list;
    }

    private MethodDeclaration lookupMethod(String cls, String method) {
        String cur = cls;
        while (cur != null) {
            Map<String, MethodDeclaration> m = methodIndex.get(cur);
            if (m != null && m.containsKey(method)) return m.get(method);
            cur = ch.parentOf(cur);
        }
        return null;
    }

    private static Set<String> union(Set<String> a, Set<String> b) {
        Set<String> r = new LinkedHashSet<>(a);
        r.addAll(b);
        return r;
    }
}

