package visitor;

import syntaxtree.*;
import java.util.*;

/**
 * Pass 6: Code Generation — pretty-prints the optimized AST as TACoJava2.
 *
 * Grammar field layout used here (from tacojava.jj / GJDepthFirst):
 *   ArrayAssignmentStatement:
 *     f0=arr(Id) f1="[" f2=index(Id) f3="]" f4="=" f5=val(Id) f6=";"
 *   FieldAssignmentStatement:
 *     f0=obj(Id) f1="." f2=field(Id) f3="=" f4=val(Id) f5=";"
 *   IfStatement:
 *     f0="if" f1="(" f2=cond(Id) f3=")" f4=thenStmt f5="else" f6=elseStmt
 *   WhileStatement:
 *     f0="while" f1="(" f2=cond(Id) f3=")" f4=body
 *   ForStatement:
 *     f0="for" f1="(" f2=initVar(Id) f3="=" f4=initExpr
 *     f5=";" f6=condExpr f7=";" f8=stepVar(Id) f9="=" f10=stepExpr
 *     f11=")" f12=body
 *   MessageSend:
 *     f0=receiver(PrimaryExpr) f1="." f2=method(Id) f3="(" f4=ArgList? f5=")"
 *   ArgList:
 *     f0=firstArg(Id) f1=( ArgRest() )*
 *   ArgRest:
 *     f0="," f1=arg(Id)
 *
 * DeadCodeVisitor keys its sets on INNER concrete nodes (already unwrapped
 * from the Statement wrapper). This visitor unwraps before querying.
 */
public class CodeGenVisitor extends GJDepthFirst<Object, Object> {

    private final ClassHierarchyVisitor ch;
    private final SymbolTableVisitor    st;
    private final ConstPropVisitor      cp;
    private final DeadCodeVisitor       dc;

    // ---------------------------------------------------------------
    // Output buffer + indentation
    // ---------------------------------------------------------------
    private final StringBuilder out   = new StringBuilder();
    private int                 indent = 0;
    private static final String INDENT_UNIT = "   ";

    // ---------------------------------------------------------------
    // Context
    // ---------------------------------------------------------------
    private String currentClass;
    private String currentMethod;

    // ---------------------------------------------------------------
    // Constructor
    // ---------------------------------------------------------------
    public CodeGenVisitor(ClassHierarchyVisitor ch,
                          SymbolTableVisitor    st,
                          ConstPropVisitor      cp,
                          DeadCodeVisitor       dc) {
        this.ch = ch;
        this.st = st;
        this.cp = cp;
        this.dc = dc;
    }

    /** Write accumulated output to stdout. */
    public void flush() { System.out.print(out); }

    // ---------------------------------------------------------------
    // Output helpers
    // ---------------------------------------------------------------
    private void emit(String s)   { out.append(s); }
    private void emitLn(String s) { out.append(s).append("\n"); }
    private void nl()             { out.append("\n"); }
    private String ind() {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < indent; i++) sb.append(INDENT_UNIT);
        return sb.toString();
    }

    // ---------------------------------------------------------------
    // Goal
    // ---------------------------------------------------------------
    @Override
    public Object visit(Goal n, Object argu) {
        n.f0.accept(this, argu);
        n.f1.accept(this, argu);
        return null;
    }

    // ---------------------------------------------------------------
    // MainClass
    // f0="class" f1=className f2="{" f3="public" f4="static" f5="void"
    // f6="main" f7="(" f8="String" f9="[" f10="]" f11=argsId f12=")"
    // f13="{" f14=VarDecls f15=Statements f16="}" f17="}"
    // ---------------------------------------------------------------
    @Override
    public Object visit(MainClass n, Object argu) {
        currentClass  = n.f1.f0.tokenImage;
        currentMethod = "main";

        emitLn("class " + currentClass + " {");
        indent++;
        emitLn(ind() + "public static void main(String [] "
                + n.f11.f0.tokenImage + ") {");
        indent++;
        n.f14.accept(this, argu);   // VarDeclarations
        emitStatementList(n.f15);   // Statements
        indent--;
        emitLn(ind() + "}");
        indent--;
        emitLn("}");
        nl();

        currentClass  = null;
        currentMethod = null;
        return null;
    }

    // ---------------------------------------------------------------
    // TypeDeclaration
    // ---------------------------------------------------------------
    @Override
    public Object visit(TypeDeclaration n, Object argu) {
        n.f0.accept(this, argu);
        return null;
    }

    // ---------------------------------------------------------------
    // ClassDeclaration
    // f0="class" f1=name f2="{" f3=VarDecls f4=MethodDecls f5="}"
    // ---------------------------------------------------------------
    @Override
    public Object visit(ClassDeclaration n, Object argu) {
        currentClass = n.f1.f0.tokenImage;
        emitLn("class " + currentClass + " {");
        indent++;
        n.f3.accept(this, argu);
        n.f4.accept(this, argu);
        indent--;
        emitLn("}");
        nl();
        currentClass = null;
        return null;
    }

    // ---------------------------------------------------------------
    // ClassExtendsDeclaration
    // f0="class" f1=name f2="extends" f3=parent f4="{" f5=VarDecls
    // f6=MethodDecls f7="}"
    // ---------------------------------------------------------------
    @Override
    public Object visit(ClassExtendsDeclaration n, Object argu) {
        currentClass = n.f1.f0.tokenImage;
        emitLn("class " + currentClass + " extends " + n.f3.f0.tokenImage + " {");
        indent++;
        n.f5.accept(this, argu);
        n.f6.accept(this, argu);
        indent--;
        emitLn("}");
        nl();
        currentClass = null;
        return null;
    }

    // ---------------------------------------------------------------
    // VarDeclaration  — never dead
    // f0=Type f1=name(Id) f2=";"
    // ---------------------------------------------------------------
    @Override
    public Object visit(VarDeclaration n, Object argu) {
        emit(ind());
        emitType(n.f0);
        emitLn(" " + n.f1.f0.tokenImage + ";");
        return null;
    }

    // ---------------------------------------------------------------
    // MethodDeclaration
    // f0="public" f1=Type f2=name(Id) f3="(" f4=FormalParams? f5=")"
    // f6="{" f7=VarDecls f8=Statements f9="return" f10=retVar(Id) f11=";" f12="}"
    // ---------------------------------------------------------------
    @Override
    public Object visit(MethodDeclaration n, Object argu) {
        String methodName = n.f2.f0.tokenImage;
        if (dc.isDeadMethod(currentClass, methodName)) return null;

        currentMethod = methodName;
        emit(ind() + "public ");
        emitType(n.f1);
        emit(" " + methodName + "(");
        n.f4.accept(this, argu);   // FormalParameterList (NodeOptional)
        emitLn(") {");
        indent++;
        n.f7.accept(this, argu);   // VarDeclarations
        emitStatementList(n.f8);   // Statements

        // return — may substitute a constant
        emitLn(ind() + "return " + constOrId(n.f10.f0.tokenImage) + ";");
        indent--;
        emitLn(ind() + "}");
        nl();
        currentMethod = null;
        return null;
    }

    // ---------------------------------------------------------------
    // FormalParameterList / FormalParameter / FormalParameterRest
    // ---------------------------------------------------------------
    @Override
    public Object visit(FormalParameterList n, Object argu) {
        n.f0.accept(this, argu);
        n.f1.accept(this, argu);
        return null;
    }

    @Override
    public Object visit(FormalParameter n, Object argu) {
        emitType(n.f0);
        emit(" " + n.f1.f0.tokenImage);
        return null;
    }

    @Override
    public Object visit(FormalParameterRest n, Object argu) {
        emit(", ");
        n.f1.accept(this, argu);
        return null;
    }

    // ---------------------------------------------------------------
    // Statement dispatch — we never call visit(Statement) directly;
    // instead emitStatement() unwraps and routes to concrete visitors.
    // ---------------------------------------------------------------

    /**
     * Central dispatcher for one statement node.
     * Accepts either a Statement wrapper or an already-unwrapped inner node.
     *
     * Handles:
     *  - Dead AssignmentStatement: drop (or promote to void call)
     *  - Dead if/while branches: emit only the live side
     *  - Everything else: emit normally
     */
    private void emitStatement(Node node) {
        // Unwrap Statement wrapper to get the concrete inner node
        Node inner = (node instanceof Statement)
                ? ((Statement) node).f0.choice
                : node;

        if (inner instanceof AssignmentStatement) {
            AssignmentStatement as = (AssignmentStatement) inner;
            if (dc.isDeadAssignment(as)) {
                // RHS is a MessageSend with side effects -> promote to void call
                if (as.f2.f0.choice instanceof MessageSend) {
                    emit(ind());
                    emitMessageSend((MessageSend) as.f2.f0.choice);
                    emitLn(";");
                }
                // Pure RHS -> drop entirely
                return;
            }
            // Live assignment
            emit(ind() + as.f0.f0.tokenImage + " = ");
            emitExpression(as.f2);
            emitLn(";");

        } else if (inner instanceof ArrayAssignmentStatement) {
            // f0=arr f1="[" f2=index(Id) f3="]" f4="=" f5=val(Id) f6=";"
            ArrayAssignmentStatement aas = (ArrayAssignmentStatement) inner;
            emitLn(ind() + aas.f0.f0.tokenImage
                    + "[" + constOrId(aas.f2.f0.tokenImage) + "] = "
                    + constOrId(aas.f5.f0.tokenImage) + ";");

        } else if (inner instanceof FieldAssignmentStatement) {
            // f0=obj f1="." f2=field(Id) f3="=" f4=val(Id) f5=";"
            FieldAssignmentStatement fas = (FieldAssignmentStatement) inner;
            emitLn(ind() + fas.f0.f0.tokenImage + "." + fas.f2.f0.tokenImage
                    + " = " + constOrId(fas.f4.f0.tokenImage) + ";");

        } else if (inner instanceof IfStatement) {
            emitIfStatement((IfStatement) inner);

        } else if (inner instanceof WhileStatement) {
            emitWhileStatement((WhileStatement) inner);

        } else if (inner instanceof ForStatement) {
            emitForStatement((ForStatement) inner);

        } else if (inner instanceof PrintStatement) {
            PrintStatement ps = (PrintStatement) inner;
            emitLn(ind() + "System.out.println("
                    + constOrId(ps.f2.f0.tokenImage) + ");");

        } else if (inner instanceof Block) {
            emitBlock((Block) inner);
        }
    }

    /** Emit all statements in a NodeListOptional, routing through emitStatement. */
    private void emitStatementList(NodeListOptional nlo) {
        if (!nlo.present()) return;
        for (Enumeration<Node> e = nlo.elements(); e.hasMoreElements();)
            emitStatement(e.nextElement());
    }

    // ---------------------------------------------------------------
    // Concrete statement emitters
    // ---------------------------------------------------------------

    private void emitIfStatement(IfStatement is) {
        String deadBranch = dc.getDeadBranch(is);

        if ("else".equals(deadBranch)) {
            // Condition always true -> emit only then-branch (no if wrapper)
            emitStatement(is.f4);

        } else if ("then".equals(deadBranch)) {
            // Condition always false -> emit only else-branch (no if wrapper)
            emitStatement(is.f6);

        } else {
            // Both branches live
            String cond = is.f2.f0.tokenImage;
            emitLn(ind() + "if (" + cond + ")");
            indent++;
            emitStatement(is.f4);
            indent--;
            emitLn(ind() + "else");
            indent++;
            emitStatement(is.f6);
            indent--;
        }
    }

    private void emitWhileStatement(WhileStatement ws) {
        if (dc.isDeadWhile(ws)) return;   // condition always false -> drop
        String cond = ws.f2.f0.tokenImage;
        emitLn(ind() + "while (" + cond + ")");
        indent++;
        emitStatement(ws.f4);
        indent--;
    }

    private void emitForStatement(ForStatement fs) {
        // f2=initVar f3="=" f4=initExpr f5=";" f6=condExpr
        // f7=";" f8=stepVar f9="=" f10=stepExpr f11=")" f12=body
        String initVar = fs.f2.f0.tokenImage;
        String stepVar = fs.f8.f0.tokenImage;

        emit(ind() + "for (" + initVar + " = ");
        emitExpression(fs.f4);
        emit("; ");
        emitExpression(fs.f6);
        emit("; " + stepVar + " = ");
        emitExpression(fs.f10);
        emitLn(")");
        indent++;
        emitStatement(fs.f12);
        indent--;
    }

    private void emitBlock(Block b) {
        emitLn(ind() + "{");
        indent++;
        emitStatementList(b.f1);
        indent--;
        emitLn(ind() + "}");
    }

    // ---------------------------------------------------------------
    // Expression emitters
    // ---------------------------------------------------------------

    private void emitExpression(Expression n) {
        Node choice = n.f0.choice;

        if (choice instanceof CompareExpression) {
            CompareExpression ce = (CompareExpression) choice;
            emit(constOrId(ce.f0.f0.tokenImage) + " < "
                    + constOrId(ce.f2.f0.tokenImage));

        } else if (choice instanceof PlusExpression) {
            PlusExpression pe = (PlusExpression) choice;
            emit(constOrId(pe.f0.f0.tokenImage) + " + "
                    + constOrId(pe.f2.f0.tokenImage));

        } else if (choice instanceof MinusExpression) {
            MinusExpression me = (MinusExpression) choice;
            emit(constOrId(me.f0.f0.tokenImage) + " - "
                    + constOrId(me.f2.f0.tokenImage));

        } else if (choice instanceof TimesExpression) {
            TimesExpression te = (TimesExpression) choice;
            emit(constOrId(te.f0.f0.tokenImage) + " * "
                    + constOrId(te.f2.f0.tokenImage));

        } else if (choice instanceof ArrayLookup) {
            // f0=arr(Id) f1="[" f2=index(Id) f3="]"
            ArrayLookup al = (ArrayLookup) choice;
            emit(al.f0.f0.tokenImage + "["
                    + constOrId(al.f2.f0.tokenImage) + "]");

        } else if (choice instanceof ArrayLength) {
            // f0=arr(Id) f1="." f2="length"
            emit(((ArrayLength) choice).f0.f0.tokenImage + ".length");

        } else if (choice instanceof MessageSend) {
            emitMessageSend((MessageSend) choice);

        } else if (choice instanceof FieldRead) {
            // f0=obj(Id) f1="." f2=field(Id)
            FieldRead fr = (FieldRead) choice;
            emit(fr.f0.f0.tokenImage + "." + fr.f2.f0.tokenImage);

        } else if (choice instanceof PrimaryExpression) {
            emitPrimary((PrimaryExpression) choice);
        }
    }

    private void emitMessageSend(MessageSend ms) {
        // f0=receiver(PrimaryExpr) f1="." f2=method(Id) f3="(" f4=ArgList? f5=")"
        emitPrimary(ms.f0);
        emit("." + ms.f2.f0.tokenImage + "(");
        if (ms.f4.present()) {
            ArgList al = (ArgList) ms.f4.node;
            emit(constOrId(al.f0.f0.tokenImage));   // first arg
            if (al.f1.present()) {
                for (Enumeration<Node> e = al.f1.elements();
                     e.hasMoreElements();) {
                    ArgRest ar = (ArgRest) e.nextElement();
                    emit(", " + constOrId(ar.f1.f0.tokenImage));
                }
            }
        }
        emit(")");
    }

    private void emitPrimary(PrimaryExpression pe) {
        Node choice = pe.f0.choice;

        if (choice instanceof IntegerLiteral) {
            emit(((IntegerLiteral) choice).f0.tokenImage);
        } else if (choice instanceof TrueLiteral) {
            emit("true");
        } else if (choice instanceof FalseLiteral) {
            emit("false");
        } else if (choice instanceof Identifier) {
            emit(constOrId(((Identifier) choice).f0.tokenImage));
        } else if (choice instanceof ThisExpression) {
            emit("this");
        } else if (choice instanceof ArrayAllocationExpression) {
            // f0="new" f1="int" f2="[" f3=sizeId f4="]"
            ArrayAllocationExpression aae = (ArrayAllocationExpression) choice;
            emit("new int[" + constOrId(aae.f3.f0.tokenImage) + "]");
        } else if (choice instanceof AllocationExpression) {
            // f0="new" f1=className(Id) f2="(" f3=")"
            emit("new " + ((AllocationExpression) choice).f1.f0.tokenImage + "()");
        } else if (choice instanceof NotExpression) {
            // f0="!" f1=id(Id)
            emit("!" + ((NotExpression) choice).f1.f0.tokenImage);
        }
    }

    // ---------------------------------------------------------------
    // Type emitter
    // ---------------------------------------------------------------
    private void emitType(Type t) {
        Node choice = t.f0.choice;
        if      (choice instanceof ArrayType)   emit("int []");
        else if (choice instanceof BooleanType) emit("boolean");
        else if (choice instanceof IntegerType) emit("int");
        else if (choice instanceof Identifier)
            emit(((Identifier) choice).f0.tokenImage);
    }

    // ---------------------------------------------------------------
    // Constant substitution
    // ---------------------------------------------------------------

    /**
     * If the CP result for varName in the current method is a known constant,
     * return the constant's literal string; otherwise return varName.
     * Called at every ConstOrId position in the TACoJava2 output.
     */
    private String constOrId(String varName) {
        if (currentClass == null || currentMethod == null) return varName;
        CPValue val = cp.getIdValue(currentClass, currentMethod, varName);
        if (val.isConst()) return val.toTokenString();
        return varName;
    }

    // ---------------------------------------------------------------
    // Override NodeListOptional to route VarDeclarations normally
    // (Statement lists are handled via emitStatementList instead)
    // ---------------------------------------------------------------
    @Override
    public Object visit(NodeListOptional n, Object argu) {
        if (!n.present()) return null;
        for (Enumeration<Node> e = n.elements(); e.hasMoreElements();)
            e.nextElement().accept(this, argu);
        return null;
    }
}

