package visitor;

import syntaxtree.*;
import java.util.*;

/**
 * Pass 4: Intraprocedural Conditional Constant Propagation.
 *
 * Extended for interprocedural use:
 *   - setParamSummary(cls, method, param, value) lets the interprocedural
 *     pass inject a computed constant for a parameter instead of NAC.
 *   - reAnalyse() re-runs all reachable methods with the current summaries.
 *
 * Straight-line assignments OVERWRITE state (not meet).
 * Meet only at explicit join points (if/while merges).
 */
public class ConstPropVisitor extends GJDepthFirst<Object, Object> {

    private final ClassHierarchyVisitor ch;
    private final SymbolTableVisitor    st;
    private final CallGraphVisitor      cg;

    // ---------------------------------------------------------------
    // Results: per-method variable states at fixpoint
    // ---------------------------------------------------------------
    private final Map<String, Map<String, Map<String, CPValue>>> methodStates
            = new LinkedHashMap<>();

    // ---------------------------------------------------------------
    // Interprocedural parameter summaries
    // "cls::method" -> paramName -> CPValue
    // Default for any absent entry is NAC (unknown).
    // ---------------------------------------------------------------
    private final Map<String, Map<String, CPValue>> paramSummaries
            = new LinkedHashMap<>();

    // ---------------------------------------------------------------
    // Method AST index
    // ---------------------------------------------------------------
    private final Map<String, Map<String, MethodDeclaration>> methodIndex
            = new LinkedHashMap<>();
    private MainClass mainClassNode;

    // ---------------------------------------------------------------
    // Mutable context during analysis
    // ---------------------------------------------------------------
    private String               currentClass;
    private String               currentMethod;
    private Map<String, CPValue> state;

    // ---------------------------------------------------------------
    // Constructor
    // ---------------------------------------------------------------
    public ConstPropVisitor(ClassHierarchyVisitor ch,
                            SymbolTableVisitor    st,
                            CallGraphVisitor      cg) {
        this.ch = ch; this.st = st; this.cg = cg;
    }

    // ---------------------------------------------------------------
    // Public query API
    // ---------------------------------------------------------------

    public CPValue getVarValue(String cls, String method, String varName) {
        Map<String, Map<String, CPValue>> m1 = methodStates.get(cls);
        if (m1 == null) return CPValue.NAC;
        Map<String, CPValue> m2 = m1.get(method);
        if (m2 == null) return CPValue.NAC;
        CPValue v = m2.get(varName);
        return v == null ? CPValue.UNDEF : v;
    }

    public CPValue getIdValue(String cls, String method, String name) {
        String cur = cls;
        while (cur != null) {
            if (st.fieldsOf(cur).containsKey(name)) return CPValue.NAC;
            cur = ch.parentOf(cur);
        }
        return getVarValue(cls, method, name);
    }

    // ---------------------------------------------------------------
    // Interprocedural API
    // ---------------------------------------------------------------

    /**
     * Inject a computed parameter value for interprocedural CP.
     * Called by InterConstPropVisitor after collecting call-site arguments.
     *
     * @param cls     declaring class of the method
     * @param method  method name
     * @param param   parameter name
     * @param value   CPValue computed from all call sites (meet of all args)
     */
    public void setParamSummary(String cls, String method,
                                 String param, CPValue value) {
        paramSummaries.computeIfAbsent(cls + "::" + method,
                                       k -> new LinkedHashMap<>())
                      .put(param, value);
    }

    /**
     * Get the current summary for a parameter (NAC if not yet set).
     */
    public CPValue getParamSummary(String cls, String method, String param) {
        Map<String, CPValue> m = paramSummaries.get(cls + "::" + method);
        return m == null ? CPValue.NAC : m.getOrDefault(param, CPValue.NAC);
    }

    /**
     * Re-run analysis of all reachable methods with current param summaries.
     * Called by InterConstPropVisitor each iteration.
     *
     * @return true if any method state changed (fixpoint not yet reached)
     */
    public boolean reAnalyse() {
        Map<String, Map<String, Map<String, CPValue>>> oldStates = deepCopy(methodStates);
        methodStates.clear();
        for (String key : cg.reachableSet()) {
            String[] p = key.split("::");
            analyseMethod(p[0], p[1]);
        }
        return !methodStates.equals(oldStates);
    }

    // ---------------------------------------------------------------
    // Entry point via Goal (used for initial analysis)
    // ---------------------------------------------------------------

    @Override
    public Object visit(Goal n, Object argu) {
        // Phase 1: index
        n.f0.accept(this, "INDEX");
        n.f1.accept(this, "INDEX");
        // Phase 2: analyse all reachable methods
        for (String key : cg.reachableSet()) {
            String[] p = key.split("::");
            analyseMethod(p[0], p[1]);
        }
        return null;
    }

    // ---------------------------------------------------------------
    // Phase 1: indexing
    // ---------------------------------------------------------------

    @Override public Object visit(MainClass n, Object argu) {
        mainClassNode = n; return null;
    }
    @Override public Object visit(ClassDeclaration n, Object argu) {
        if (!"INDEX".equals(argu)) return null;
        n.f4.accept(this, n.f1.f0.tokenImage); return null;
    }
    @Override public Object visit(ClassExtendsDeclaration n, Object argu) {
        if (!"INDEX".equals(argu)) return null;
        n.f6.accept(this, n.f1.f0.tokenImage); return null;
    }
    @Override public Object visit(MethodDeclaration n, Object argu) {
        if (!(argu instanceof String)) return null;
        methodIndex.computeIfAbsent((String)argu, k -> new LinkedHashMap<>())
                   .put(n.f2.f0.tokenImage, n);
        return null;
    }

    // ---------------------------------------------------------------
    // Phase 2: per-method fixpoint analysis
    // ---------------------------------------------------------------

    private void analyseMethod(String cls, String method) {
        currentClass  = cls;
        currentMethod = method;
        state         = new LinkedHashMap<>();

        if ("main".equals(method)) {
            for (String local : st.localsOf(cls, method).keySet())
                state.put(local, CPValue.UNDEF);
            runFixpoint(mainClassNode.f15);
        } else {
            MethodDeclaration md = lookupMethod(cls, method);
            if (md == null) { currentClass = null; currentMethod = null; return; }

            // Parameters: use interprocedural summary if available, else NAC
            for (String param : st.paramsOf(cls, method))
                state.put(param, getParamSummary(cls, method, param));

            // Locals: UNDEF
            for (String local : st.localsOf(cls, method).keySet())
                if (!state.containsKey(local))
                    state.put(local, CPValue.UNDEF);

            runFixpoint(md.f8);
        }

        methodStates.computeIfAbsent(cls, k -> new LinkedHashMap<>())
                    .put(method, new LinkedHashMap<>(state));
        currentClass = null; currentMethod = null; state = null;
    }

    private void runFixpoint(NodeListOptional stmts) {
        boolean changed = true;
        while (changed) {
            Map<String, CPValue> before = new LinkedHashMap<>(state);
            runStatements(stmts);
            changed = !state.equals(before);
        }
    }

    private void runStatements(NodeListOptional stmts) {
        if (!stmts.present()) return;
        for (Enumeration<Node> e = stmts.elements(); e.hasMoreElements();)
            e.nextElement().accept(this, null);
    }

    // ---------------------------------------------------------------
    // Statement visitors
    // ---------------------------------------------------------------

    @Override
    public Object visit(AssignmentStatement n, Object argu) {
        String lhs = n.f0.f0.tokenImage;
        if (!isField(lhs))
            state.put(lhs, evalExpression(n.f2));
        return null;
    }

    @Override public Object visit(ArrayAssignmentStatement n, Object argu) { return null; }
    @Override public Object visit(FieldAssignmentStatement n, Object argu)  { return null; }
    @Override public Object visit(PrintStatement n, Object argu)            { return null; }

    @Override
    public Object visit(Block n, Object argu) {
        runStatements(n.f1); return null;
    }

    @Override
    public Object visit(IfStatement n, Object argu) {
        String  condName = n.f2.f0.tokenImage;
        CPValue condVal  = lookupVar(condName);

        if (condVal.isTrue()) {
            n.f4.accept(this, argu);
        } else if (condVal.isFalse()) {
            n.f6.accept(this, argu);
        } else {
            Map<String, CPValue> snap = new LinkedHashMap<>(state);
            n.f4.accept(this, argu);
            Map<String, CPValue> afterThen = new LinkedHashMap<>(state);
            state = new LinkedHashMap<>(snap);
            n.f6.accept(this, argu);
