import syntaxtree.*;
import visitor.*;
import java.util.*;

public class P3Debug {
    public static void main(String[] args) throws Exception {

        Goal root = new TACoJavaParser(System.in).Goal();

        ClassHierarchyVisitor ch = new ClassHierarchyVisitor();
        root.accept(ch, null);
        System.err.println("=== Class Hierarchy ===");
        for (String cls : ch.classNames())
            System.err.println("  " + cls + " parent=" + ch.parentOf(cls)
                    + " methods=" + ch.methodsOf(cls));

        SymbolTableVisitor st = new SymbolTableVisitor(ch);
        root.accept(st, null);
        System.err.println("\n=== Symbol Table (main locals) ===");
        String mainCls = root.f0.f1.f0.tokenImage;
        System.err.println("  Main locals: " + st.localsOf(mainCls, "main"));
        System.err.println("  A.live params: " + st.paramsOf("A", "live"));
        System.err.println("  A.live locals: " + st.localsOf("A", "live"));

        CallGraphVisitor cg = new CallGraphVisitor(ch, st, mainCls);
        root.accept(cg, null);
        System.err.println("\n=== Call Graph Reachable ===");
        for (String k : cg.reachableSet()) System.err.println("  " + k);

        // Initial CP
        ConstPropVisitor cpv = new ConstPropVisitor(ch, st, cg);
        root.accept(cpv, null);
        System.err.println("\n=== After Initial CP ===");
        System.err.println("  Main::main result=" + cpv.getVarValue(mainCls, "main", "result"));
        System.err.println("  Main::main obj="    + cpv.getVarValue(mainCls, "main", "obj"));
        System.err.println("  Main::main b="      + cpv.getVarValue(mainCls, "main", "b"));
        System.err.println("  A::live x="  + cpv.getVarValue("A", "live", "x"));
        System.err.println("  A::live k="  + cpv.getVarValue("A", "live", "k"));
        System.err.println("  A::live r="  + cpv.getVarValue("A", "live", "r"));
        System.err.println("  getReturnValue(A,live)=" + cpv.getReturnValue("A", "live"));

        // Interprocedural CP
        InterConstPropVisitor icp = new InterConstPropVisitor(ch, st, cg, cpv);
        icp.run(root);
        System.err.println("\n=== After Interprocedural CP ===");
        System.err.println("  Main::main result=" + cpv.getVarValue(mainCls, "main", "result"));
        System.err.println("  Main::main obj="    + cpv.getVarValue(mainCls, "main", "obj"));
        System.err.println("  Main::main b="      + cpv.getVarValue(mainCls, "main", "b"));
        System.err.println("  A::live x="  + cpv.getVarValue("A", "live", "x"));
        System.err.println("  A::live r="  + cpv.getVarValue("A", "live", "r"));
        System.err.println("  getReturnValue(A,live)=" + cpv.getReturnValue("A", "live"));
        System.err.println("  getIdValue(Main,main,result)=" + cpv.getIdValue(mainCls, "main", "result"));
        System.err.println("  getIdValue(Main,main,obj)="    + cpv.getIdValue(mainCls, "main", "obj"));
        System.err.println("  A::live hasSideEffects=" + cpv.methodHasSideEffects("A", "live"));

        // Dead code
        DeadCodeVisitor dc = new DeadCodeVisitor(ch, st, cg, cpv);
        root.accept(dc, null);
        System.err.println("\n=== Dead Code ===");
        System.err.println("  isDeadMethod(A,live)=" + dc.isDeadMethod("A", "live"));
        System.err.println("  isDeadMethod(A,dead)=" + dc.isDeadMethod("A", "dead"));
        System.err.println("  isDeadVarDecl(Main,main,result)=" + dc.isDeadVarDecl(mainCls, "main", "result"));
        System.err.println("  isDeadVarDecl(Main,main,obj)="    + dc.isDeadVarDecl(mainCls, "main", "obj"));
        System.err.println("  isDeadVarDecl(Main,main,b)="      + dc.isDeadVarDecl(mainCls, "main", "b"));

        // Code gen
        System.err.println("\n=== Output ===");
        CodeGenVisitor gen = new CodeGenVisitor(ch, st, cpv, dc);
        root.accept(gen, null);
        gen.flush();
    }
}

