new = '''    private void markDeadMethods() {
        // First pass: mark unreachable methods dead.
        for (String cls : ch.classNames())
            for (String method : ch.methodsOf(cls))
                if (!cg.reachable(cls, method))
                    deadMethods.add(cls + \"::\" + method);

        // Second pass: mark reachable methods dead only if the ENTIRE
        // CHA dispatch group (root declaring class + all overrides) returns
        // the same constant and has no side effects.
        //
        // We must check the group as a whole, not each method individually.
        // Eliminating B.foo while A.foo is alive is wrong — a call to
        // object.foo() (object:A) could dispatch to B.foo at runtime.
        //
        // Strategy: for each method name, find all root dispatch types
        // (classes that are NOT subclasses of another class declaring the
        // same method — i.e. the topmost declarer). For each root, use
        // getReturnValue(root, method) which already does full CHA expansion.
        // If that returns CONST and no target has side effects -> dead group.

        // Collect all (cls, method) pairs that are reachable
        Set<String> reachableMethods = new LinkedHashSet<>();
        for (String cls : ch.classNames())
            for (String method : ch.methodsOf(cls))
                if (cg.reachable(cls, method))
                    reachableMethods.add(cls + \"::\" + method);

        // For each reachable method, check if its FULL dispatch group is
        // constant. Use the receiver type = declaring class itself (getReturnValue
        // expands to all subclasses automatically).
        for (String key : reachableMethods) {
            String[] p   = key.split(\"::\");
            String   cls = p[0], method = p[1];

            // Find the topmost class in the hierarchy that declares this method.
            // This is the \"dispatch root\" — the type whose subclasses CHA expands.
            String dispatchRoot = cls;
            String parent = ch.parentOf(cls);
            while (parent != null) {
                if (ch.declaringClass(parent, method) != null)
                    dispatchRoot = parent;
                parent = ch.parentOf(parent);
            }

            // Only process from the dispatch root to avoid redundant checks
            if (!dispatchRoot.equals(cls)) continue;

