package visitor;

import syntaxtree.*;
import java.util.*;

/**
 * Pass 3: Call Graph construction via Class Hierarchy Analysis (CHA).
 *
 * CHA resolution rule for a call x.foo(args) where x has declared type T:
 * - Include T.foo if T (or an ancestor) declares foo
 * - Include C.foo for every strict subclass C of T (transitively) that
 * inherits or declares foo
 *
 * Algorithm (worklist):
 * 1. Seed worklist with (mainClassName, "main")
 * 2. For each reachable (class, method), collect all MessageSend nodes
 * in its body
 * 3. CHA-resolve each call site -> add newly found callees to worklist
 * 4. Repeat until fixpoint
 *
 * After visiting the Goal node, use reachable(className, methodName)
 * to test liveness.
 */
public class CallGraph extends GJDepthFirst {

  private final ClassHierarchy ch;
  private final SymbolTable st;
  private final String mainClassName;

  // ---------------------------------------------------------------
  // Phase 1 index: className -> methodName -> MethodDeclaration node
  // ---------------------------------------------------------------
  private final Map<String, Map<String, MethodDeclaration>> methodIndex = new LinkedHashMap<>();

  // Captured during indexing for scanning main's statements
  private MainClass mainClassNode = null;

  // ---------------------------------------------------------------
  // Reachable set (stored as "ClassName::methodName" strings)
  // ---------------------------------------------------------------
  private final Set<String> reachableKeys = new LinkedHashSet<>();

  // ---------------------------------------------------------------
  // Constructor
  // ---------------------------------------------------------------
  public CallGraph(ClassHierarchy ch,
      SymbolTable st,
      String mainClassName) {
    this.ch = ch;
    this.st = st;
    this.mainClassName = mainClassName;
  }

  // ---------------------------------------------------------------
  // Public query API
  // ---------------------------------------------------------------

  /** Is (className, methodName) reachable from main? */
  public boolean reachable(String className, String methodName) {
    return reachableKeys.contains(key(className, methodName));
  }

  /** Full reachable set as unmodifiable "ClassName::methodName" strings. */
  public Set<String> reachableSet() {
    return Collections.unmodifiableSet(reachableKeys);
  }

  // ---------------------------------------------------------------
  // Two-phase entry point via Goal
  // ---------------------------------------------------------------

  /**
   * f0 -> MainClass()
   * f1 -> ( TypeDeclaration() )*
   * f2 -> <EOF>
   */
  @Override
  public Object visit(Goal n, Object argu) {
    // Phase 1: index all method AST nodes & capture mainClassNode
    n.f0.accept(this, "INDEX");
    n.f1.accept(this, "INDEX");

    // Phase 2: worklist propagation
    propagate();
    return null;
  }

  // ---------------------------------------------------------------
  // Phase 1 visitors — argu == "INDEX"
  // ---------------------------------------------------------------

  /** Capture the MainClass node so we can scan its statements later. */
  @Override
  public Object visit(MainClass n, Object argu) {
    mainClassNode = n;
    return null;
  }

  /**
   * f0 -> "class"
   * f1 -> Identifier()
   * f2 -> "{"
   * f3 -> ( VarDeclaration() )*
   * f4 -> ( MethodDeclaration() )*
   * f5 -> "}"
   */
  @Override
  public Object visit(ClassDeclaration n, Object argu) {
    if (!"INDEX".equals(argu))
      return null;
    String className = n.f1.f0.tokenImage;
    n.f4.accept(this, className);
    return null;
  }

  /**
   * f0 -> "class"
   * f1 -> Identifier()
   * f2 -> "extends"
   * f3 -> Identifier()
   * f4 -> "{"
   * f5 -> ( VarDeclaration() )*
   * f6 -> ( MethodDeclaration() )*
   * f7 -> "}"
   */
  @Override
  public Object visit(ClassExtendsDeclaration n, Object argu) {
    if (!"INDEX".equals(argu))
      return null;
    String className = n.f1.f0.tokenImage;
    n.f6.accept(this, className);
    return null;
  }

  /**
   * Index this node under (className, methodName).
   * argu = enclosing class name (String) during indexing.
   *
   * f0 -> "public"
   * f1 -> Type()
   * f2 -> Identifier() <- method name
   * f3 -> "("
   * f4 -> ( FormalParameterList() )?
   * f5 -> ")"
   * f6 -> "{"
   * f7 -> ( VarDeclaration() )*
   * f8 -> ( Statement() )*
   * f9 -> "return"
   * f10 -> Identifier()
   * f11 -> ";"
   * f12 -> "}"
   */
  @Override
  public Object visit(MethodDeclaration n, Object argu) {
    if (!(argu instanceof String))
      return null;
    String className = (String) argu;
    String methodName = n.f2.f0.tokenImage;
    methodIndex.computeIfAbsent(className, k -> new LinkedHashMap<>())
        .put(methodName, n);
    return null;
  }

  // ---------------------------------------------------------------
  // Phase 2: worklist propagation
  // ---------------------------------------------------------------

  private void propagate() {
    Deque<String[]> worklist = new ArrayDeque<>();

    // Seed with the main method
    worklist.add(new String[] { mainClassName, "main" });

    while (!worklist.isEmpty()) {
      String[] entry = worklist.poll();
      String cls = entry[0];
      String method = entry[1];

      if (!reachableKeys.add(key(cls, method)))
        continue; // already seen

      // Collect all MessageSend nodes in this method's body
      List<MessageSend> calls = collectCalls(cls, method);

      // CHA-resolve each call and enqueue newly discovered callees
      for (MessageSend ms : calls) {
        String calledMethod = ms.f2.f0.tokenImage;
        String receiverType = resolveReceiverType(ms, cls, method);
        if (receiverType == null)
          continue; // unresolvable — skip

        // CHA: declared type + all transitive subclasses
        Set<String> candidates = new LinkedHashSet<>();
        candidates.add(receiverType);
        candidates.addAll(ch.allSubclasses(receiverType));

        for (String candidate : candidates) {
          String declaringCls = ch.declaringClass(candidate, calledMethod);
          if (declaringCls != null) {
            String k = key(declaringCls, calledMethod);
            if (!reachableKeys.contains(k)) {
              worklist.add(new String[] { declaringCls, calledMethod });
            }
          }
        }
      }
    }
  }

  // ---------------------------------------------------------------
  // Collect MessageSend nodes from a method's body
  // ---------------------------------------------------------------

  private List<MessageSend> collectCalls(String cls, String method) {
    List<MessageSend> out = new ArrayList<>();
    MessageSendCollector collector = new MessageSendCollector();

    if ("main".equals(method) && mainClassNode != null) {
      // f15 = ( Statement() )* in MainClass
      mainClassNode.f15.accept(collector, out);
    } else {
      MethodDeclaration md = lookupMethod(cls, method);
      if (md != null) {
        // f8 = ( Statement() )* in MethodDeclaration
        md.f8.accept(collector, out);
      }
    }
    return out;
  }

  // ---------------------------------------------------------------
  // CHA receiver type resolution
  // ---------------------------------------------------------------

  /**
   * Determine the DECLARED static type of the receiver in a MessageSend.
   *
   * TACoJava MessageSend:
   * PrimaryExpression "." Identifier "(" ArgList? ")"
   *
   * PrimaryExpression choices (f0.choice):
   * IntegerLiteral | TrueLiteral | FalseLiteral | Identifier
   * | ThisExpression | ArrayAllocationExpression
   * | AllocationExpression | NotExpression
   *
   * Resolvable:
   * Identifier -> symbol table lookup
   * ThisExpression -> enclosing class
   * AllocationExpression -> the allocated class name
   *
   * Everything else -> null (conservatively skip).
   */
  private String resolveReceiverType(MessageSend ms,
      String enclosingClass,
      String enclosingMethod) {
    // ms.f0 is PrimaryExpression; .f0 is NodeChoice
    Node choice = ms.f0.f0.choice;

    if (choice instanceof Identifier) {
      String varName = ((Identifier) choice).f0.tokenImage;
      return st.typeOf(enclosingClass, enclosingMethod, varName);
    }
    if (choice instanceof ThisExpression) {
      return enclosingClass;
    }
    if (choice instanceof AllocationExpression) {
      // new Foo() -- type is Foo
      return ((AllocationExpression) choice).f1.f0.tokenImage;
    }
    return null;
  }

  // ---------------------------------------------------------------
  // Utility
  // ---------------------------------------------------------------

  /**
   * Find the MethodDeclaration for (className, methodName), walking up
   * the inheritance chain if needed.
   */
  private MethodDeclaration lookupMethod(String className, String methodName) {
    String cur = className;
    while (cur != null) {
      Map<String, MethodDeclaration> m = methodIndex.get(cur);
      if (m != null && m.containsKey(methodName))
        return m.get(methodName);
      cur = ch.parentOf(cur);
    }
    return null;
  }

  private static String key(String cls, String method) {
    return cls + "::" + method;
  }

  // ---------------------------------------------------------------
  // Inner helper: depth-first collector of MessageSend nodes
  // ---------------------------------------------------------------
  private static class MessageSendCollector extends GJDepthFirst {

    @SuppressWarnings("unchecked")
    @Override
    public Object visit(MessageSend n, Object argu) {
      ((List<MessageSend>) argu).add(n);
      // Visit args too (TACoJava args are plain Identifiers,
      // but visit for completeness / future-proofing)
      n.f4.accept(this, argu);
      return null;
    }
  }
}

package visitor;

import syntaxtree.*;
import java.util.*;

/**
 * Pass 1: Builds the class hierarchy.
 *
 * After visiting the AST, provides:
 * parentOf(C) -> direct parent class name, or null if none
 * childrenOf(C) -> direct subclass names
 * allSubclasses(C) -> transitive subclass names (computed on demand)
 * methodsOf(C) -> method names declared directly in C
 * allMethodsOf(C) -> method names declared in C or any ancestor
 * classNames() -> all class names (including main class)
 *
 * Usage:
 * ClassHierarchyVisitor ch = new ClassHierarchyVisitor();
 * goal.accept(ch, null);
 */
public class ClassHierarchy extends GJDepthFirst {

    // ---------------------------------------------------------------
    // Internal tables (populated during visiting)
    // ---------------------------------------------------------------

    /** Maps class name -> direct parent name (null if no extends) */
    private final Map<String, String> parentOf = new LinkedHashMap<>();

    /** Maps class name -> set of direct child class names */
    private final Map<String, Set<String>> childrenOf = new LinkedHashMap<>();

    /** Maps class name -> set of method names declared IN that class */
    private final Map<String, Set<String>> methodsOf = new LinkedHashMap<>();

    // ---------------------------------------------------------------
    // Public query API
    // ---------------------------------------------------------------

    /** All known class names (including the main class). */
    public Set<String> classNames() {
        return Collections.unmodifiableSet(parentOf.keySet());
    }

    /** Direct parent of C, or null. */
    public String parentOf(String className) {
        return parentOf.get(className);
    }

    /** Direct children of C (may be empty). */
    public Set<String> childrenOf(String className) {
        return childrenOf.getOrDefault(className, Collections.emptySet());
    }

    /** Methods declared directly in C (may be empty). */
    public Set<String> methodsOf(String className) {
        return methodsOf.getOrDefault(className, Collections.emptySet());
    }

    /**
     * All transitive subclasses of C (not including C itself).
     * Computed by BFS over childrenOf.
     */
    public Set<String> allSubclasses(String className) {
        Set<String> result = new LinkedHashSet<>();
        Queue<String> worklist = new LinkedList<>();
        worklist.addAll(childrenOf(className));
        while (!worklist.isEmpty()) {
            String c = worklist.poll();
            if (result.add(c)) { // if newly added
                worklist.addAll(childrenOf(c));
            }
        }
        return result;
    }

    /**
     * All method names visible in C: own methods UNION inherited methods
     * (walking up the parent chain).
     */
    public Set<String> allMethodsOf(String className) {
        Set<String> result = new LinkedHashSet<>();
        String cur = className;
        while (cur != null) {
            result.addAll(methodsOf(cur));
            cur = parentOf(cur);
        }
        return result;
    }

    /**
     * Returns true if className declares (directly) a method named methodName.
     */
    public boolean declaresMethod(String className, String methodName) {
        return methodsOf(className).contains(methodName);
    }

    /**
     * Finds the class in C's hierarchy (C itself or an ancestor) that
     * actually declares methodName. Returns null if not found.
     */
    public String declaringClass(String className, String methodName) {
        String cur = className;
        while (cur != null) {
            if (declaresMethod(cur, methodName))
                return cur;
            cur = parentOf(cur);
        }
        return null;
    }

    // ---------------------------------------------------------------
    // Visitor methods
    // ---------------------------------------------------------------

    /**
     * f0 -> "class"
     * f1 -> Identifier() <- class name
     * f2 -> "{"
     * f3 -> ( VarDeclaration() )*
     * f4 -> ( MethodDeclaration() )*
     * f5 -> "}"
     */
    @Override
    public Object visit(ClassDeclaration n, Object argu) {
        String name = n.f1.f0.tokenImage;
        registerClass(name, null);
        // Visit method declarations, passing the class name down
        n.f4.accept(this, name);
        return null;
    }

    /**
     * f0 -> "class"
     * f1 -> Identifier() <- class name
     * f2 -> "extends"
     * f3 -> Identifier() <- parent name
     * f4 -> "{"
     * f5 -> ( VarDeclaration() )*
     * f6 -> ( MethodDeclaration() )*
     * f7 -> "}"
     */
    @Override
    public Object visit(ClassExtendsDeclaration n, Object argu) {
        String name = n.f1.f0.tokenImage;
        String parent = n.f3.f0.tokenImage;
        registerClass(name, parent);
        // Record child link
        childrenOf.computeIfAbsent(parent, k -> new LinkedHashSet<>()).add(name);
        // Visit method declarations
        n.f6.accept(this, name);
        return null;
    }

    /**
     * f0 -> "class"
     * f1 -> Identifier() <- main class name
     * ...
     * We register the main class so it shows up in classNames().
     */
    @Override
    public Object visit(MainClass n, Object argu) {
        String name = n.f1.f0.tokenImage;
        registerClass(name, null);
        // main class has no ordinary methods, so nothing more to do
        return null;
    }

    /**
     * f0 -> "public"
     * f1 -> Type()
     * f2 -> Identifier() <- method name
     * f3 -> "("
     * ...
     * argu = enclosing class name (String)
     */
    @Override
    public Object visit(MethodDeclaration n, Object argu) {
        String className = (String) argu;
        String methodName = n.f2.f0.tokenImage;
        methodsOf.computeIfAbsent(className, k -> new LinkedHashSet<>()).add(methodName);
        return null;
    }

    // ---------------------------------------------------------------
    // Helpers
    // ---------------------------------------------------------------

    private void registerClass(String name, String parent) {
        parentOf.put(name, parent); // parent may be null
        // Ensure entries exist even if no children / methods are added later
        childrenOf.computeIfAbsent(name, k -> new LinkedHashSet<>());
        methodsOf.computeIfAbsent(name, k -> new LinkedHashSet<>());
    }
}

package visitor;

/**
 * Constant Propagation Lattice Value.
 *
 * Three-level lattice (per variable):
 *
 * NAC (Not A Constant — value is unknown / varies)
 * / | \
 * CONST(v) (known constant: an integer or boolean)
 * \ | /
 * UNDEF (bottom — variable not yet assigned on any path)
 *
 * Meet rule:
 * UNDEF meet x = x
 * x meet UNDEF = x
 * CONST(v) meet CONST(v) = CONST(v)
 * CONST(v) meet CONST(w) = NAC (v != w)
 * NAC meet x = NAC
 * x meet NAC = NAC
 */
public class CPValue {

    // ---------------------------------------------------------------
    // Kind enum
    // ---------------------------------------------------------------
    public enum Kind {
        UNDEF, CONST, NAC
    }

    // ---------------------------------------------------------------
    // Singleton constants
    // ---------------------------------------------------------------
    public static final CPValue UNDEF = new CPValue(Kind.UNDEF, null);
    public static final CPValue NAC = new CPValue(Kind.NAC, null);
    public static final CPValue TRUE_VAL = new CPValue(Kind.CONST, Boolean.TRUE);
    public static final CPValue FALSE_VAL = new CPValue(Kind.CONST, Boolean.FALSE);

    // ---------------------------------------------------------------
    // Fields
    // ---------------------------------------------------------------
    public final Kind kind;
    /** Non-null iff kind == CONST. Either an Integer or a Boolean. */
    public final Object value;

    // ---------------------------------------------------------------
    // Constructors / factories
    // ---------------------------------------------------------------
    private CPValue(Kind kind, Object value) {
        this.kind = kind;
        this.value = value;
    }

    /** Factory for integer constants. */
    public static CPValue ofInt(int v) {
        return new CPValue(Kind.CONST, v);
    }

    /** Factory for boolean constants. */
    public static CPValue ofBool(boolean v) {
        return v ? TRUE_VAL : FALSE_VAL;
    }

    // ---------------------------------------------------------------
    // Lattice meet operation
    // ---------------------------------------------------------------
    public static CPValue meet(CPValue a, CPValue b) {
        // UNDEF is bottom — it contributes nothing
        if (a.kind == Kind.UNDEF)
            return b;
        if (b.kind == Kind.UNDEF)
            return a;
        // NAC dominates everything
        if (a.kind == Kind.NAC || b.kind == Kind.NAC)
            return NAC;
        // Both CONST
        assert a.kind == Kind.CONST && b.kind == Kind.CONST;
        if (a.value.equals(b.value))
            return a;
        return NAC;
    }

    // ---------------------------------------------------------------
    // Convenience predicates
    // ---------------------------------------------------------------
    public boolean isConst() {
        return kind == Kind.CONST;
    }

    public boolean isNAC() {
        return kind == Kind.NAC;
    }

    public boolean isUndef() {
        return kind == Kind.UNDEF;
    }

    public boolean isTrue() {
        return isConst() && Boolean.TRUE.equals(value);
    }

    public boolean isFalse() {
        return isConst() && Boolean.FALSE.equals(value);
    }

    public boolean isBool() {
        return isConst() && value instanceof Boolean;
    }

    public boolean isInt() {
        return isConst() && value instanceof Integer;
    }

    public int intValue() {
        return (Integer) value;
    }

    public boolean boolValue() {
        return (Boolean) value;
    }

    // ---------------------------------------------------------------
    // Emit as TACoJava2 token string
    // ---------------------------------------------------------------
    /**
     * Returns the literal string to emit in the output program,
     * e.g. "42", "-3", "true", "false".
     * Only call this when isConst() == true.
     */
    public String toTokenString() {
        if (value instanceof Boolean)
            return (Boolean) value ? "true" : "false";
        int v = (Integer) value;
        // Negative integers need the minus sign
        return Integer.toString(v);
    }

    // ---------------------------------------------------------------
    // Object overrides
    // ---------------------------------------------------------------
    @Override
    public boolean equals(Object o) {
        if (this == o)
            return true;
        if (!(o instanceof CPValue))
            return false;
        CPValue other = (CPValue) o;
        if (kind != other.kind)
            return false;
        if (value == null)
            return other.value == null;
        return value.equals(other.value);
    }

    @Override
    public int hashCode() {
        return kind.hashCode() * 31 + (value == null ? 0 : value.hashCode());
    }

    @Override
    public String toString() {
        switch (kind) {
            case UNDEF:
                return "UNDEF";
            case NAC:
                return "NAC";
            default:
                return "CONST(" + value + ")";
        }
    }
}

package visitor;

import syntaxtree.*;
import java.util.*;

/**
 * Interprocedural Constant Propagation (context-insensitive).
 *
 * KEY FIX: analyses methods in reverse-call order (callees before callers)
 * so that when main is analysed, live's return value is already in
 * methodStates. This ensures evalMessageSend folds correctly in a single
 * reAnalyse pass.
 *
 * Algorithm:
 * 1. Build call-site index (once).
 * 2. Compute topological order of methods (callees first).
 * 3. Loop:
 * a. Collect argument CPValues at every call site -> meet into param summaries.
 * b. Re-analyse all methods IN TOPOLOGICAL ORDER with updated summaries.
 * c. Repeat until no state changes.
 */
public class InterConstPropVisitor {

    private final ClassHierarchy ch;
    private final SymbolTable st;
    private final CallGraph cg;
    private final ConstPropVisitor cpv;

    // callerKey -> list of MessageSend nodes in that method
    private final Map<String, List<MessageSend>> callSiteIndex = new LinkedHashMap<>();

    // Topological order: callees before callers
    private List<String> topoOrder = new ArrayList<>();

    public InterConstPropVisitor(ClassHierarchy ch,
            SymbolTable st,
            CallGraph cg,
            ConstPropVisitor cpv) {
        this.ch = ch;
        this.st = st;
        this.cg = cg;
        this.cpv = cpv;
    }

    // ---------------------------------------------------------------
    // Main entry point
    // ---------------------------------------------------------------

    public void run(Goal goal) {
        buildCallSiteIndex(goal);
        buildTopoOrder();

        boolean changed = true;
        while (changed) {
            collectAndInjectArguments();
            changed = cpv.reAnalyseInOrder(topoOrder);
        }
    }

    // ---------------------------------------------------------------
    // Build call-site index: one list of MessageSend per reachable method
    // ---------------------------------------------------------------

    private void buildCallSiteIndex(Goal goal) {
        MessageSendCollector collector = new MessageSendCollector();
        MainClass mainNode = cpv.mainClassNode();

        for (String key : cg.reachableSet()) {
            String[] p = key.split("::");
            String cls = p[0], method = p[1];
            List<MessageSend> calls = new ArrayList<>();

            if ("main".equals(method) && mainNode != null) {
                mainNode.f15.accept(collector, calls);
            } else {
                MethodDeclaration md = lookupMD(cls, method);
                if (md != null)
                    md.f8.accept(collector, calls);
            }
            callSiteIndex.put(key, calls);
        }
    }

    // ---------------------------------------------------------------
    // Topological sort: callees appear before callers in the list.
    //
    // We reverse-DFS the call graph: start from leaves (methods that
    // call nothing), work up to callers. Cycles (mutual recursion) are
    // broken by the existing meet-based fixpoint — we just pick any order.
    // ---------------------------------------------------------------

    private void buildTopoOrder() {
        // Build adjacency: caller -> set of callees (reachable keys)
        Map<String, Set<String>> callees = new LinkedHashMap<>();
        for (String callerKey : cg.reachableSet()) {
            Set<String> targets = new LinkedHashSet<>();
            List<MessageSend> calls = callSiteIndex.getOrDefault(
                    callerKey, Collections.emptyList());
            String[] cp2 = callerKey.split("::");
            String callerCls = cp2[0], callerMeth = cp2[1];

            for (MessageSend ms : calls) {
                String methodName = ms.f2.f0.tokenImage;
                String receiverType = resolveReceiverType(ms, callerCls, callerMeth);
                if (receiverType == null)
                    continue;

                Set<String> candidates = new LinkedHashSet<>();
                candidates.add(receiverType);
                candidates.addAll(ch.allSubclasses(receiverType));
                for (String candidate : candidates) {
                    String dc = ch.declaringClass(candidate, methodName);
                    if (dc != null && cg.reachable(dc, methodName))
                        targets.add(dc + "::" + methodName);
                }
            }
            callees.put(callerKey, targets);
        }

        // Post-order DFS (callees visited before callers in result)
        Set<String> visited = new LinkedHashSet<>();
        List<String> result = new ArrayList<>();
        for (String key : cg.reachableSet())
            dfs(key, callees, visited, result);

        // result is post-order: callees come AFTER callers in DFS post-order.
        // We want callees FIRST, so reverse it.
        // Collections.reverse(result);
        topoOrder = result;
    }

    private void dfs(String key, Map<String, Set<String>> callees,
            Set<String> visited, List<String> result) {
        if (!visited.add(key))
            return;
        for (String callee : callees.getOrDefault(key, Collections.emptySet()))
            dfs(callee, callees, visited, result);
        result.add(key);
    }

    // ---------------------------------------------------------------
    // Collect argument values from call sites -> inject into param summaries
    // ---------------------------------------------------------------

    private void collectAndInjectArguments() {
        Map<String, Map<String, CPValue>> newSummaries = new LinkedHashMap<>();

        for (Map.Entry<String, List<MessageSend>> entry : callSiteIndex.entrySet()) {
            String[] callerParts = entry.getKey().split("::");
            String callerCls = callerParts[0], callerMeth = callerParts[1];
            List<MessageSend> calls = entry.getValue();
            if (calls.isEmpty())
                continue;

            // KEY FIX: get arg values at the exact point each call executes,
            // not from the final post-fixpoint state
            Map<MessageSend, List<CPValue>> argValuesAtSite = cpv.collectCallSiteArgValues(callerCls, callerMeth,
                    calls);

            for (MessageSend ms : calls) {
                String calledMethod = ms.f2.f0.tokenImage;
                String receiverType = resolveReceiverType(ms, callerCls, callerMeth);
                if (receiverType == null)
                    continue;

                List<CPValue> argVals = argValuesAtSite.getOrDefault(
                        ms, Collections.emptyList());

                Set<String> candidates = new LinkedHashSet<>();
                candidates.add(receiverType);
                candidates.addAll(ch.allSubclasses(receiverType));

                for (String candidate : candidates) {
                    String declaringCls = ch.declaringClass(candidate, calledMethod);
                    if (declaringCls == null || !cg.reachable(declaringCls, calledMethod))
                        continue;
                    List<String> params = st.paramsOf(declaringCls, calledMethod);
                    String summaryKey = declaringCls + "::" + calledMethod;
                    Map<String, CPValue> summary = newSummaries.computeIfAbsent(
                            summaryKey, k -> new LinkedHashMap<>());
                    for (int i = 0; i < Math.min(params.size(), argVals.size()); i++) {
                        CPValue existing = summary.getOrDefault(params.get(i), CPValue.UNDEF);
                        summary.put(params.get(i), CPValue.meet(existing, argVals.get(i)));
                    }
                }
            }
        }

        // Inject: methods with no observed call sites get NAC for all params
        for (String key : cg.reachableSet()) {
            String[] p = key.split("::");
            String cls = p[0], method = p[1];
            List<String> params = st.paramsOf(cls, method);
            if (params.isEmpty())
                continue;
            Map<String, CPValue> summary = newSummaries.get(key);
            for (String param : params) {
                CPValue val = (summary == null || !summary.containsKey(param))
                        ? CPValue.NAC
                        : summary.get(param);
                if (val.isUndef())
                    val = CPValue.NAC;
                cpv.setParamSummary(cls, method, param, val);
            }
        }
    }

    // ---------------------------------------------------------------
    // Evaluate argument identifiers from caller's current CP state
    // ---------------------------------------------------------------

    // private List<CPValue> evaluateArgs(MessageSend ms,
    // String callerCls, String callerMeth) {
    // List<CPValue> vals = new ArrayList<>();
    // if (!ms.f4.present())
    // return vals;
    // ArgList al = (ArgList) ms.f4.node;
    // vals.add(cpv.lookupVarInMethod(callerCls, callerMeth, al.f0.f0.tokenImage));
    // if (al.f1.present())
    // for (Enumeration<Node> e = al.f1.elements(); e.hasMoreElements();) {
    // ArgRest ar = (ArgRest) e.nextElement();
    // vals.add(cpv.lookupVarInMethod(callerCls, callerMeth, ar.f1.f0.tokenImage));
    // }
    // return vals;
    // }

    // ---------------------------------------------------------------
    // Receiver type resolution
    // ---------------------------------------------------------------

    private String resolveReceiverType(MessageSend ms, String cls, String method) {
        Node choice = ms.f0.f0.choice;
        if (choice instanceof Identifier)
            return st.typeOf(cls, method, ((Identifier) choice).f0.tokenImage);
        if (choice instanceof ThisExpression)
            return cls;
        if (choice instanceof AllocationExpression)
            return ((AllocationExpression) choice).f1.f0.tokenImage;
        return null;
    }

    private MethodDeclaration lookupMD(String cls, String method) {
        String cur = cls;
        while (cur != null) {
            Map<String, MethodDeclaration> m = cpv.methodIndex().get(cur);
            if (m != null && m.containsKey(method))
                return m.get(method);
            cur = ch.parentOf(cur);
        }
        return null;
    }

    private static class MessageSendCollector extends GJDepthFirst {
        @SuppressWarnings("unchecked")
        @Override
        public Object visit(MessageSend n, Object argu) {
            ((List<MessageSend>) argu).add(n);
            n.f4.accept(this, argu);
            return null;
        }
    }
}

package visitor;

import syntaxtree.*;
import java.util.*;

/**
 * Pass 2: Builds the symbol table.
 *
 * For each class and method, records the declared type of every
 * field, parameter, and local variable. Also records the return
 * type of every method.
 *
 * After visiting the AST call the query methods below to look up types.
 *
 * Key scoping rule used throughout the compiler:
 * Local lookup order: local vars → params → fields of enclosing class
 * → fields of ancestor classes (via hierarchy).
 *
 * Usage:
 * SymbolTableVisitor st = new SymbolTableVisitor(classHierarchy);
 * goal.accept(st, null);
 */
public class SymbolTable extends GJDepthFirst {

  // ---------------------------------------------------------------
  // The class hierarchy (needed to resolve inherited fields)
  // ---------------------------------------------------------------
  private final ClassHierarchy ch;

  // ---------------------------------------------------------------
  // Tables populated during visiting
  // ---------------------------------------------------------------

  /** className -> { fieldName -> typeName } */
  private final Map<String, Map<String, String>> fields = new LinkedHashMap<>();

  /** className -> methodName -> { paramOrLocalName -> typeName } */
  private final Map<String, Map<String, Map<String, String>>> locals = new LinkedHashMap<>();

  /** className -> methodName -> returnType */
  private final Map<String, Map<String, String>> returnTypes = new LinkedHashMap<>();

  /** className -> methodName -> ordered list of parameter names */
  private final Map<String, Map<String, List<String>>> paramOrder = new LinkedHashMap<>();

  // ---------------------------------------------------------------
  // Constructor
  // ---------------------------------------------------------------
  public SymbolTable(ClassHierarchy ch) {
    this.ch = ch;
  }

  // ---------------------------------------------------------------
  // Public query API
  // ---------------------------------------------------------------

  /**
   * Look up the declared type of a variable used inside (className, methodName).
   * Search order: locals/params → fields of className → inherited fields.
   * Returns null if not found.
   */
  public String typeOf(String className, String methodName, String varName) {
    // 1. Locals and params of this method
    Map<String, String> methodLocals = getLocals(className, methodName);
    if (methodLocals != null && methodLocals.containsKey(varName))
      return methodLocals.get(varName);

    // 2. Fields (walk up the hierarchy)
    String cur = className;
    while (cur != null) {
      Map<String, String> f = fields.get(cur);
      if (f != null && f.containsKey(varName))
        return f.get(varName);
      cur = ch.parentOf(cur);
    }
    return null; // unknown
  }

  /**
   * Declared return type of className.methodName.
   */
  public String returnTypeOf(String className, String methodName) {
    Map<String, String> m = returnTypes.get(className);
    return m == null ? null : m.get(methodName);
  }

  /**
   * Ordered list of parameter names for className.methodName.
   */
  public List<String> paramsOf(String className, String methodName) {
    Map<String, List<String>> m = paramOrder.get(className);
    if (m == null)
      return Collections.emptyList();
    List<String> p = m.get(methodName);
    return p == null ? Collections.emptyList() : Collections.unmodifiableList(p);
  }

  /**
   * All field names of className (own fields only, not inherited).
   */
  public Map<String, String> fieldsOf(String className) {
    return fields.getOrDefault(className, Collections.emptyMap());
  }

  /**
   * All locals+params of className.methodName.
   */
  public Map<String, String> localsOf(String className, String methodName) {
    Map<String, String> m = getLocals(className, methodName);
    return m == null ? Collections.emptyMap() : Collections.unmodifiableMap(m);
  }

  // ---------------------------------------------------------------
  // Visitor context tracking
  // ---------------------------------------------------------------

  /** Name of the class currently being visited */
  private String currentClass;

  /** Name of the method currently being visited (null in class body) */
  private String currentMethod;

  // ---------------------------------------------------------------
  // Visitor methods
  // ---------------------------------------------------------------

  /**
   * MainClass: register it; it has no fields or ordinary methods,
   * but we still need to visit VarDeclarations inside main as locals
   * under a synthetic method name "main".
   *
   * f0 -> "class"
   * f1 -> Identifier() <- class name
   * ...
   * f14 -> ( VarDeclaration() )*
   * f15 -> ( Statement() )*
   */
  @Override
  public Object visit(MainClass n, Object argu) {
    currentClass = n.f1.f0.tokenImage;
    currentMethod = "main";
    fields.computeIfAbsent(currentClass, k -> new LinkedHashMap<>());
    ensureMethod(currentClass, currentMethod);
    n.f14.accept(this, argu); // local var declarations inside main
    currentMethod = null;
    currentClass = null;
    return null;
  }

  /**
   * f0 -> "class"
   * f1 -> Identifier()
   * f2 -> "{"
   * f3 -> ( VarDeclaration() )* <- fields
   * f4 -> ( MethodDeclaration() )*
   * f5 -> "}"
   */
  @Override
  public Object visit(ClassDeclaration n, Object argu) {
    currentClass = n.f1.f0.tokenImage;
    currentMethod = null;
    fields.computeIfAbsent(currentClass, k -> new LinkedHashMap<>());
    n.f3.accept(this, argu); // field declarations
    n.f4.accept(this, argu); // method declarations
    currentClass = null;
    return null;
  }

  /**
   * f0 -> "class"
   * f1 -> Identifier()
   * f2 -> "extends"
   * f3 -> Identifier()
   * f4 -> "{"
   * f5 -> ( VarDeclaration() )* <- fields
   * f6 -> ( MethodDeclaration() )*
   * f7 -> "}"
   */
  @Override
  public Object visit(ClassExtendsDeclaration n, Object argu) {
    currentClass = n.f1.f0.tokenImage;
    currentMethod = null;
    fields.computeIfAbsent(currentClass, k -> new LinkedHashMap<>());
    n.f5.accept(this, argu); // field declarations
    n.f6.accept(this, argu); // method declarations
    currentClass = null;
    return null;
  }

  /**
   * VarDeclaration:
   * - Inside a method (currentMethod != null) → local variable
   * - Inside a class body (currentMethod == null) → field
   *
   * f0 -> Type()
   * f1 -> Identifier()
   * f2 -> ";"
   */
  @Override
  public Object visit(VarDeclaration n, Object argu) {
    String typeName = typeString(n.f0);
    String varName = n.f1.f0.tokenImage;

    if (currentMethod != null) {
      // local variable
      getOrCreateLocals(currentClass, currentMethod).put(varName, typeName);
    } else {
      // field
      fields.computeIfAbsent(currentClass, k -> new LinkedHashMap<>())
          .put(varName, typeName);
    }
    return null;
  }

  /**
   * f0 -> "public"
   * f1 -> Type() <- return type
   * f2 -> Identifier() <- method name
   * f3 -> "("
   * f4 -> ( FormalParameterList() )?
   * f5 -> ")"
   * f6 -> "{"
   * f7 -> ( VarDeclaration() )*
   * f8 -> ( Statement() )*
   * f9 -> "return"
   * f10 -> Identifier()
   * f11 -> ";"
   * f12 -> "}"
   */
  @Override
  public Object visit(MethodDeclaration n, Object argu) {
    currentMethod = n.f2.f0.tokenImage;
    String retType = typeString(n.f1);

    ensureMethod(currentClass, currentMethod);
    returnTypes.computeIfAbsent(currentClass, k -> new LinkedHashMap<>())
        .put(currentMethod, retType);
    paramOrder.computeIfAbsent(currentClass, k -> new LinkedHashMap<>())
        .computeIfAbsent(currentMethod, k -> new ArrayList<>());

    n.f4.accept(this, argu); // formal parameters (if any)
    n.f7.accept(this, argu); // local var declarations

    currentMethod = null;
    return null;
  }

  /**
   * f0 -> Type()
   * f1 -> Identifier()
   */
  @Override
  public Object visit(FormalParameter n, Object argu) {
    String typeName = typeString(n.f0);
    String paramName = n.f1.f0.tokenImage;

    // Params go into the locals map AND the ordered param list
    getOrCreateLocals(currentClass, currentMethod).put(paramName, typeName);
    paramOrder.computeIfAbsent(currentClass, k -> new LinkedHashMap<>())
        .computeIfAbsent(currentMethod, k -> new ArrayList<>())
        .add(paramName);
    return null;
  }

  // ---------------------------------------------------------------
  // Helpers
  // ---------------------------------------------------------------

  /**
   * Convert a Type AST node to a plain String (e.g., "int", "boolean",
   * "int[]", or a class name).
   */
  private String typeString(Type t) {
    Node choice = t.f0.choice;
    if (choice instanceof ArrayType)
      return "int[]";
    if (choice instanceof BooleanType)
      return "boolean";
    if (choice instanceof IntegerType)
      return "int";
    // Otherwise it's an Identifier node
    return ((Identifier) choice).f0.tokenImage;
  }

  private void ensureMethod(String cls, String method) {
    locals.computeIfAbsent(cls, k -> new LinkedHashMap<>())
        .computeIfAbsent(method, k -> new LinkedHashMap<>());
  }

  private Map<String, String> getLocals(String cls, String method) {
    Map<String, Map<String, String>> m = locals.get(cls);
    return m == null ? null : m.get(method);
  }

  private Map<String, String> getOrCreateLocals(String cls, String method) {
    return locals.computeIfAbsent(cls, k -> new LinkedHashMap<>())
        .computeIfAbsent(method, k -> new LinkedHashMap<>());
  }
}

